contract RewardTokenMinter {
    uint256 public constant EPOCH_DURATION = 14 days;
    address public gaugeController;
    address public token;
    address public owner;
    bool public isPaused;

    uint256 public c = 10000;
    uint256 public lastEpochTime;
    mapping(address => uint256) public userEpoch;
    mapping(address => uint256) public userWeights;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    modifier notPaused() {
        require(!isPaused, "paused");
        _;
    }

    constructor(address _token, address _gaugeController) {
        token = _token;
        gaugeController = _gaugeController;
        owner = msg.sender;
        lastEpochTime = block.timestamp;
    }

    function updateOwnership(address newOwner) external onlyOwner {
        owner = newOwner;
    }

    function setPause(bool paused) external onlyOwner {
        isPaused = paused;
    }

    function setGaugeController(address _controller) external onlyOwner {
        gaugeController = _controller;
    }

    function setEmissionCoefficient(uint256 _c) external onlyOwner {
        c = _c;
    }

    function epoch() external notPaused {
        require(block.timestamp >= lastEpochTime + EPOCH_DURATION, "epoch not due");
        lastEpochTime = (block.timestamp / EPOCH_DURATION) * EPOCH_DURATION;
        uint256 veSupply = IVotingEscrow(gaugeController).totalSupply();
        uint256 emission = c * sqrt(veSupply);
        IToken(token).mint(address(this), emission);
    }

    function mint(address to) external notPaused returns (uint256) {
        uint256 amount = calculateMint(to);
        require(amount > 0, "nothing to mint");
        userEpoch[to] = getCurrentEpoch();
        userWeights[to] = IVotingEscrow(gaugeController).balanceOf(to);
        IToken(token).mint(to, amount);
        return amount;
    }

    function calculateMint(address user) public view returns (uint256) {
        if (userEpoch[user] >= getCurrentEpoch()) return 0;
        uint256 weight = IVotingEscrow(gaugeController).balanceOf(user);
        uint256 totalWeight = IVotingEscrow(gaugeController).totalSupply();
        if (totalWeight == 0) return 0;
        uint256 currentEmission = c * sqrt(totalWeight);
        return (currentEmission * weight) / totalWeight;
    }

    function getCurrentEpoch() public view returns (uint256) {
        if (block.timestamp < lastEpochTime) return 0;
        return (block.timestamp - lastEpochTime) / EPOCH_DURATION;
    }

    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }
}

interface IVotingEscrow {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
}

interface IToken {
    function mint(address to, uint256 amount) external;
}

