        if (liquidityPools[sender] && !isMaxBuyExempt[recipient]) {
            uint256 maxAmount = (_totalSupply * maxBuyNumerator) /
                maxBuyDenominator;
            require(
                amount <= maxAmount,
                "De Layer: Max buy amount exceeded. Try a lower amount."
            );
        }
