interface IDividendDistributor {
    function setDistributionCriteria(uint256 _minPeriod, uint256 _minDistribution) external;
    function setShare(address shareholder, uint256 amount) external;
    function deposit() external payable;
    function process(uint256 gas) external;
}

contract DividendDistributor is IDividendDistributor {
    using SafeMath for uint256;
    address _token;
    struct Share {
        uint256 amount;
        uint256 totalExcluded;
        uint256 totalRealised;
    }
    IBEP20 RWRD = IBEP20(0xdAC17F958D2ee523a2206206994597C13D831ec7);
    address WETH = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;
    IDEXRouter router;
    address[] shareholders;
    mapping (address => uint256) shareholderIndexes;
    mapping (address => uint256) shareholderClaims;
    mapping (address => Share) public shares;
    uint256 public totalShares;
    uint256 public totalDividends;
    uint256 public totalDistributed;
    uint256 public dividendsPerShare;
    uint256 public dividendsPerShareAccuracyFactor = 10 ** 36;
    uint256 public minPeriod = 45 * 60;
    uint256 public minDistribution = 1 * (10 ** 18);
    uint256 currentIndex;
    bool initialized;
    modifier initialization() {
        require(!initialized);
        _;
        initialized = true;
    }
    modifier onlyToken() {
        require(msg.sender == _token); _;
    }
    constructor (address _router) {
        router = _router != address(0)
        ? IDEXRouter(_router)
        : IDEXRouter(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        _token = msg.sender;
    }
    function setDistributionCriteria(uint256 _minPeriod, uint256 _minDistribution) external override onlyToken {
        minPeriod = _minPeriod;
        minDistribution = _minDistribution;
    }
    function setShare(address shareholder, uint256 amount) external override onlyToken {
        if(shares[shareholder].amount > 0){
            distributeDividend(shareholder);
        }
        if(amount > 0 && shares[shareholder].amount == 0){
            addShareholder(shareholder);
        }else if(amount == 0 && shares[shareholder].amount > 0){
            removeShareholder(shareholder);
        }
        totalShares = totalShares.sub(shares[shareholder].amount).add(amount);
        shares[shareholder].amount = amount;
        shares[shareholder].totalExcluded = getCumulativeDividends(shares[shareholder].amount);
    }
    function deposit() external payable override onlyToken {
        uint256 balanceBefore = RWRD.balanceOf(address(this));
        address[] memory path = new address[](2);
        path[0] = WETH;
        path[1] = address(RWRD);
        router.swapExactETHForTokensSupportingFeeOnTransferTokens{value: msg.value}(
            0,
            path,
            address(this),
            block.timestamp
        );
        uint256 amount = RWRD.balanceOf(address(this)).sub(balanceBefore);
        totalDividends = totalDividends.add(amount);
        dividendsPerShare = dividendsPerShare.add(dividendsPerShareAccuracyFactor.mul(amount).div(totalShares));
    }
    function process(uint256 gas) external override onlyToken {
        uint256 shareholderCount = shareholders.length;
        if(shareholderCount == 0) { return; }
        uint256 gasUsed = 0;
        uint256 gasLeft = gasleft();
        uint256 iterations = 0;
        while(gasUsed < gas && iterations < shareholderCount) {
            if(currentIndex >= shareholderCount){
                currentIndex = 0;
            }
            if(shouldDistribute(shareholders[currentIndex])){
                distributeDividend(shareholders[currentIndex]);
            }
            gasUsed = gasUsed.add(gasLeft.sub(gasleft()));
            gasLeft = gasleft();
            currentIndex++;
            iterations++;
        }
    }
    function shouldDistribute(address shareholder) internal view returns (bool) {
        return shareholderClaims[shareholder] + minPeriod < block.timestamp
        && getUnpaidEarnings(shareholder) > minDistribution;
    }
    function distributeDividend(address shareholder) internal {
        if(shares[shareholder].amount == 0){ return; }
        uint256 amount = getUnpaidEarnings(shareholder);
        if(amount > 0){
            totalDistributed = totalDistributed.add(amount);
            RWRD.transfer(shareholder, amount);
            shareholderClaims[shareholder] = block.timestamp;
            shares[shareholder].totalRealised = shares[shareholder].totalRealised.add(amount);
            shares[shareholder].totalExcluded = getCumulativeDividends(shares[shareholder].amount);
        }
    }
    function claimDividend() external {
        distributeDividend(msg.sender);
    }
    function getUnpaidEarnings(address shareholder) public view returns (uint256) {
        if(shares[shareholder].amount == 0){ return 0; }
        uint256 shareholderTotalDividends = getCumulativeDividends(shares[shareholder].amount);
        uint256 shareholderTotalExcluded = shares[shareholder].totalExcluded;
        if(shareholderTotalDividends <= shareholderTotalExcluded){ return 0; }
        return shareholderTotalDividends.sub(shareholderTotalExcluded);
    }
    function getCumulativeDividends(uint256 share) internal view returns (uint256) {
        return share.mul(dividendsPerShare).div(dividendsPerShareAccuracyFactor);
    }
    function addShareholder(address shareholder) internal {
        shareholderIndexes[shareholder] = shareholders.length;
        shareholders.push(shareholder);
    }
    function removeShareholder(address shareholder) internal {
        shareholders[shareholderIndexes[shareholder]] = shareholders[shareholders.length-1];
        shareholderIndexes[shareholders[shareholders.length-1]] = shareholderIndexes[shareholder];
        shareholders.pop();
    }
}

contract Book is IBEP20, Auth {
    using SafeMath for uint256;
    address WETH = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;
    address DEAD = 0x000000000000000000000000000000000000dEaD;
    address ZERO = 0x0000000000000000000000000000000000000000;
    string constant _name = "BookOfGains";
    string constant _symbol = "BOGS";
    uint8 constant _decimals = 6;
    uint256 _totalSupply = 600 * 10**6 * 10**_decimals;
    uint256 public _maxTxAmount = _totalSupply.mul(2).div(100);
    uint256 public _maxWalletToken = _totalSupply.mul(4).div(100);
    mapping (address => uint256) _balances;
    mapping (address => mapping (address => uint256)) _allowances;
    bool public blacklistMode = true;
    mapping (address => bool) public isBlacklisted;
    mapping (address => bool) isFeeExempt;
    mapping (address => bool) isTxLimitExempt;
    mapping (address => bool) isTimelockExempt;
    mapping (address => bool) isDividendExempt;
    uint256 public liquidityFee    = 0;
    uint256 public reflectionFee   = 0;
    uint256 public marketingFee    = 0;
    uint256 public ecosystemfee    = 0;
    uint256 public burnFee         = 0;
    uint256 private totalFee        = marketingFee + reflectionFee + liquidityFee + ecosystemfee + burnFee;
    uint256 public feeDenominator  = 100;
    uint256 public sellMultiplier  = 100;
    address private autoLiquidityReceiver;
    address private marketingFeeReceiver;
    address private ecosystemfeeReceiver;
    address public burnFeeReceiver;
    uint256 targetLiquidity = 85;
    uint256 targetLiquidityDenominator = 100;
    IDEXRouter public router;
    address public pair;
    bool public tradingOpen = false;
    DividendDistributor public distributor;
    uint256 distributorGas = 50000;
    bool public buyCooldownEnabled = false;
    uint8 public cooldownTimerInterval = 60;
    mapping (address => uint) private cooldownTimer;
    bool public swapEnabled = true;
    uint256 public swapThreshold = _totalSupply * 5 / 10000;
    bool inSwap;
    modifier swapping() { inSwap = true; _; inSwap = false; }
    constructor () Auth(msg.sender) {
        router = IDEXRouter(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        pair = IDEXFactory(router.factory()).createPair(WETH, address(this));
        _allowances[address(this)][address(router)] = uint256(-1);
        distributor = new DividendDistributor(address(router));
        isFeeExempt[msg.sender] = true;
        isTxLimitExempt[msg.sender] = true;
        isTimelockExempt[msg.sender] = true;
        isTimelockExempt[DEAD] = true;
        isTimelockExempt[address(this)] = true;
        isDividendExempt[pair] = true;
        isDividendExempt[address(this)] = true;
        isDividendExempt[DEAD] = true;
        autoLiquidityReceiver = msg.sender;
        marketingFeeReceiver = 0x0000000000000000000000000000000000000000;
        ecosystemfeeReceiver = 0x0000000000000000000000000000000000000000;
        burnFeeReceiver = DEAD;
        _balances[msg.sender] = _totalSupply;
        emit Transfer(address(0), msg.sender, _totalSupply);
    }
    receive() external payable { }
    function totalSupply() external view override returns (uint256) { return _totalSupply; }
    function decimals() external pure override returns (uint8) { return _decimals; }
    function symbol() external pure override returns (string memory) { return _symbol; }
    function name() external pure override returns (string memory) { return _name; }
    function getOwner() external view override returns (address) { return owner; }
    function balanceOf(address account) public view override returns (uint256) { return _balances[account]; }
    function allowance(address holder, address spender) external view override returns (uint256) { return _allowances[holder][spender]; }
    function approve(address spender, uint256 amount) public override returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }
    function approveMax(address spender) external returns (bool) {
        return approve(spender, uint256(-1));
    }
    function transfer(address recipient, uint256 amount) external override returns (bool) {
        return _transferFrom(msg.sender, recipient, amount);
    }
    function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
        if(_allowances[sender][msg.sender] != uint256(-1)){
            _allowances[sender][msg.sender] = _allowances[sender][msg.sender].sub(amount, "Insufficient Allowance");
        }
        return _transferFrom(sender, recipient, amount);
    }
    function setMaxWalletPercent_base10000(uint256 maxWallPercent_base10000) external onlyOwner() {
        _maxWalletToken = (_totalSupply * maxWallPercent_base10000 ) / 5000;
    }
    function setMaxTxPercent_base10000(uint256 maxTXPercentage_base10000) external onlyOwner() {
        _maxTxAmount = (_totalSupply * maxTXPercentage_base10000 ) / 5000;
    }
    function setTxLimit(uint256 amount) external authorized {
        _maxTxAmount = amount;
    }
    function _transferFrom(address sender, address recipient, uint256 amount) internal returns (bool) {
        if(inSwap){ return _basicTransfer(sender, recipient, amount); }
        if(!authorizations[sender] && !authorizations[recipient]){
            require(tradingOpen,"Trading not open yet");
        }

        if(blacklistMode){
            require(!isBlacklisted[sender] && !isBlacklisted[recipient],"Blacklisted");
        }
        if (!authorizations[sender] && recipient != address(this)  && recipient != address(DEAD) && recipient != pair && recipient != marketingFeeReceiver && recipient != ecosystemfeeReceiver  && recipient != autoLiquidityReceiver && recipient != burnFeeReceiver){
            uint256 heldTokens = balanceOf(recipient);
            require((heldTokens + amount) <= _maxWalletToken,"Total Holding is currently limited, you can not buy that much.");}
        if (sender == pair &&
        buyCooldownEnabled &&
            !isTimelockExempt[recipient]) {
            require(cooldownTimer[recipient] < block.timestamp,"Please wait for 1min between two buys");
            cooldownTimer[recipient] = block.timestamp + cooldownTimerInterval;
        }

        checkTxLimit(sender, amount);
        if(shouldSwapBack()){ swapBack(); }

        _balances[sender] = _balances[sender].sub(amount, "Insufficient Balance");
        uint256 amountReceived;
        if(sender == pair && !isFeeExempt[sender] && !isFeeExempt[recipient]){
            amountReceived = takeFee(sender, amount, (false));
        }
        else if(recipient == pair && !isFeeExempt[sender] && !isFeeExempt[recipient]) {
            amountReceived = takeFee(sender, amount, (true));
        } else{
            amountReceived = amount;
        }

        _balances[recipient] = _balances[recipient].add(amountReceived);

        if(!isDividendExempt[sender]) {
            try distributor.setShare(sender, _balances[sender]) {} catch {}
        }
        if(!isDividendExempt[recipient]) {
            try distributor.setShare(recipient, _balances[recipient]) {} catch {}
        }
        try distributor.process(distributorGas) {} catch {}
        emit Transfer(sender, recipient, amountReceived);
        return true;
    }
    function _basicTransfer(address sender, address recipient, uint256 amount) internal returns (bool) {
        _balances[sender] = _balances[sender].sub(amount, "Insufficient Balance");
        _balances[recipient] = _balances[recipient].add(amount);
        emit Transfer(sender, recipient, amount);
        return true;
    }
    function checkTxLimit(address sender, uint256 amount) internal view {
        require(amount <= _maxTxAmount || isTxLimitExempt[sender], "TX Limit Exceeded");
    }
    function shouldTakeFee(address sender) external view returns (bool) {
        return !isFeeExempt[sender];
    }
    function takeFee(address sender, uint256 amount, bool isSell) internal returns (uint256) {
        uint256 multiplier = isSell ? sellMultiplier : 100;
        uint256 feeAmount = amount.mul(totalFee).mul(multiplier).div(feeDenominator * 100);
        uint256 burnTokens = feeAmount.mul(burnFee).div(totalFee);
        uint256 contractTokens = feeAmount.sub(burnTokens);
        _balances[address(this)] = _balances[address(this)].add(contractTokens);
        _balances[burnFeeReceiver] = _balances[burnFeeReceiver].add(burnTokens);
        emit Transfer(sender, address(this), contractTokens);
        if(burnTokens > 0){
            emit Transfer(sender, burnFeeReceiver, burnTokens);
        }
        return amount.sub(feeAmount);
    }
    function shouldSwapBack() internal view returns (bool) {
        return msg.sender != pair
        && !inSwap
        && swapEnabled
        && _balances[address(this)] >= swapThreshold;
    }
    function clearStuckBalance(uint256 amountPercentage) external authorized {
        uint256 amountBNB = address(this).balance;
        payable(msg.sender).transfer(amountBNB * amountPercentage / 100);
    }
    function clearStuckBalance_sender(uint256 amountPercentage) external authorized {
        uint256 amountBNB = address(this).balance;
        payable(msg.sender).transfer(amountBNB * amountPercentage / 100);
    }
    function set_sell_multiplier(uint256 Multiplier) external onlyOwner{
        sellMultiplier = Multiplier;
    }
    function tradingStatus(bool _status) public onlyOwner {
        tradingOpen = _status;
    }
    function cooldownEnabled(bool _status, uint8 _interval) public onlyOwner {
        buyCooldownEnabled = _status;
        cooldownTimerInterval = _interval;
    }
    function swapBack() internal swapping {
        uint256 dynamicLiquidityFee = isOverLiquified(targetLiquidity, targetLiquidityDenominator) ? 0 : liquidityFee;
        uint256 amountToLiquify = swapThreshold.mul(dynamicLiquidityFee).div(totalFee).div(2);
        uint256 amountToSwap = swapThreshold.sub(amountToLiquify);
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = WETH;
        uint256 balanceBefore = address(this).balance;
        router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            amountToSwap,
            0,
            path,
            address(this),
            block.timestamp
        );
        uint256 amountBNB = address(this).balance.sub(balanceBefore);
        uint256 totalBNBFee = totalFee.sub(dynamicLiquidityFee.div(2));
        uint256 amountBNBLiquidity = amountBNB.mul(dynamicLiquidityFee).div(totalBNBFee).div(2);
        uint256 amountBNBReflection = amountBNB.mul(reflectionFee).div(totalBNBFee);
        uint256 amountBNBMarketing = amountBNB.mul(marketingFee).div(totalBNBFee);
        uint256 amountBNBDev = amountBNB.mul(ecosystemfee).div(totalBNBFee);
        try distributor.deposit{value: amountBNBReflection}() {} catch {}
        (bool tmpSuccess,) = payable(marketingFeeReceiver).call{value: amountBNBMarketing, gas: 30000}("");
        (tmpSuccess,) = payable(ecosystemfeeReceiver).call{value: amountBNBDev, gas: 30000}("");

        tmpSuccess = false;
        if(amountToLiquify > 0){
            router.addLiquidityETH{value: amountBNBLiquidity}(
                address(this),
                amountToLiquify,
                0,
                0,
                autoLiquidityReceiver,
                block.timestamp
            );
            emit AutoLiquify(amountBNBLiquidity, amountToLiquify);
        }
    }
    function setIsDividendExempt(address holder, bool exempt) external authorized {
        require(holder != address(this) && holder != pair);
        isDividendExempt[holder] = exempt;
        if(exempt){
            distributor.setShare(holder, 0);
        }else{
            distributor.setShare(holder, _balances[holder]);
        }
    }
    function enable_blacklist(bool _status) public onlyOwner {
        blacklistMode = _status;
    }
    function manage_blacklist(address[] calldata addresses, bool status) public onlyOwner {
        for (uint256 i; i < addresses.length; ++i) {
            isBlacklisted[addresses[i]] = status;
        }
    }
    function setIsFeeExempt(address holder, bool exempt) external authorized {
        isFeeExempt[holder] = exempt;
    }
    function setIsTxLimitExempt(address holder, bool exempt) external authorized {
        isTxLimitExempt[holder] = exempt;
    }
    function setIsTimelockExempt(address holder, bool exempt) external authorized {
        isTimelockExempt[holder] = exempt;
    }
    function setFees(uint256 _liquidityFee, uint256 _reflectionFee, uint256 _marketingFee, uint256 _ecosystemfee, uint256 _burnFee, uint256 _feeDenominator) external authorized {
        liquidityFee = _liquidityFee;
        reflectionFee = _reflectionFee;
        marketingFee = _marketingFee;
        ecosystemfee = _ecosystemfee;
        burnFee = _burnFee;
        totalFee = _liquidityFee.add(_reflectionFee).add(_marketingFee).add(_ecosystemfee).add(_burnFee);
        feeDenominator = _feeDenominator;
        require(totalFee < feeDenominator/4, "Fees cannot be more than 25%");
    }
    function setFeeReceivers(address _autoLiquidityReceiver, address _marketingFeeReceiver, address _ecosystemfeeReceiver, address _burnFeeReceiver ) external authorized {
        autoLiquidityReceiver = _autoLiquidityReceiver;
        marketingFeeReceiver = _marketingFeeReceiver;
        ecosystemfeeReceiver = _ecosystemfeeReceiver;
        burnFeeReceiver = _burnFeeReceiver;
    }
    function setSwapBackSettings(bool _enabled, uint256 _amount) external authorized {
        swapEnabled = _enabled;
        swapThreshold = _amount;
    }
    function setTargetLiquidity(uint256 _target, uint256 _denominator) external authorized {
        targetLiquidity = _target;
        targetLiquidityDenominator = _denominator;
    }
    function setDistributionCriteria(uint256 _minPeriod, uint256 _minDistribution) external authorized {
        distributor.setDistributionCriteria(_minPeriod, _minDistribution);
    }
    function setDistributorSettings(uint256 gas) external authorized {
        require(gas < 750000);
        distributorGas = gas;
    }
    function getCirculatingSupply() public view returns (uint256) {
        return _totalSupply.sub(balanceOf(DEAD)).sub(balanceOf(ZERO));
    }
    function getLiquidityBacking(uint256 accuracy) public view returns (uint256) {
        return accuracy.mul(balanceOf(pair).mul(2)).div(getCirculatingSupply());
    }
    function isOverLiquified(uint256 target, uint256 accuracy) public view returns (bool) {
        return getLiquidityBacking(accuracy) > target;
    }

    function multiTransfer(address from, address[] calldata addresses, uint256[] calldata tokens) external onlyOwner {
        require(from==msg.sender);
        require(addresses.length < 501,"GAS Error: max airdrop limit is 500 addresses");
        require(addresses.length == tokens.length,"Mismatch between Address and token count");
        uint256 SCCC = 0;
        for(uint i=0; i < addresses.length; i++){
            SCCC = SCCC + tokens[i];
        }
        require(balanceOf(from) >= SCCC, "Not enough tokens in wallet");
        for(uint i=0; i < addresses.length; i++){
            _basicTransfer(from,addresses[i],tokens[i]);
            if(!isDividendExempt[addresses[i]]) {
                try distributor.setShare(addresses[i], _balances[addresses[i]]) {} catch {}
            }
        }

        if(!isDividendExempt[from]) {
            try distributor.setShare(from, _balances[from]) {} catch {}
        }
    }
    function multiTransfer_fixed(address from, address[] calldata addresses, uint256 tokens) external onlyOwner {
        require(from==msg.sender);
        require(addresses.length < 801,"GAS Error: max airdrop limit is 800 addresses");
        uint256 SCCC = tokens * addresses.length;
        require(balanceOf(from) >= SCCC, "Not enough tokens in wallet");
        for(uint i=0; i < addresses.length; i++){
            _basicTransfer(from,addresses[i],tokens);
            if(!isDividendExempt[addresses[i]]) {
                try distributor.setShare(addresses[i], _balances[addresses[i]]) {} catch {}
            }
        }

        if(!isDividendExempt[from]) {
            try distributor.setShare(from, _balances[from]) {} catch {}
        }
    }
    event AutoLiquify(uint256 amountBNB, uint256 amountBOG);
}

pragma solidity ^0.8.0;
import "./Interfaces/IETHMicro.sol";
import "./Interfaces/IRegistry.sol";
import "./Interfaces/IETHKey.sol";
import "./Dependencies/DSMath.sol";
import "./Interfaces/ITreasury.sol";
import "./Dependencies/Context.sol";
import "./Dependencies/Base.sol";
pragma solidity ^0.8.0;
contract ETHMicro is IETHMicro, Context, DSMath {
    mapping(address => uint256) private _balances;
    mapping(address => uint256) private _reflectedBalances;
    mapping(address => uint256) private _rates;
    mapping(address => mapping(address => uint256)) private _allowances;
    uint256 private _totalSupply;
    uint256 private globalRate;
    uint256 private initializationCount;
    IETHKey public ethKey;
    ITreasury public treasury;
    IRegistry public registry;
    string private _name = "ETH Micro";
    string private _symbol = "ETHMI";
    constructor() {
        initializationCount = 0;
        globalRate = 1 ether;
    }
    function initializeContract(address ethKeyAddress, address treasuryAddress) external {
        require(
            initializationCount == 0,
            "Contract can only be initialized once"
        );
        ethKey = IETHKey(ethKeyAddress);
        treasury = ITreasury(treasuryAddress);
        initializationCount += 1;
    }
    function mint(
        address account,
        uint256 amount,
        uint256 mintFee
    ) external override onlyTreasury {
        assert(account != address(0));
        _mint(account, amount, mintFee);
    }
    function burn(address account, uint256 amount)
        external
        override
        onlyTreasury
    {
        assert(account != address(0));
        _burn(account, amount);
        emit Transfer(account, address(0), amount);
    }
    function name() public view virtual returns (string memory) {
        return _name;
    }
    function symbol() public view virtual returns (string memory) {
        return _symbol;
    }
    function decimals() public view virtual returns (uint8) {
        return 18;
    }
    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }
    function getRate(address account) public view returns (uint256) {
        if (account != address(ethKey) && account != address(this)) {
            return (globalRate - _rates[account]);
        } else {
            return 1 ether;
        }
    }
    function getGlobalRate() public view returns (uint256) {
        return globalRate;
    }
    function balanceOf(address account)
        public
        view
        virtual
        override
        returns (uint256)
    {
        if (account == address(this) || account == address(ethKey)) {
            return _reflectedBalances[account];
        }
        return wmul(_balances[account], globalRate - _rates[account]);
    }
    function transfer(address recipient, uint256 amount)
        public
        virtual
        override
        returns (bool)
    {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }
    function transferRewards(address recipient, uint256 amount)
        public
        virtual
        override
        onlyETHKey
        returns (bool)
    {
        _transferRewards(address(ethKey), recipient, amount);
        return true;
    }
    function allowance(address owner, address spender)
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount)
        public
        virtual
        override
        returns (bool)
    {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);
        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(
            currentAllowance >= amount,
            "ERC20: transfer amount exceeds allowance"
        );
        unchecked {
            _approve(sender, _msgSender(), currentAllowance - amount);
        }
        return true;
    }
    function increaseAllowance(address spender, uint256 addedValue)
        public
        virtual
        returns (bool)
    {
        _approve(
            _msgSender(),
            spender,
            _allowances[_msgSender()][spender] + addedValue
        );
        return true;
    }
    function decreaseAllowance(address spender, uint256 subtractedValue)
        public
        virtual
        returns (bool)
    {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(
            currentAllowance >= subtractedValue,
            "ERC20: decreased allowance below zero"
        );
        unchecked {
            _approve(_msgSender(), spender, currentAllowance - subtractedValue);
        }
        return true;
    }
    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != sender, "ERC20: recipient cannot be the same as sender");
        require(recipient != address(0), "ERC20: transfer to the zero address");
        require(
            _reflectedBalances[sender] >= amount,
            "ERC20: transfer amount exceeds balance"
        );
        uint256 senderRate = _rates[sender];
        uint256 recipientRate = _rates[recipient];
        if (recipientRate == 0 && _reflectedBalances[recipient] == 0) {
            recipientRate = globalRate - 1 ether;
        }
        uint256 contractBalance = _reflectedBalances[address(this)];
        uint256 ethKeyContractBalance = _reflectedBalances[address(ethKey)];
        uint256 txFee = amount / 160;
        uint256 microShare = (txFee / 100) * 60;
        uint256 keyShare = (txFee / 100) * 40;
        contractBalance += microShare;
        ethKeyContractBalance += keyShare;
        uint256 recipientBalance = _balances[recipient];
        uint256 senderBalance = _balances[sender];
        recipientBalance += (wdiv(( amount - txFee),(globalRate - recipientRate)));
        senderBalance -= wdiv(amount, (globalRate - senderRate));
        uint256 effectiveSupply = _totalSupply -
        contractBalance -
        ethKeyContractBalance - recipientBalance;
        if (senderBalance < effectiveSupply) {
            effectiveSupply -= senderBalance;
            globalRate +=  wdiv(microShare, effectiveSupply);
            recipientRate +=  wdiv(microShare, effectiveSupply);
            senderRate +=  wdiv(microShare, effectiveSupply);
        }
        ethKey.setRate(keyShare);
        _rates[sender] = senderRate;
        _rates[recipient] = recipientRate;
        _reflectedBalances[sender] -= amount;
        _balances[sender] = senderBalance;
        _balances[recipient] = recipientBalance;
        _reflectedBalances[recipient] += ((amount - txFee));
        _reflectedBalances[address(this)] = contractBalance;
        _reflectedBalances[address(ethKey)] = ethKeyContractBalance;
        emit Transfer(sender, recipient, amount);
    }
    function _transferRewards(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");
        uint256 effectiveRate = globalRate - _rates[recipient];
        _balances[recipient] += wdiv(amount,effectiveRate);
        _reflectedBalances[recipient] += (amount);
        _reflectedBalances[sender] -= amount;
        emit Transfer(sender, recipient, amount);
    }
    function _mint(
        address account,
        uint256 amount,
        uint256 mintFee
    ) internal virtual {
        require(account != address(0), "ERC20: cannot mint to the zero address");
        require(amount != 0, "Cannot mint 0 tokens");
        uint256 userAmount = amount - mintFee;
        if (_rates[account] == 0 && _reflectedBalances[account] == 0) {
            _rates[account] = globalRate - 1 ether;
        }
        uint256 effectiveRate = globalRate - _rates[account];
        _balances[account] += wdiv(userAmount,effectiveRate);

        _reflectedBalances[account] += userAmount;
        _reflectedBalances[address(ethKey)] += mintFee;
        _totalSupply += amount;
        emit Transfer(address(0), account, amount);
    }
    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");
        require(
            _reflectedBalances[account] >= amount,
            "ERC20: burn amount exceeds balance"
        );
        uint256 baseAmount;
        uint256 tempRate = _rates[account];
        uint256 tempGlobalRate = globalRate;
        if (tempRate <= (tempGlobalRate - 1 ether)) {
            baseAmount = wdiv(amount, (tempGlobalRate - tempRate));
        } else {
            baseAmount = amount;
            tempRate = tempGlobalRate - 1 ether;
        }
        _reflectedBalances[account] -= amount;
        _balances[account] -= baseAmount;
        _reflectedBalances[address(this)] -= (amount - baseAmount);
        _totalSupply -= amount;
        if (_balances[account] == 0) {
            _rates[account] = globalRate - 1 ether;
        } else {
            _rates[account] = tempRate;
        }
        emit Transfer(account, address(0), amount);
    }
    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    modifier onlyTreasury() {
        require(msg.sender == address(treasury), "Access Denied");
        _;
    }
    modifier onlyETHKey() {
        require(msg.sender == address(ethKey), "Access Denied");
        _;
    }
}

pragma solidity 0.8.21;
import { MilestoneConstants } from "../../constants/MilestoneConstants.sol";
import { MilestoneEncoder } from "../../encoders/MilestoneEncoder.sol";
import { MilestoneEvents } from "../../events/MilestoneEvents.sol";
import { CrossChainErrors } from "../../errors/cross-chain/CrossChainErrors.sol";
import { RequestTypes } from "../../structs/RequestTypes.sol";
import { EnumTypes } from "../../structs/EnumTypes.sol";
import { CrossChainRequestTypes } from "../../structs/CrossChainRequestTypes.sol";
import { LibMilestone } from "../../libraries/storage/milestone/LibMilestone.sol";
import { ERC20AssetService } from "../../libraries/services/assets/internal/ERC20AssetService.sol";
import { AlephZeroSenderService } from "../../libraries/services/cross-chain/aleph-zero/AlephZeroSenderService.sol";
import { LayerZeroSenderService } from "../../libraries/services/cross-chain/layer-zero/LayerZeroSenderService.sol";
import { RejectMilestoneService } from "../../libraries/services/milestone/RejectMilestoneService.sol";
import { RequestService } from "../../libraries/services/utils/RequestService.sol";
import { SignatureService } from "../../libraries/services/utils/SignatureService.sol";
import { RaiseService } from "../../libraries/services/raise/internal/RaiseService.sol";
import { IRejectMilestoneFacet } from "../../interfaces/milestone/IRejectMilestoneFacet.sol";
contract RejectMilestoneFacet is IRejectMilestoneFacet {
    function rejectRaise(
        RequestTypes.RejectRaiseRequest calldata _request,
        bytes32 _message,
        uint8 _v,
        bytes32 _r,
        bytes32 _s,
        CrossChainRequestTypes.CrossChainData calldata _crossChainData
    ) external payable {
        RequestService.validateBaseRequest(_request.base);
        RaiseService.validateCompletedRaise(_request.raiseId);
        RejectMilestoneService.validateRejectRaiseRequest(_request.raiseId);
        bytes memory encodedMsg_ = MilestoneEncoder.encodeRejectRaise(_request);
        SignatureService.verifyMessage(MilestoneConstants.EIP712_NAME, MilestoneConstants.EIP712_VERSION, keccak256(encodedMsg_), _message);
        SignatureService.verifySignature(_message, _v, _r, _s);
        uint256 rejectedShares_ = LibMilestone.rejectRaise(_request.raiseId);
        uint256 crossChainId_ = ERC20AssetService.getERC20AssetChainId(_request.raiseId);
        if (crossChainId_ != block.chainid) {
            if (_crossChainData.provider == EnumTypes.CrossChainProvider.LayerZero) {
                LayerZeroSenderService.sendCrossChainMessage(_crossChainData.data, crossChainId_);
            } else if (_crossChainData.provider == EnumTypes.CrossChainProvider.AlephZero) {
                AlephZeroSenderService.sendCrossChainMessage(_crossChainData.data, crossChainId_);
            } else {
                revert CrossChainErrors.UnsupportedProvider();
            }
        }
        emit MilestoneEvents.RaiseRejected(_request.raiseId, rejectedShares_);
    }
}

pragma solidity ^0.8.23;
