contract AdvancedToken {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;
    uint256 public tradingActiveTime;
    bool public tradingActive;
    address public owner;
    address public treasury;
    address public taxAccount;
    address public uniswapRouter;
    uint256 public taxRate = 500;
    uint256 public burnRate = 200;
    uint256 public constant FEE_DENOMINATOR = 10000;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => bool) public blacklisted;
    mapping(address => bool) public excludedFromFees;
    mapping(address => bool) public excludedFromLimits;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event BlacklistUpdated(address indexed account, bool status);
    event TradingActivated();
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier tradingEnabled() {
        require(tradingActive && block.timestamp >= tradingActiveTime, "Trading disabled");
        _;
    }
    constructor(string memory _name, string memory _symbol, uint8 _decimals, uint256 _initialSupply, address _treasury, address _taxAccount, address _router) {
        name = _name;
        symbol = _symbol;
        decimals = _decimals;
        totalSupply = _initialSupply * 10 ** _decimals;
        maxTxAmount = totalSupply / 100;
        maxWalletAmount = totalSupply / 50;
        owner = msg.sender;
        treasury = _treasury;
        taxAccount = _taxAccount;
        uniswapRouter = _router;
        balanceOf[msg.sender] = totalSupply;
        excludedFromFees[msg.sender] = true;
        excludedFromFees[address(this)] = true;
        excludedFromLimits[msg.sender] = true;
        excludedFromLimits[address(this)] = true;
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(allowance[from][msg.sender] >= value, "Allowance exceeded");
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(!blacklisted[from] && !blacklisted[to], "Blacklisted");
        require(value > 0, "Invalid amount");
        if (!excludedFromLimits[from] && !excludedFromLimits[to]) {
            if (tradingActive) {
                require(value <= maxTxAmount, "Exceeds max transaction");
                require(balanceOf[to] + value <= maxWalletAmount, "Exceeds max wallet");
            }
        }
        uint256 taxAmount = 0;
        uint256 burnAmount = 0;
        if (!excludedFromFees[from] && !excludedFromFees[to] && tradingActive) {
            taxAmount = (value * taxRate) / FEE_DENOMINATOR;
            burnAmount = (value * burnRate) / FEE_DENOMINATOR;
        }
        uint256 netAmount = value - taxAmount - burnAmount;
        balanceOf[from] -= value;
        balanceOf[to] += netAmount;
        if (taxAmount > 0) {
            balanceOf[taxAccount] += taxAmount;
            emit Transfer(from, taxAccount, taxAmount);
        }
        if (burnAmount > 0) {
            totalSupply -= burnAmount;
            emit Transfer(from, address(0), burnAmount);
        }
        emit Transfer(from, to, netAmount);
    }
    function activateTrading() external onlyOwner {
        require(!tradingActive, "Already active");
        tradingActive = true;
        tradingActiveTime = block.timestamp + 300;
        emit TradingActivated();
    }
    function addLiquidity(uint256 tokenAmount) external payable onlyOwner {
        require(tokenAmount > 0, "Invalid amount");
        require(balanceOf[msg.sender] >= tokenAmount, "Insufficient balance");
        balanceOf[msg.sender] -= tokenAmount;
        balanceOf[address(this)] += tokenAmount;
        allowance[address(this)][uniswapRouter] = tokenAmount;
        IUniswapV2Router(uniswapRouter).addLiquidityETH{value: msg.value}(address(this), tokenAmount, 0, 0, owner, block.timestamp);
    }
    function setBlacklist(address account, bool status) external onlyOwner {
        blacklisted[account] = status;
        emit BlacklistUpdated(account, status);
    }
    function setExcludedFromFees(address account, bool status) external onlyOwner {
        excludedFromFees[account] = status;
    }
    function setExcludedFromLimits(address account, bool status) external onlyOwner {
        excludedFromLimits[account] = status;
    }
    function setTaxRates(uint256 _taxRate, uint256 _burnRate) external onlyOwner {
        taxRate = _taxRate;
        burnRate = _burnRate;
    }
    function setLimits(uint256 _maxTxAmount, uint256 _maxWalletAmount) external onlyOwner {
        maxTxAmount = _maxTxAmount;
        maxWalletAmount = _maxWalletAmount;
    }
    function withdrawTokens(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
    function withdrawETH(uint256 amount) external onlyOwner {
        payable(owner).transfer(amount);
    }
    receive() external payable {}
}

