contract ConfigurableERC20 is ERC20, Ownable {
    using Address for address;

    // --- State Variables ---
    uint8 private _decimals;
    address[] public feeRecipients;
    uint256[] public feeAmounts;
    uint256 public totalFeeAmount;

    // --- Events ---
    event FeeDistributed(address indexed recipient, uint256 amount);
    event TokenRecovery(address indexed token, address indexed sender, uint256 amount);

    // --- Constructor ---
    /**
     * @dev Initializes the token with name, symbol, supply, decimals, and fee distribution.
     * @param name Name of the token.
     * @param symbol Symbol of the token.
     * @param initialSupply Total supply to mint.
     * @param tokenDecimals Number of decimals (e.g., 18).
     * @param recipients Array of addresses to receive deployment fees.
     * @param amounts Array of amounts to send to each recipient.
     */
    constructor(
        string memory name,
        string memory symbol,
        uint256 initialSupply,
        uint8 tokenDecimals,
        address[] memory recipients,
        uint256[] memory amounts
    ) ERC20(name, symbol) Ownable() {
        require(initialSupply > 0, "ConfigurableERC20: supply must be greater than 0");
        require(tokenDecimals <= 18, "ConfigurableERC20: decimals too high");
        require(recipients.length == amounts.length, "ConfigurableERC20: arrays length mismatch");

        _decimals = tokenDecimals;

        // Mint total supply to owner
        _mint(msg.sender, initialSupply);

        // Validate and store fee recipients and amounts
        for (uint256 i = 0; i < recipients.length; i++) {
            require(recipients[i] != address(0), "ConfigurableERC20: recipient is zero address");
            // Optional: add check for duplicate addresses

