import "./ERC20.sol";
import "./Ownable.sol";
import "./IUniswapRouter.sol";

contract GPT is ERC20, Ownable {
    uint256 constant TIME_LIMIT = 3; 

    IUniswapRouter public router;
    address public pair;
    address public feeWallet;

    bool private swapping;
    bool public tradingEnabled;

    uint256 swapTokensAtAmount;
    uint256 maxHold;
    uint256 limitTimeStamp;

    uint256 tax = 5; //To be shared to stakers

    mapping(address => bool) private _isExcludedFromFees;

    event ExcludeFromFees(address indexed account, bool isExcluded);

    constructor(
        address _routerAddress,
        address _feeWallet
    ) ERC20("Graphitect AI", "GPT") {
        feeWallet = _feeWallet;

        IUniswapRouter _router = IUniswapRouter(_routerAddress);

        address _pair = IFactory(_router.factory()).createPair(
            address(this),
            _router.WETH()
        );

        router = _router;

        pair = _pair;

        excludeFromFees(owner(), true);
        excludeFromFees(_feeWallet, true);
        excludeFromFees(address(this), true);

        setSwapTokensAtAmount(5000_000);

        maxHold = 2_000_000 * (10 ** 18);

        _mint(owner(), 100_000_000 * (10 ** 18));
    }

    function setSwapTokensAtAmount(uint256 amount) public onlyOwner {
        swapTokensAtAmount = amount * 10 ** 18;
    }

    function excludeFromFees(address account, bool excluded) public onlyOwner {
        require(
            _isExcludedFromFees[account] != excluded,
            "Account is already excluded"
        );
        _isExcludedFromFees[account] = excluded;

        emit ExcludeFromFees(account, excluded);
    }

    function isExcludedFromFees(address account) public view returns (bool) {
        return _isExcludedFromFees[account];
    }

    function setFeeWallet(address _feeWallet) public onlyOwner {
        feeWallet = _feeWallet;
    }

    function activateTrading() external onlyOwner {
        require(!tradingEnabled, "Trading already enabled");
        tradingEnabled = true;
        limitTimeStamp = block.timestamp + TIME_LIMIT;
    }

    function _transfer(
        address from,
        address to,
        uint256 amount
    ) internal override {
        require(from != address(0), "ERC20: Transfer from the zero address");
        require(to != address(0), "ERC20: Transfer to the zero address");

        address _pair = pair;

        if (
            !_isExcludedFromFees[from] && !_isExcludedFromFees[to] && !swapping
        ) {
            require(tradingEnabled, "Trading not active");
            if (limitTimeStamp > block.timestamp && to != _pair) {
                require(
                    amount + balanceOf(to) <= maxHold,
                    "Unable to exceed Max Wallet"
                );
            }
        }

        if (amount == 0) {
            super._transfer(from, to, 0);
            return;
        }

        uint256 contractTokenBalance = balanceOf(address(this));
        bool canSwap = contractTokenBalance >= swapTokensAtAmount;

        if (
            canSwap &&
            !swapping &&
            to == _pair &&
            !_isExcludedFromFees[from] &&
            !_isExcludedFromFees[to]
