contract TaxToken is ERC20, Ownable {
    using SafeERC20 for IERC20;
    IUniswapV2Router02 public uniswapRouter;
    address public uniswapPair;
    address public marketingWallet;
    address public developmentWallet;
    uint256 public transactionTax = 500;
    uint256 public marketingShare = 300;
    uint256 public developmentShare = 200;
    uint256 public maxBuyAmount;
    uint256 public maxHoldAmount;
    uint256 public swapThreshold;
    uint256 private constant TAX_DENOMINATOR = 10000;
    bool public tradingEnabled = false;
    bool private inSwap;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isExcludedFromLimit;
    event TradingEnabled(bool enabled);
    event TaxUpdated(uint256 tax, uint256 marketing, uint256 development);
    event WalletsUpdated(address marketing, address development);
    event FeesDistributed(uint256 marketingETH, uint256 developmentETH);
    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor(string memory name, string memory symbol, uint256 totalSupply, address router, address marketing, address development) ERC20(name, symbol) {
        marketingWallet = marketing;
        developmentWallet = development;
        uniswapRouter = IUniswapV2Router02(router);
        uniswapPair = IUniswapV2Factory(uniswapRouter.factory()).createPair(address(this), uniswapRouter.WETH());
        maxBuyAmount = totalSupply * 10**decimals() / 100;
        maxHoldAmount = totalSupply * 10**decimals() / 50;
        swapThreshold = totalSupply * 10**decimals() / 1000;
        _mint(msg.sender, totalSupply * 10**decimals());
        isExcludedFromFee[msg.sender] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromFee[marketingWallet] = true;
        isExcludedFromFee[developmentWallet] = true;
        isExcludedFromLimit[msg.sender] = true;
        isExcludedFromLimit[address(this)] = true;
        isExcludedFromLimit[marketingWallet] = true;
        isExcludedFromLimit[developmentWallet] = true;
    }
    function _transfer(address from, address to, uint256 amount) internal override {
        require(from != address(0), "Transfer from zero address");
        require(to != address(0), "Transfer to zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading not enabled");
        }
        if (!isExcludedFromLimit[from] && !isExcludedFromLimit[to]) {
            if (from == uniswapPair) {
                require(amount <= maxBuyAmount, "Exceeds max buy amount");
            }
            if (to != uniswapPair) {
                require(balanceOf(to) + amount <= maxHoldAmount, "Exceeds max hold amount");
            }
        }
        uint256 taxAmount = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to] && !inSwap) {
            taxAmount = amount * transactionTax / TAX_DENOMINATOR;
            if (taxAmount > 0) {
                super._transfer(from, address(this), taxAmount);
                amount -= taxAmount;
            }
            if (to == uniswapPair) {
                _distributeFees();
            }
        }
        super._transfer(from, to, amount);
    }
    function _distributeFees() private lockTheSwap {
        uint256 contractBalance = balanceOf(address(this));
        if (contractBalance >= swapThreshold) {
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(contractBalance);
            uint256 newBalance = address(this).balance - initialBalance;
            uint256 marketingETH = newBalance * marketingShare / transactionTax;
            uint256 developmentETH = newBalance - marketingETH;
            if (marketingETH > 0) {
                payable(marketingWallet).transfer(marketingETH);
            }
            if (developmentETH > 0) {
                payable(developmentWallet).transfer(developmentETH);
            }
            emit FeesDistributed(marketingETH, developmentETH);
        }
    }
    function _swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapRouter.WETH();
        _approve(address(this), address(uniswapRouter), tokenAmount);
        uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount,0,path,address(this),block.timestamp);
    }
    function enableTrading() external onlyOwner {
        tradingEnabled = true;
        emit TradingEnabled(true);
    }
    function setTax(uint256 tax, uint256 marketing, uint256 development) external onlyOwner {
        require(tax <= 1000, "Tax too high");
        require(marketing + development == tax, "Tax distribution must equal total tax");
        transactionTax = tax;
        marketingShare = marketing;
        developmentShare = development;
        emit TaxUpdated(tax, marketing, development);
    }
    function setWallets(address marketing, address development) external onlyOwner {
        require(marketing != address(0) && development != address(0), "Invalid wallets");
        marketingWallet = marketing;
        developmentWallet = development;
        emit WalletsUpdated(marketing, development);
    }
    function setLimits(uint256 maxBuy, uint256 maxHold) external onlyOwner {
        maxBuyAmount = maxBuy;
        maxHoldAmount = maxHold;
    }
    function setSwapThreshold(uint256 threshold) external onlyOwner {
        swapThreshold = threshold;
    }
    function excludeFromFee(address account, bool excluded) external onlyOwner {
        isExcludedFromFee[account] = excluded;
    }
    function excludeFromLimit(address account, bool excluded) external onlyOwner {
        isExcludedFromLimit[account] = excluded;
    }
    function manualDistributeFees() external onlyOwner {
        _distributeFees();
    }
    function rescueTokens(address token, uint256 amount) external onlyOwner {
        IERC20(token).safeTransfer(owner(), amount);
    }
    receive() external payable {}
}

