import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
contract TokenVesting is ReentrancyGuard, Ownable {
    IERC20 public token;
    struct VestingSchedule {
        uint256 totalAmount;
        uint256 releasedAmount;
        uint256 startTime;
        uint256 cliffDuration;
        uint256 vestingDuration;
        bool revocable;
        bool revoked;
    }
    mapping(address => VestingSchedule) public vestingSchedules;
    event VestingScheduleCreated(address indexed beneficiary, uint256 amount, uint256 startTime, uint256 cliff, uint256 duration, bool revocable);
    event TokensReleased(address indexed beneficiary, uint256 amount);
    event VestingRevoked(address indexed beneficiary, uint256 unvestedAmount);
    constructor(address _token) {
        token = IERC20(_token);
    }
    function createVestingSchedule(address beneficiary, uint256 amount, uint256 startTime, uint256 cliff, uint256 duration, bool revocable) external onlyOwner {
        require(beneficiary != address(0), "Zero address beneficiary");
        require(amount > 0, "Zero amount");
        require(startTime >= block.timestamp, "Start time in past");
        require(cliff <= duration, "Cliff longer than duration");
        require(vestingSchedules[beneficiary].totalAmount == 0, "Schedule exists");
        vestingSchedules[beneficiary] = VestingSchedule({
            totalAmount: amount,
            releasedAmount: 0,
            startTime: startTime,
            cliffDuration: cliff,
            vestingDuration: duration,
            revocable: revocable,
            revoked: false
        });
        emit VestingScheduleCreated(beneficiary, amount, startTime, cliff, duration, revocable);
    }
    function release() external nonReentrant {
        VestingSchedule storage schedule = vestingSchedules[msg.sender];
        require(schedule.totalAmount > 0, "No vesting schedule");
        require(!schedule.revoked, "Vesting revoked");
        uint256 releasable = _computeReleasableAmount(schedule);
        require(releasable > 0, "No tokens to release");
        schedule.releasedAmount += releasable;
        require(token.transfer(msg.sender, releasable), "Transfer failed");
        emit TokensReleased(msg.sender, releasable);
    }
    function revokeVesting(address beneficiary) external onlyOwner {
        VestingSchedule storage schedule = vestingSchedules[beneficiary];
        require(schedule.totalAmount > 0, "No vesting schedule");
        require(schedule.revocable, "Not revocable");
        require(!schedule.revoked, "Already revoked");
        uint256 releasable = _computeReleasableAmount(schedule);
        schedule.revoked = true;
        if (releasable > 0) {
            schedule.releasedAmount += releasable;
            require(token.transfer(beneficiary, releasable), "Transfer failed");
        }
        uint256 unvestedAmount = schedule.totalAmount - schedule.releasedAmount;
        emit VestingRevoked(beneficiary, unvestedAmount);
    }
    function _computeReleasableAmount(VestingSchedule memory schedule) private view returns (uint256) {
        if (block.timestamp < schedule.startTime + schedule.cliffDuration) {
            return 0;
        }
        if (block.timestamp >= schedule.startTime + schedule.vestingDuration) {
            return schedule.totalAmount - schedule.releasedAmount;
        }
        uint256 timeElapsed = block.timestamp - schedule.startTime;
        uint256 totalVestable = schedule.totalAmount * timeElapsed / schedule.vestingDuration;
        return totalVestable - schedule.releasedAmount;
    }
    function getReleasableAmount(address beneficiary) external view returns (uint256) {
        VestingSchedule memory schedule = vestingSchedules[beneficiary];
        if (schedule.totalAmount == 0 || schedule.revoked) return 0;
        return _computeReleasableAmount(schedule);
    }
}

