        AssetType assetType;
        uint256 nonce;
        uint256 availableAfter;
        uint256 deadline;
    }
    constructor(
        address earnStakingManager
    ) EIP712("EarnNetwork", "1") EarnAssetHolder(earnStakingManager) {}
    function addReward(
        address executor,
        address tokenAddress,
        uint256 erc1155TokenId,
        uint256 amount,
        uint256[] memory erc721TokenIds,
        AssetType assetType,
        uint256 nonce,
        uint256 availableAfter,
        uint256 deadline,
        bytes memory signature
    ) external payable nonReentrant {
        ExecutionData memory data = ExecutionData(
            executor,
            tokenAddress,
            erc1155TokenId,
            amount,
            erc721TokenIds,
            assetType,
            nonce,
            availableAfter,
            deadline
        );
        require(
            data.executor == msg.sender || data.executor == address(0),
            "EPR: Wrong executor"
        );
        require(block.timestamp <= data.deadline, "EPR: Transaction overdue");
        _deposit(data, signature);
    }
    function _deposit(
        ExecutionData memory data,
        bytes memory signature
    ) internal {
        require(data.amount > 0, "ESP: amount cannot be zero");
        _verifySignature(data, signature);
        _useNonce(data.nonce);
        Asset memory sa = stakingManager.getOrCreateAsset(
            0,
            data.tokenAddress,
            data.erc1155TokenId,
            data.assetType
        );
        _depositAsset(stakingManager.rewardsHolderContract(), data.amount, sa, data.erc721TokenIds);
        stakingManager.execReward(
            data.executor,
            data.nonce,
            data.tokenAddress,
            data.amount,
            data.erc1155TokenId,
            data.erc721TokenIds,
            false
        );
    }
    function _verifySignature(
        ExecutionData memory data,
        bytes memory signature
    ) internal view {
        require(data.deadline >= block.timestamp, "EPR: deadline is reached");
        require(
            data.availableAfter <= block.timestamp,
            "EPR: not available yet"
        );
        bytes32 typedHash = _hashTypedDataV4(
            keccak256(
                abi.encode(
                    keccak256(
                        "Reward(address executor,address tokenAddress,uint256 erc1155TokenId,uint256 amount,uint256[] erc721TokenIds,uint256 assetType,uint256 nonce,uint256 availableAfter,uint256 deadline)"
                    ),
                    data.executor,
                    data.tokenAddress,
                    data.erc1155TokenId,
                    data.amount,
                    keccak256(abi.encodePacked(data.erc721TokenIds)),
                    data.assetType,
                    data.nonce,
                    data.availableAfter,
                    data.deadline
                )
            )
        );
        require(
            ECDSA.recover(typedHash, signature) == stakingManager.signer(),
            "EarnPayments: Wrong signature"
        );
    }
    function adminWithdraw(
        address tokenAddress,
        uint256 erc1155tokenId,
        AssetType assetType,
        uint256 amount,
        uint256[] memory erc721TokenIds
    ) external onlyAdmin {
        stakingManager.getOrCreateAsset(
            0,
            tokenAddress,
            erc1155tokenId,
            assetType
        );
        bytes32 assetId = stakingManager.getAssetId(
            tokenAddress,
            erc1155tokenId,
            assetType
        );
        _withdrawAssets(
            stakingManager.treasury(),
            amount,
            erc721TokenIds,
            assetId
        );
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract StrategyManager is ReentrancyGuard {
    address public owner;
    address public admin;

    struct Strategy {
        address receiver;
        uint256 usdcPercent;
        uint256 wethPercent;
        uint256 daiPercent;
        uint256 lastDistribution;
        bool isActive;
    }

    mapping(uint256 => Strategy) public strategies;
    uint256 public strategyCount;

    IERC20 public usdc;
    IERC20 public weth;
    IERC20 public dai;

    uint256 public constant DAILY_COOLDOWN = 1 days;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    modifier onlyAdminOrOwner() {
        require(msg.sender == admin || msg.sender == owner, "not admin or owner");
        _;
    }

    constructor(address _usdc, address _weth, address _dai) {
        owner = msg.sender;
        admin = msg.sender;
        usdc = IERC20(_usdc);
        weth = IERC20(_weth);
        dai = IERC20(_dai);
    }

    function addStrategy(address receiver, uint256 usdcPct, uint256 wethPct, uint256 daiPct) external onlyAdminOrOwner {
        require(receiver != address(0), "invalid receiver");
        require(usdcPct <= 10000 && wethPct <= 10000 && daiPct <= 10000, "invalid percent");
        strategies[strategyCount] = Strategy(receiver, usdcPct, wethPct, daiPct, 0, true);
        strategyCount++;
    }

    function updateStrategy(uint256 id, address receiver, uint256 usdcPct, uint256 wethPct, uint256 daiPct) external onlyAdminOrOwner {
        require(id < strategyCount, "invalid id");
        require(receiver != address(0), "invalid receiver");
        require(usdcPct <= 10000 && wethPct <= 10000 && daiPct <= 10000, "invalid percent");
        Strategy storage s = strategies[id];
        s.receiver = receiver;
        s.usdcPercent = usdcPct;
        s.wethPercent = wethPct;
        s.daiPercent = daiPct;
    }

    function removeStrategy(uint256 id) external onlyAdminOrOwner {
        require(id < strategyCount, "invalid id");
        strategies[id].isActive = false;
    }

    function setAdmin(address _admin) external onlyOwner {
        require(_admin != address(0), "invalid admin");
        admin = _admin;
    }

    function migrateStrategy(uint256 fromId, uint256 toId) external onlyOwner {
        require(fromId < strategyCount && toId < strategyCount, "invalid id");
        require(strategies[fromId].isActive && strategies[toId].isActive, "inactive strategy");
        Strategy storage from = strategies[fromId];
        Strategy storage to = strategies[toId];
        to.usdcPercent += from.usdcPercent;
        to.wethPercent += from.wethPercent;
        to.daiPercent += from.daiPercent;
        from.isActive = false;
    }

    function distribute() external nonReentrant {
        require(strategies[0].receiver != address(0), "no strategies");
        for (uint256 i = 0; i < strategyCount; i++) {
            Strategy storage s = strategies[i];
            require(block.timestamp >= s.lastDistribution + DAILY_COOLDOWN, "cooldown not met");
            if (s.isActive && s.receiver != address(0)) {
                uint256 usdcAmount = (usdc.balanceOf(address(this)) * s.usdcPercent) / 10000;
                uint256 wethAmount = (weth.balanceOf(address(this)) * s.wethPercent) / 10000;
                uint256 daiAmount = (dai.balanceOf(address(this)) * s.daiPercent) / 10000;
                if (usdcAmount > 0) usdc.transfer(s.receiver, usdcAmount);
                if (wethAmount > 0) weth.transfer(s.receiver, wethAmount);
                if (daiAmount > 0) dai.transfer(s.receiver, daiAmount);
                s.lastDistribution = block.timestamp;
            }
        }
    }
}

