pragma solidity ^0.8.0;
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
interface IOracle {
    function latestAnswer() external view returns (int256);
}
interface IRebasingToken {
    function balanceOf(address account) external view returns (uint256);
    function sharesToBalance(uint256 shares) external view returns (uint256);
}
interface IERC4626 {
    function convertToAssets(uint256 shares) external view returns (uint256);
}
contract CurveStableswap is ReentrancyGuard {
    using SafeERC20 for IERC20;
    uint256 public constant N_COINS = 8;
    uint256 public constant PRECISION = 1e18;
    uint256 public constant A_PRECISION = 100;
    uint256 public constant MAX_FEE = 1e16;
    uint256 public constant MAX_ADMIN_FEE = 1e17;
    uint256 public amp;
    uint256 public fee;
    uint256 public admin_fee;
    address[N_COINS] public coins;
    uint256[N_COINS] public precisions;
    uint256[N_COINS] public rates;
    uint256[N_COINS] public balances;
    uint256 public total_supply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    struct EMA {
        uint256 value;
        uint256 lastUpdate;
    }
    EMA public priceEMA;
    EMA public tvlEMA;
    uint256 public emaAlpha = 9e17;
    uint256 public future_amp;
    uint256 public future_amp_time;
    address public owner;
    mapping(uint256 => IOracle) public oracles;
    mapping(uint256 => bool) public isRebasing;
    mapping(uint256 => bool) public isERC4626;
    event TokenExchange(address indexed buyer, uint256 sold_id, uint256 tokens_sold, uint256 bought_id, uint256 tokens_bought);
    event AddLiquidity(address indexed provider, uint256[N_COINS] token_amounts, uint256 fee, uint256 token_supply);
    event RemoveLiquidity(address indexed provider, uint256[N_COINS] token_amounts, uint256 token_supply);
    event CommitNewParameters(uint256 amp, uint256 fee, uint256 admin_fee);
    event NewParameters(uint256 amp, uint256 fee, uint256 admin_fee);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(address[N_COINS] memory _coins, uint256[N_COINS] memory _precisions, uint256 _amp, uint256 _fee, uint256 _admin_fee) {
        owner = msg.sender;
        coins = _coins;
        precisions = _precisions;
        amp = _amp;
        fee = _fee;
        admin_fee = _admin_fee;
        for (uint256 i = 0; i < N_COINS; i++) {
            rates[i] = PRECISION;
        }
    }
    function get_dy(uint256 i, uint256 j, uint256 dx) external view returns (uint256) {
        uint256[N_COINS] memory xp = _xp();
        uint256 x = xp[i] + (dx * rates[i] / PRECISION);
        uint256 y = _get_y(i, j, x, xp);
        uint256 dy = (xp[j] - y) * PRECISION / rates[j];
        uint256 _fee = dy * fee / 1e18;
        return dy - _fee;
    }
    function exchange(uint256 i, uint256 j, uint256 dx, uint256 min_dy) external nonReentrant returns (uint256) {
        require(i != j, "Same coin");
        IERC20(coins[i]).safeTransferFrom(msg.sender, address(this), dx);
        uint256[N_COINS] memory xp = _xp();
        uint256 x = xp[i] + (dx * rates[i] / PRECISION);
        uint256 y = _get_y(i, j, x, xp);
        uint256 dy = (xp[j] - y) * PRECISION / rates[j];
        uint256 _fee = dy * fee / 1e18;
        uint256 admin_fee_amount = _fee * admin_fee / 1e18;
        dy -= _fee;
        require(dy >= min_dy, "Slippage");
        balances[i] += dx;
        balances[j] -= dy;
        IERC20(coins[j]).safeTransfer(msg.sender, dy);
        _update_ema(dy, _get_virtual_price());
        emit TokenExchange(msg.sender, i, dx, j, dy);
        return dy;
    }
    function add_liquidity(uint256[N_COINS] memory amounts, uint256 min_mint_amount) external nonReentrant returns (uint256) {
        uint256[N_COINS] memory fees;
        uint256 _fee = fee * N_COINS / (4 * (N_COINS - 1));
        uint256 amp_ = _get_amp();
        uint256 token_supply = total_supply;
        uint256[N_COINS] memory old_balances = balances;
        uint256 D0;
        if (token_supply > 0) {
            D0 = _get_D_mem(old_balances, amp_);
        }
        for (uint256 i = 0; i < N_COINS; i++) {
            if (amounts[i] > 0) {
                IERC20(coins[i]).safeTransferFrom(msg.sender, address(this), amounts[i]);
                balances[i] += amounts[i];
            }
        }
        uint256 D1 = _get_D(_xp(), amp_);
        uint256 mint_amount;
        if (token_supply == 0) {
            mint_amount = D1;
        } else {
            for (uint256 i = 0; i < N_COINS; i++) {
                uint256 ideal_balance = D1 * old_balances[i] / D0;
                uint256 difference;
                if (ideal_balance > balances[i]) {
                    difference = ideal_balance - balances[i];
                } else {
                    difference = balances[i] - ideal_balance;
                }
                fees[i] = _fee * difference / 1e18;
                balances[i] -= fees[i];
            }
            uint256 D2 = _get_D(_xp(), amp_);
            mint_amount = token_supply * (D2 - D0) / D0;
        }
        require(mint_amount >= min_mint_amount, "Slippage");
        total_supply += mint_amount;
        balanceOf[msg.sender] += mint_amount;
        _update_ema(mint_amount, _get_virtual_price());
        emit AddLiquidity(msg.sender, amounts, _fee, mint_amount);
        return mint_amount;
    }
    function _get_amp() internal view returns (uint256) {
        if (block.timestamp >= future_amp_time) {
            return future_amp;
        }
        uint256 t1 = future_amp_time;
        uint256 a1 = future_amp;
        if (block.timestamp <= t1 - 7 days) {
            return amp;
        }
        uint256 a2 = amp;
        uint256 t = block.timestamp;
        return a2 + (a1 - a2) * (t - (t1 - 7 days)) / 7 days;
    }
    function _xp() internal view returns (uint256[N_COINS] memory xp) {
        for (uint256 i = 0; i < N_COINS; i++) {
            xp[i] = _get_scaled_balance(i) * precisions[i];
        }
    }
    function _get_scaled_balance(uint256 i) internal view returns (uint256) {
        uint256 balance = balances[i];
        if (isRebasing[i]) {
            return IRebasingToken(coins[i]).sharesToBalance(balance);
        } else if (isERC4626[i]) {
            return IERC4626(coins[i]).convertToAssets(balance);
        } else if (address(oracles[i]) != address(0)) {
            return balance * uint256(oracles[i].latestAnswer()) / PRECISION;
        }
        return balance;
    }
    function _get_D(uint256[N_COINS] memory xp, uint256 _amp) internal pure returns (uint256) {
        uint256 S;
        for (uint256 i = 0; i < N_COINS; i++) {
            S += xp[i];
        }
        if (S == 0) return 0;
        uint256 D = S;
        uint256 Ann = _amp * N_COINS;
        for (uint256 j = 0; j < 255; j++) {
            uint256 D_prev = D;
            uint256 D_P = D;
            for (uint256 k = 0; k < N_COINS; k++) {
                D_P = D_P * D / (xp[k] * N_COINS);
            }
            uint256 D_next = (Ann * S + D_P * N_COINS) * D / ((Ann - 1) * D + (N_COINS + 1) * D_P);
            if (D_next > D) {
                if (D_next - D <= 1) return D_next;
            } else {
                if (D - D_next <= 1) return D_next;
            }
            D = D_next;
        }
        revert("D convergence failed");
    }
    function _get_D_mem(uint256[N_COINS] memory _balances, uint256 _amp) internal view returns (uint256) {
        uint256[N_COINS] memory xp;
        for (uint256 i = 0; i < N_COINS; i++) {
            xp[i] = _balances[i] * precisions[i];
        }
        return _get_D(xp, _amp);
    }
    function _get_y(uint256 i, uint256 j, uint256 x, uint256[N_COINS] memory xp) internal view returns (uint256) {
        uint256 _amp = _get_amp();
        uint256 D = _get_D(xp, _amp);
        uint256 c = D;
        uint256 S_;
        uint256 Ann = _amp * N_COINS;
        uint256 _x;
        for (uint256 k = 0; k < N_COINS; k++) {
            if (k == i) _x = x;
            else if (k != j) _x = xp[k];
            else continue;
            S_ += _x;
            c = c * D / (_x * N_COINS);
        }
        c = c * D / (Ann * N_COINS);
        uint256 b = S_ + D / Ann;
        uint256 y_prev;
        uint256 y = D;
        for (uint256 m = 0; m < 255; m++) {
            y_prev = y;
            y = (y*y + c) / (2 * y + b - D);
            if (y > y_prev) {
                if (y - y_prev <= 1) return y;
            } else {
                if (y_prev - y <= 1) return y;
            }
        }
        revert("Y convergence failed");
    }
    function _get_virtual_price() internal view returns (uint256) {
        uint256 D = _get_D(_xp(), _get_amp());
        uint256 token_supply = total_supply;
        if (token_supply > 0) {
            return D * PRECISION / token_supply;
        }
        return 0;
    }
    function _update_ema(uint256 volume, uint256 price) internal {
        uint256 timeElapsed = block.timestamp - priceEMA.lastUpdate;
        if (timeElapsed > 0) {
            uint256 alpha = emaAlpha ** timeElapsed;
            priceEMA.value = (price * (PRECISION - alpha) + priceEMA.value * alpha) / PRECISION;
            tvlEMA.value = (volume * (PRECISION - alpha) + tvlEMA.value * alpha) / PRECISION;
            priceEMA.lastUpdate = block.timestamp;
            tvlEMA.lastUpdate = block.timestamp;
        }
    }
    function commit_new_parameters(uint256 _amp, uint256 _fee, uint256 _admin_fee) external onlyOwner {
        require(_fee <= MAX_FEE, "Fee too high");
        require(_admin_fee <= MAX_ADMIN_FEE, "Admin fee too high");
        future_amp = _amp;
        future_amp_time = block.timestamp + 7 days;
        emit CommitNewParameters(_amp, _fee, _admin_fee);
    }
    function apply_new_parameters() external onlyOwner {
        require(block.timestamp >= future_amp_time, "Too early");
        amp = future_amp;
        emit NewParameters(amp, fee, admin_fee);
    }
    function set_token_type(uint256 i, bool _isRebasing, bool _isERC4626, address oracle) external onlyOwner {
        isRebasing[i] = _isRebasing;
        isERC4626[i] = _isERC4626;
        oracles[i] = IOracle(oracle);
    }
}

