    string private constant _symbol = "BBS";

    uint256 public buyReflectionFee = 5;
    uint256 public buyLiquidityFee = 3;
    uint256 public buyMarketingFee = 2;
    uint256 public sellReflectionFee = 8;
    uint256 public sellLiquidityFee = 4;
    uint256 public sellMarketingFee = 3;

    uint256 public maxTxAmount = TOTAL_SUPPLY / 500; // 0.2%
    uint256 public maxWalletAmount = TOTAL_SUPPLY / 200; // 0.5%

    bool private inSwapAndLiquify;
    bool public swapAndLiquifyEnabled = true;
    uint256 public swapTokensAtAmount = TOTAL_SUPPLY / 1000; // 0.1%

    address public marketingWallet;

    event SwapAndLiquify(uint256 tokensSwapped, uint256 ethReceived, uint256 tokensIntoLiqudity);
    event SwapTokensForETH(uint256 amountIn, address[] path);

    modifier lockTheSwap {
        inSwapAndLiquify = true;
        _;
        inSwapAndLiquify = false;
    }

    constructor(address _marketingWallet, address routerAddress) {
        marketingWallet = _marketingWallet;

        _balances[address(this)] = TOTAL_SUPPLY;

        IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(routerAddress);
        uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory()).createPair(address(this), _uniswapV2Router.WETH());
        uniswapV2Router = _uniswapV2Router;

        _isExcludedFromFees[owner()] = true;
        _isExcludedFromFees[address(this)] = true;
        _isExcludedFromFees[marketingWallet] = true;

        _isExcludedFromMaxTx[owner()] = true;
        _isExcludedFromMaxTx[address(this)] = true;
        _isExcludedFromMaxTx[marketingWallet] = true;

        _isExcludedFromMaxWallet[owner()] = true;
        _isExcludedFromMaxWallet[address(this)] = true;
        _isExcludedFromMaxWallet[uniswapV2Pair] = true;

        emit Transfer(address(0), address(this), TOTAL_SUPPLY);
    }

    function name() public pure override returns (string memory) {
        return _name;
    }

    function symbol() public pure override returns (string memory) {
        return _symbol;
    }

    function decimals() public pure override returns (uint8) {
        return DECIMALS;
    }

    function totalSupply() public pure override returns (uint256) {
        return TOTAL_SUPPLY;
    }

    function balanceOf(address account) public view override returns (uint256) {
        return _balances[account];
    }

    function transfer(address recipient, uint256 amount) public override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }

    function allowance(address owner, address spender) public view override returns (uint256) {
        return _allowances[owner][spender];
    }

    function approve(address spender, uint256 amount) public override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(sender, _msgSender(), _allowances[sender][_msgSender()].sub(amount, "ERC20: transfer amount exceeds allowance"));
        return true;
    }

    function _approve(address owner, address spender, uint256 amount) private {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }

    function _transfer(address from, address to, uint256 amount) private {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");

        if (!_isExcludedFromMaxTx[from] && !_isExcludedFromMaxTx[to]) {
            require(amount <= maxTxAmount, "Transfer amount exceeds max tx limit");
        }

        if (!_isExcludedFromMaxWallet[to]) {
            require(_balances[to].add(amount) <= maxWalletAmount, "Exceeds max wallet limit");
        }

        uint256 contractTokenBalance = _balances[address(this)];
        bool overMinimumTokenBalance = contractTokenBalance >= swapTokensAtAmount;

        if (!inSwapAndLiquify && swapAndLiquifyEnabled && to == uniswapV2Pair) {
            if (overMinimumTokenBalance) {
                swapAndLiquify(swapTokensAtAmount);
            }
        }

        bool takeFee = !(_isExcludedFromFees[from] || _isExcludedFromFees[to]) && swapAndLiquifyEnabled;
        if (takeFee) {
            _takeFees(from, to, amount);
        } else {
            _balances[from] = _balances[from].sub(amount);
            _balances[to] = _balances[to].add(amount);
            emit Transfer(from, to, amount);
        }
    }

    function _takeFees(address from, address to, uint256 amount) private {
        uint256 totalFee = 0;
        uint256 reflectionFee = 0;
        uint256 liquidityFee = 0;
        uint256 marketingFee = 0;

        if (from == uniswapV2Pair) {
            reflectionFee = amount.mul(buyReflectionFee).div(100);
            liquidityFee = amount.mul(buyLiquidityFee).div(100);
            marketingFee = amount.mul(buyMarketingFee).div(100);
        } else if (to == uniswapV2Pair) {
            reflectionFee = amount.mul(sellReflectionFee).div(100);
            liquidityFee = amount.mul(sellLiquidityFee).div(100);
            marketingFee = amount.mul(sellMarketingFee).div(100);
        }

        totalFee = reflectionFee.add(liquidityFee).add(marketingFee);

        _balances[from] = _balances[from].sub(amount);
        _balances[address(this)] = _balances[address(this)].add(totalFee);
        _balances[to] = _balances[to].add(amount.sub(totalFee));

        if (liquidityFee > 0) {
            emit Transfer(from, address(this), liquidityFee);
        }
        if (marketingFee > 0) {
            emit Transfer(from, marketingWallet, marketingFee);
            _balances[address(this)] = _balances[address(this)].sub(marketingFee);
            _balances[marketingWallet] = _balances[marketingWallet].add(marketingFee);
        }
        if (reflectionFee > 0) {
            emit Transfer(from, address(this), reflectionFee);
        }
    }

    function swapAndLiquify(uint256 contractTokenBalance) private lockTheSwap {
        uint256 totalFees = buyLiquidityFee.add(buyMarketingFee).add(sellLiquidityFee).add(sellMarketingFee);
        if (totalFees == 0) return;

        uint256 marketingShare = buyMarketingFee.add(sellMarketingFee);
        uint256 liquidityShare = buyLiquidityFee.add(sellLiquidityFee);
        uint256 liquidityTokens = contractTokenBalance.mul(liquidityShare).div(totalFees).div(2);
        uint256 marketingTokens = contractTokenBalance.mul(marketingShare).div(totalFees);
        uint256 swapTokens = liquidityTokens.add(marketingTokens);

        uint256 initialBalance = address(this).balance;

        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(swapTokens, 0, path, address(this), block.timestamp);

        uint256 ethReceived = address(this).balance.sub(initialBalance);
        uint256 ethLiquidity = ethReceived.mul(liquidityShare).div(liquidityShare.add(marketingShare));

        if (liquidityTokens > 0 && ethLiquidity > 0) {
            uniswapV2Router.addLiquidityETH{value: ethLiquidity}(address(this), liquidityTokens, 0, 0, owner(), block.timestamp);
            emit SwapAndLiquify(liquidityTokens, ethLiquidity, liquidityTokens);
        }

        emit SwapTokensForETH(swapTokens, path);
    }

    function setMarketingWallet(address newWallet) external {
        require(msg.sender == marketingWallet || msg.sender == owner(), "not authorized");
        marketingWallet = newWallet;
    }

    function setSwapAndLiquifyEnabled(bool enabled) external {
        require(msg.sender == owner(), "not owner");
        swapAndLiquifyEnabled = enabled;
    }

    function setBuyFees(uint256 reflection, uint256 liquidity, uint256 marketing) external {
        require(msg.sender == owner(), "not owner");
        buyReflectionFee = reflection;
        buyLiquidityFee = liquidity;
        buyMarketingFee = marketing;
    }

    function setSellFees(uint256 reflection, uint256 liquidity, uint256 marketing) external {
        require(msg.sender == owner(), "not owner");
        sellReflectionFee = reflection;
        sellLiquidityFee = liquidity;
        sellMarketingFee = marketing;
    }

    function excludeFromFees(address account, bool excluded) external {
        require(msg.sender == owner(), "not owner");
        _isExcludedFromFees[account] = excluded;
    }

    function excludeFromMaxTx(address account, bool excluded) external {
        require(msg.sender == owner(), "not owner");
        _isExcludedFromMaxTx[account] = excluded;
    }

    function excludeFromMaxWallet(address account, bool excluded) external {
        require(msg.sender == owner(), "not owner");
        _isExcludedFromMaxWallet[account] = excluded;
    }

    function setMaxTxAmount(uint256 amount) external {
        require(msg.sender == owner(), "not owner");
        maxTxAmount = amount;
    }

    function setMaxWalletAmount(uint256 amount) external {
        require(msg.sender == owner(), "not owner");
        maxWalletAmount = amount;
    }

    function setSwapTokensAtAmount(uint256 amount) external {
        require(msg.sender == owner(), "not owner");
        swapTokensAtAmount = amount;
    }

    function rescueETH(uint256 amount) external {
        require(msg.sender == owner() || msg.sender == marketingWallet, "not authorized");
        payable(msg.sender).transfer(amount);
    }

    function rescueERC20(address tokenAddress, uint256 tokens) external {
        require(msg.sender == owner() || msg.sender == marketingWallet, "not authorized");
        IERC20(tokenAddress).transfer(msg.sender, tokens);
    }

    receive() external payable {}
}

