import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MistCoinWrapper is ERC20, Ownable {
    IERC20 public immutable mistCoin;

    mapping(address => bool) public dropBox;
    mapping(address => bool) public transferWhitelist;

    bool public wrappingEnabled = true;
    bool public unwrappingEnabled = true;

    event Wrap(address indexed user, uint256 amount);
    event Unwrap(address indexed user, uint256 amount);
    event DropBoxUpdated(address indexed user, bool enabled);
    event TransferWhitelistUpdated(address indexed user, bool enabled);

    constructor(address _mistCoin) ERC20("MistCoin Wrapper", "wMIST") {
        require(_mistCoin != address(0), "invalid token address");
        mistCoin = IERC20(_mistCoin);
    }

    function wrap(uint256 amount) external {
        require(wrappingEnabled, "wrapping disabled");
        require(amount > 0, "amount is zero");
        require(mistCoin.transferFrom(msg.sender, address(this), amount), "transfer failed");
        _mint(msg.sender, amount);
        emit Wrap(msg.sender, amount);
    }

    function unwrap(uint256 amount) external {
        require(unwrappingEnabled, "unwrapping disabled");
        require(amount > 0, "amount is zero");
        _burn(msg.sender, amount);
        require(mistCoin.transfer(msg.sender, amount), "transfer failed");
        emit Unwrap(msg.sender, amount);
    }

    function setWrappingEnabled(bool enabled) external onlyOwner {
        wrappingEnabled = enabled;
    }

    function setUnwrappingEnabled(bool enabled) external onlyOwner {
        unwrappingEnabled = enabled;
    }

    function setDropBox(address user, bool enabled) external onlyOwner {
        dropBox[user] = enabled;
        emit DropBoxUpdated(user, enabled);
    }

    function setTransferWhitelist(address user, bool enabled) external onlyOwner {
        transferWhitelist[user] = enabled;
        emit TransferWhitelistUpdated(user, enabled);
    }

    function _transfer(address from, address to, uint256 amount) internal override {
        require(amount > 0, "amount is zero");
        require(to != address(0), "transfer to zero address");

        if (!transferWhitelist[from] && !transferWhitelist[to]) {
            require(!dropBox[from] && !dropBox[to], "transfer restricted by drop box");
        }

        super._transfer(from, to, amount);
    }

    function rescueERC20(address tokenAddress, uint256 amount) external onlyOwner {
        require(tokenAddress != address(mistCoin), "cannot rescue MistCoin");
        IERC20(tokenAddress).transfer(owner(), amount);
    }

    function rescueMistCoin(uint256 amount) external onlyOwner {
        mistCoin.transfer(owner(), amount);
    }
}

