import "@openzeppelin/contracts/access/Ownable.sol";
abstract contract GasEfficientAccessControl is Ownable {
    mapping(address => uint256) private _roles;
    uint256 private constant OWNER_ROLE = 1 << 255;
    event RoleGranted(uint256 indexed role, address indexed account, address indexed sender);
    event RoleRevoked(uint256 indexed role, address indexed account, address indexed sender);
    function hasRole(address account, uint256 role) public view returns (bool) {
        uint256 accountRoles;
        assembly {
            accountRoles := sload(add(_roles.slot, account))
        }
        return (accountRoles & role != 0) || (account == owner() && (role & OWNER_ROLE != 0));
    }
    function grantRole(address account, uint256 role) external {
        require(msg.sender == owner() || hasRole(msg.sender, OWNER_ROLE), "Access denied");
        _grantRole(account, role);
    }
    function revokeRole(address account, uint256 role) external {
        require(msg.sender == owner() || hasRole(msg.sender, OWNER_ROLE), "Access denied");
        _revokeRole(account, role);
    }
    function _grantRole(address account, uint256 role) internal {
        uint256 currentRoles;
        assembly {
            let slot := add(_roles.slot, account)
            currentRoles := sload(slot)
            let newRoles := or(currentRoles, role)
            sstore(slot, newRoles)
        }
        emit RoleGranted(role, account, msg.sender);
    }
    function _revokeRole(address account, uint256 role) internal {
        uint256 currentRoles;
        assembly {
            let slot := add(_roles.slot, account)
            currentRoles := sload(slot)
            let newRoles := and(currentRoles, not(role))
            sstore(slot, newRoles)
        }
        emit RoleRevoked(role, account, msg.sender);
    }
    function grantRoles(address account, uint256[] calldata roles) external {
        require(msg.sender == owner() || hasRole(msg.sender, OWNER_ROLE), "Access denied");
        uint256 combinedRole;
        for (uint256 i = 0; i < roles.length; i++) {
            combinedRole |= roles[i];
        }
        _grantRole(account, combinedRole);
    }
    function revokeRoles(address account, uint256[] calldata roles) external {
        require(msg.sender == owner() || hasRole(msg.sender, OWNER_ROLE), "Access denied");
        uint256 combinedRole;
        for (uint256 i = 0; i < roles.length; i++) {
            combinedRole |= roles[i];
        }
        _revokeRole(account, combinedRole);
    }
    function getRoles(address account) external view returns (uint256) {
        uint256 accountRoles;
        assembly {
            accountRoles := sload(add(_roles.slot, account))
        }
        if (account == owner()) {
            accountRoles |= OWNER_ROLE;
        }
        return accountRoles;
    }
    modifier onlyRole(uint256 role) {
        require(hasRole(msg.sender, role), "Access denied");
        _;
    }
    modifier onlyOwnerOrRole(uint256 role) {
        require(msg.sender == owner() || hasRole(msg.sender, role), "Access denied");
        _;
    }
}

