contract Runestones is Context, Ownable {
    using Address for address;
    string public constant name = "Runestones";
    string public constant symbol = "RUNES";
    uint8 public constant decimals = 18;
    uint256 public constant TOTAL_SUPPLY = 10000 * 10**18;
    uint256 public constant MAX_WALLET = 200 * 10**18;
    uint256 private _totalSupply;
    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(uint256 => address) private _owners;
    mapping(address => uint256) private _ownedTokensCount;
    mapping(uint256 => RuneType) private _runeTypes;
    mapping(address => bool) public whitelist;
    mapping(address => bool) public blacklist;
    address public uniswapPair;
    IUniswapV2Router02 public uniswapRouter;
    bool public tradingEnabled = false;
    bool private inSwap;
    uint256 private _currentTokenId = 1;
    enum RuneType { COMMON, ADEPT, LEGENDARY }
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);
    event ApprovalForAll(address indexed owner, address indexed operator, bool approved);
    event RuneMinted(uint256 indexed tokenId, RuneType runeType, address indexed owner);
    event RuneBurned(uint256 indexed tokenId, address indexed owner);
    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor() {
        _mint(msg.sender, TOTAL_SUPPLY);
        uniswapRouter = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        uniswapPair = IUniswapV2Factory(uniswapRouter.factory()).createPair(address(this), uniswapRouter.WETH());
        whitelist[msg.sender] = true;
        whitelist[address(this)] = true;
    }
    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }
    function balanceOf(address account) public view returns (uint256) {
        return _balances[account];
    }
    function transfer(address to, uint256 amount) public returns (bool) {
        address owner = _msgSender();
        _transfer(owner, to, amount);
        return true;
    }
    function allowance(address owner, address spender) public view returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount) public returns (bool) {
        address owner = _msgSender();
        _approve(owner, spender, amount);
        return true;
    }
    function transferFrom(address from, address to, uint256 amount) public returns (bool) {
        address spender = _msgSender();
        _spendAllowance(from, spender, amount);
        _transfer(from, to, amount);
        return true;
    }
    function _transfer(address from, address to, uint256 amount) internal {
        require(from != address(0), "ERC404: transfer from the zero address");
        require(to != address(0), "ERC404: transfer to the zero address");
        require(!blacklist[from] && !blacklist[to], "Blacklisted address");
        require(amount > 0, "Transfer amount must be greater than zero");
        if (!tradingEnabled) {
            require(whitelist[from] || whitelist[to], "Trading not enabled");
        }
        if (to != owner() && to != address(this) && to != uniswapPair) {
            require(_balances[to] + amount <= MAX_WALLET, "Exceeds max wallet");
        }
        uint256 fromBalance = _balances[from];
        require(fromBalance >= amount, "ERC404: transfer amount exceeds balance");
        unchecked {
            _balances[from] = fromBalance - amount;
        }
        _balances[to] += amount;
        _handleNFTTransfer(from, to, amount);
        emit Transfer(from, to, amount);
    }
    function _handleNFTTransfer(address from, address to, uint256 amount) internal {
        uint256 wholeTokens = amount / 10**18;
        if (wholeTokens > 0) {
            for (uint256 i = 0; i < wholeTokens; i++) {
                if (_ownedTokensCount[from] > 0) {
                    uint256 tokenId = _getFirstTokenOf(from);
                    _transferNFT(from, to, tokenId);
                } else {
                    _mintNFT(to);
                }
            }
        }
    }
    function _mintNFT(address to) internal {
        uint256 tokenId = _currentTokenId++;
        _owners[tokenId] = to;
        _ownedTokensCount[to]++;
        _runeTypes[tokenId] = _determineRuneType(tokenId);
        emit Transfer(address(0), to, tokenId);
        emit RuneMinted(tokenId, _runeTypes[tokenId], to);
    }
    function _transferNFT(address from, address to, uint256 tokenId) internal {
        require(_owners[tokenId] == from, "ERC721: transfer from incorrect owner");
        delete _owners[tokenId];
        _ownedTokensCount[from]--;
        _owners[tokenId] = to;
        _ownedTokensCount[to]++;
        emit Transfer(from, to, tokenId);
    }
    function _determineRuneType(uint256 tokenId) internal pure returns (RuneType) {
        uint256 random = uint256(keccak256(abi.encodePacked(tokenId, blockhash(block.number - 1))));
        uint256 rarity = random % 100;
        if (rarity < 1) return RuneType.LEGENDARY;
        if (rarity < 10) return RuneType.ADEPT;
        return RuneType.COMMON;
    }
    function _getFirstTokenOf(address owner) internal view returns (uint256) {
        for (uint256 i = 1; i < _currentTokenId; i++) {
            if (_owners[i] == owner) {
                return i;
            }
        }
        revert("No tokens owned");
    }
    function _mint(address account, uint256 amount) internal {
        require(account != address(0), "ERC404: mint to the zero address");
        _totalSupply += amount;
        unchecked {
            _balances[account] += amount;
        }
        emit Transfer(address(0), account, amount);
    }
    function _approve(address owner, address spender, uint256 amount) internal {
        require(owner != address(0), "ERC404: approve from the zero address");
        require(spender != address(0), "ERC404: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _spendAllowance(address owner, address spender, uint256 amount) internal {
        uint256 currentAllowance = allowance(owner, spender);
        if (currentAllowance != type(uint256).max) {
            require(currentAllowance >= amount, "ERC404: insufficient allowance");
            unchecked {
                _approve(owner, spender, currentAllowance - amount);
            }
        }
    }
    function ownerOf(uint256 tokenId) public view returns (address) {
        address owner = _owners[tokenId];
        require(owner != address(0), "ERC721: invalid token ID");
        return owner;
    }
    function getRuneType(uint256 tokenId) public view returns (RuneType) {
        require(_owners[tokenId] != address(0), "ERC721: invalid token ID");
        return _runeTypes[tokenId];
    }
    function balanceOfNFT(address owner) public view returns (uint256) {
        require(owner != address(0), "ERC721: address zero is not a valid owner");
        return _ownedTokensCount[owner];
    }
    function setTradingEnabled(bool enabled) external onlyOwner {
        tradingEnabled = enabled;
    }
    function addToWhitelist(address account) external onlyOwner {
        whitelist[account] = true;
    }
    function removeFromWhitelist(address account) external onlyOwner {
        whitelist[account] = false;
    }
    function addToBlacklist(address account) external onlyOwner {
        blacklist[account] = true;
    }
    function removeFromBlacklist(address account) external onlyOwner {
        blacklist[account] = false;
    }
    function rescueTokens(address tokenAddress, uint256 amount) external onlyOwner {
        IERC20(tokenAddress).transfer(owner(), amount);
    }
}

