        // Owner is set by Ownable constructor
    }

    function startOwnershipTransfer(address newOwner) external onlyOwner {
        require(newOwner != address(0), "invalid address");
        require(newOwner != owner(), "same as current owner");

        pendingOwner = newOwner;
        pendingOwnerDeadline = block.timestamp + OWNERSHIP_TRANSFER_DELAY;

        emit OwnershipTransferStarted(newOwner, pendingOwnerDeadline);
    }

    function acceptOwnership() external onlyOwnerOrPendingOwner {
        require(msg.sender == pendingOwner, "not pending owner");
        require(block.timestamp >= pendingOwnerDeadline, "transfer delay not met");

        address previousOwner = owner();
        transferOwnership(pendingOwner);
        pendingOwner = address(0);
        pendingOwnerDeadline = 0;

        emit OwnershipTransferred(previousOwner, pendingOwner);
    }

    function cancelOwnershipTransfer() external onlyOwner {
        require(pendingOwner != address(0), "no pending transfer");

        pendingOwner = address(0);
        pendingOwnerDeadline = 0;
    }
