pragma solidity ^0.8.12;
import {IERC20} from '@zerolendxyz/core-v3/contracts/dependencies/openzeppelin/contracts/IERC20.sol';
import {IStreamable} from './interfaces/IStreamable.sol';
import {AdminControlledEcosystemReserve} from './AdminControlledEcosystemReserve.sol';
import {ReentrancyGuard} from './libs/ReentrancyGuard.sol';
import {SafeERC20} from './libs/SafeERC20.sol';
contract AaveEcosystemReserveV2 is AdminControlledEcosystemReserve, ReentrancyGuard, IStreamable {
  using SafeERC20 for IERC20;
  uint256 private _nextStreamId;
  mapping(uint256 => Stream) private _streams;
  modifier onlyAdminOrRecipient(uint256 streamId) {
    require(
      msg.sender == _fundsAdmin || msg.sender == _streams[streamId].recipient,
      'caller is not the funds admin or the recipient of the stream'
    );
    _;
  }
  modifier streamExists(uint256 streamId) {
    require(_streams[streamId].isEntity, 'stream does not exist');
    _;
  }
  function initialize(address fundsAdmin) external initializer {
    _nextStreamId = 100000;
    _setFundsAdmin(fundsAdmin);
  }
  function getNextStreamId() external view returns (uint256) {
    return _nextStreamId;
  }
  function getStream(
    uint256 streamId
  )
    external
    view
    streamExists(streamId)
    returns (
      address sender,
      address recipient,
      uint256 deposit,
      address tokenAddress,
      uint256 startTime,
      uint256 stopTime,
      uint256 remainingBalance,
      uint256 ratePerSecond
    )
  {
    sender = _streams[streamId].sender;
    recipient = _streams[streamId].recipient;
    deposit = _streams[streamId].deposit;
    tokenAddress = _streams[streamId].tokenAddress;
    startTime = _streams[streamId].startTime;
    stopTime = _streams[streamId].stopTime;
    remainingBalance = _streams[streamId].remainingBalance;
    ratePerSecond = _streams[streamId].ratePerSecond;
  }
  function deltaOf(uint256 streamId) public view streamExists(streamId) returns (uint256 delta) {
    Stream memory stream = _streams[streamId];
    if (block.timestamp <= stream.startTime) return 0;
    if (block.timestamp < stream.stopTime) return block.timestamp - stream.startTime;
    return stream.stopTime - stream.startTime;
  }
  struct BalanceOfLocalVars {
    uint256 recipientBalance;
    uint256 withdrawalAmount;
    uint256 senderBalance;
  }
  function balanceOf(
    uint256 streamId,
    address who
  ) public view streamExists(streamId) returns (uint256 balance) {
    Stream memory stream = _streams[streamId];
    BalanceOfLocalVars memory vars;
    uint256 delta = deltaOf(streamId);
    vars.recipientBalance = delta * stream.ratePerSecond;
    if (stream.deposit > stream.remainingBalance) {
      vars.withdrawalAmount = stream.deposit - stream.remainingBalance;
      vars.recipientBalance = vars.recipientBalance - vars.withdrawalAmount;
    }
    if (who == stream.recipient) return vars.recipientBalance;
    if (who == stream.sender) {
      vars.senderBalance = stream.remainingBalance - vars.recipientBalance;
      return vars.senderBalance;
    }
    return 0;
  }
  struct CreateStreamLocalVars {
    uint256 duration;
    uint256 ratePerSecond;
  }
  function createStream(
    address recipient,
    uint256 deposit,
    address tokenAddress,
    uint256 startTime,
    uint256 stopTime
  ) external onlyFundsAdmin returns (uint256) {
    require(recipient != address(0), 'stream to the zero address');
    require(recipient != address(this), 'stream to the contract itself');
    require(recipient != msg.sender, 'stream to the caller');
    require(deposit > 0, 'deposit is zero');
    require(startTime >= block.timestamp, 'start time before block.timestamp');
    require(stopTime > startTime, 'stop time before the start time');
    CreateStreamLocalVars memory vars;
    vars.duration = stopTime - startTime;
    require(deposit >= vars.duration, 'deposit smaller than time delta');
    require(deposit % vars.duration == 0, 'deposit not multiple of time delta');
    vars.ratePerSecond = deposit / vars.duration;
    uint256 streamId = _nextStreamId;
    _streams[streamId] = Stream({
      remainingBalance: deposit,
      deposit: deposit,
      isEntity: true,
      ratePerSecond: vars.ratePerSecond,
      recipient: recipient,
      sender: address(this),
      startTime: startTime,
      stopTime: stopTime,
      tokenAddress: tokenAddress
    });
    _nextStreamId++;
    emit CreateStream(
      streamId,
      address(this),
      recipient,
      deposit,
      tokenAddress,
      startTime,
      stopTime
    );
    return streamId;
  }
  function withdrawFromStream(
    uint256 streamId,
    uint256 amount
  ) external nonReentrant streamExists(streamId) onlyAdminOrRecipient(streamId) returns (bool) {
    require(amount > 0, 'amount is zero');
    Stream memory stream = _streams[streamId];
    uint256 balance = balanceOf(streamId, stream.recipient);
    require(balance >= amount, 'amount exceeds the available balance');
    _streams[streamId].remainingBalance = stream.remainingBalance - amount;
    if (_streams[streamId].remainingBalance == 0) delete _streams[streamId];
    IERC20(stream.tokenAddress).safeTransfer(stream.recipient, amount);
    emit WithdrawFromStream(streamId, stream.recipient, amount);
    return true;
  }
  function cancelStream(
    uint256 streamId
  ) external nonReentrant streamExists(streamId) onlyAdminOrRecipient(streamId) returns (bool) {
    Stream memory stream = _streams[streamId];
    uint256 senderBalance = balanceOf(streamId, stream.sender);
    uint256 recipientBalance = balanceOf(streamId, stream.recipient);
    delete _streams[streamId];
    IERC20 token = IERC20(stream.tokenAddress);
    if (recipientBalance > 0) token.safeTransfer(stream.recipient, recipientBalance);
    emit CancelStream(streamId, stream.sender, stream.recipient, senderBalance, recipientBalance);
    return true;
  }
}

pragma solidity 0.8.10;
import "./interfaces/IAllowlist.1.sol";
import "./libraries/LibAllowlistMasks.sol";
import "./Initializable.sol";
import "./Administrable.sol";
import "./state/allowlist/AllowerAddress.sol";
import "./state/allowlist/Allowlist.sol";
contract AllowlistV1 is IAllowlistV1, Initializable, Administrable {
    function initAllowlistV1(address _admin, address _allower) external init(0) {
        _setAdmin(_admin);
        AllowerAddress.set(_allower);
        emit SetAllower(_allower);
    }
    function getAllower() external view returns (address) {
        return AllowerAddress.get();
    }
    function isAllowed(address _account, uint256 _mask) external view returns (bool) {
        uint256 userPermissions = Allowlist.get(_account);
        if (userPermissions & LibAllowlistMasks.DENY_MASK == LibAllowlistMasks.DENY_MASK) {
            return false;
        }
        return userPermissions & _mask == _mask;
    }
    function isDenied(address _account) external view returns (bool) {
        return Allowlist.get(_account) & LibAllowlistMasks.DENY_MASK == LibAllowlistMasks.DENY_MASK;
    }
    function hasPermission(address _account, uint256 _mask) external view returns (bool) {
        return Allowlist.get(_account) & _mask == _mask;
    }
    function getPermissions(address _account) external view returns (uint256) {
        return Allowlist.get(_account);
    }
    function onlyAllowed(address _account, uint256 _mask) external view {
        uint256 userPermissions = Allowlist.get(_account);
        if (userPermissions & LibAllowlistMasks.DENY_MASK == LibAllowlistMasks.DENY_MASK) {
            revert Denied(_account);
        }
        if (userPermissions & _mask != _mask) {
            revert LibErrors.Unauthorized(_account);
        }
    }
    function setAllower(address _newAllowerAddress) external onlyAdmin {
        AllowerAddress.set(_newAllowerAddress);
        emit SetAllower(_newAllowerAddress);
    }
    function allow(address[] calldata _accounts, uint256[] calldata _permissions) external {
        if (msg.sender != AllowerAddress.get() && msg.sender != _getAdmin()) {
            revert LibErrors.Unauthorized(msg.sender);
        }
        if (_accounts.length == 0) {
            revert InvalidAlloweeCount();
        }
        if (_accounts.length != _permissions.length) {
            revert MismatchedAlloweeAndStatusCount();
        }
        for (uint256 i = 0; i < _accounts.length;) {
            LibSanitize._notZeroAddress(_accounts[i]);
            Allowlist.set(_accounts[i], _permissions[i]);
            unchecked {
                ++i;
            }
        }
        emit SetAllowlistPermissions(_accounts, _permissions);
    }
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
interface IERC721 {
    function ownerOf(uint256 tokenId) external view returns (address);
}
interface IStakingRewards {
    function getStakerLevel(address user) external view returns (uint256);
}
contract DungeonConfig is Ownable, ReentrancyGuard {
    IERC721 public dungeonNFT;
    IStakingRewards public stakingRewards;
    struct DungeonSettings {
        bool isLocked;
        uint256 trialTimeout;
        bool enableRandomization;
        bytes32 passwordHash;
        uint8 gameMode;
        uint256 resetCooldown;
        uint256 lastResetTime;
        uint256 version;
    }
    struct FloorData {
        uint256 floorNumber;
        bytes32 dataHash;
        uint256 timestamp;
        uint256 version;
    }
    mapping(uint256 => DungeonSettings) public dungeonSettings;
    mapping(uint256 => mapping(uint256 => FloorData)) public floorData;
    mapping(uint256 => uint256) public currentFloorVersion;
    mapping(address => bool) public globalAdmins;
    mapping(uint256 => mapping(address => bool)) public tokenAdmins;
    mapping(address => uint256) public userPermissions;
    uint256 public constant PERMISSION_CONFIGURE = 1;
    uint256 public constant PERMISSION_RESET = 2;
    uint256 public constant PERMISSION_MANAGE_FLOORS = 4;
    event DungeonConfigured(uint256 indexed tokenId, address indexed configurator, DungeonSettings settings);
    event FloorDataUpdated(uint256 indexed tokenId, uint256 indexed floorNumber, bytes32 dataHash, uint256 version);
    event DungeonReset(uint256 indexed tokenId, address indexed resetter, uint256 newVersion);
    event PermissionGranted(address indexed user, uint256 permissions);
    event GlobalAdminUpdated(address indexed admin, bool status);
    event TokenAdminUpdated(uint256 indexed tokenId, address indexed admin, bool status);
    modifier onlyDungeonOwnerOrAdmin(uint256 tokenId) {
        require(_isAuthorized(tokenId, msg.sender), "Not authorized");
        _;
    }
    modifier onlyGlobalAdmin() {
        require(globalAdmins[msg.sender] || msg.sender == owner(), "Not global admin");
        _;
    }
    constructor(address _dungeonNFT, address _stakingRewards) {
        dungeonNFT = IERC721(_dungeonNFT);
        stakingRewards = IStakingRewards(_stakingRewards);
        globalAdmins[msg.sender] = true;
    }
    function configureDungeon(uint256 tokenId, bool isLocked, uint256 trialTimeout, bool enableRandomization, bytes32 passwordHash, uint8 gameMode, uint256 resetCooldown) external onlyDungeonOwnerOrAdmin(tokenId) {
        require(_hasPermission(msg.sender, PERMISSION_CONFIGURE), "Insufficient permissions");
        dungeonSettings[tokenId] = DungeonSettings({
            isLocked: isLocked,
            trialTimeout: trialTimeout,
            enableRandomization: enableRandomization,
            passwordHash: passwordHash,
            gameMode: gameMode,
            resetCooldown: resetCooldown,
            lastResetTime: dungeonSettings[tokenId].lastResetTime,
            version: dungeonSettings[tokenId].version
        });
        emit DungeonConfigured(tokenId, msg.sender, dungeonSettings[tokenId]);
    }
    function updateFloorData(uint256 tokenId, uint256 floorNumber, bytes32 dataHash) external onlyDungeonOwnerOrAdmin(tokenId) {
        require(_hasPermission(msg.sender, PERMISSION_MANAGE_FLOORS), "Insufficient permissions");
        uint256 newVersion = currentFloorVersion[tokenId] + 1;
        floorData[tokenId][floorNumber] = FloorData({
            floorNumber: floorNumber,
            dataHash: dataHash,
            timestamp: block.timestamp,
            version: newVersion
        });
        currentFloorVersion[tokenId] = newVersion;
        emit FloorDataUpdated(tokenId, floorNumber, dataHash, newVersion);
    }
    function resetDungeon(uint256 tokenId) external onlyDungeonOwnerOrAdmin(tokenId) nonReentrant {
        require(_hasPermission(msg.sender, PERMISSION_RESET), "Insufficient permissions");
        DungeonSettings storage settings = dungeonSettings[tokenId];
        require(block.timestamp >= settings.lastResetTime + settings.resetCooldown, "Reset cooldown active");
        settings.lastResetTime = block.timestamp;
        settings.version++;
        currentFloorVersion[tokenId]++;
        emit DungeonReset(tokenId, msg.sender, settings.version);
    }
    function setGlobalAdmin(address admin, bool status) external onlyOwner {
        globalAdmins[admin] = status;
        emit GlobalAdminUpdated(admin, status);
    }
    function setTokenAdmin(uint256 tokenId, address admin, bool status) external onlyDungeonOwnerOrAdmin(tokenId) {
        tokenAdmins[tokenId][admin] = status;
        emit TokenAdminUpdated(tokenId, admin, status);
    }
    function grantUserPermissions(address user, uint256 permissions) external onlyGlobalAdmin {
        userPermissions[user] = permissions;
        emit PermissionGranted(user, permissions);
    }
    function getDungeonSettings(uint256 tokenId) external view returns (DungeonSettings memory) {
        return dungeonSettings[tokenId];
    }
    function getFloorData(uint256 tokenId, uint256 floorNumber) external view returns (FloorData memory) {
        return floorData[tokenId][floorNumber];
    }
    function verifyPassword(uint256 tokenId, string memory password) external view returns (bool) {
        return dungeonSettings[tokenId].passwordHash == keccak256(abi.encodePacked(password));
    }
    function _isAuthorized(uint256 tokenId, address user) internal view returns (bool) {
        return dungeonNFT.ownerOf(tokenId) == user || 
               tokenAdmins[tokenId][user] || 
               globalAdmins[user] || 
               user == owner() ||
               _hasStakingPermission(user);
    }
    function _hasPermission(address user, uint256 requiredPermission) internal view returns (bool) {
        return (userPermissions[user] & requiredPermission) == requiredPermission || 
               globalAdmins[user] || 
               user == owner();
    }
    function _hasStakingPermission(address user) internal view returns (bool) {
        if (address(stakingRewards) == address(0)) return false;
        return stakingRewards.getStakerLevel(user) >= 3;
    }
    function getCurrentFloorVersion(uint256 tokenId) external view returns (uint256) {
        return currentFloorVersion[tokenId];
    }
    function canResetDungeon(uint256 tokenId) external view returns (bool) {
        DungeonSettings memory settings = dungeonSettings[tokenId];
        return block.timestamp >= settings.lastResetTime + settings.resetCooldown;
    }
}

