    uint256 public constant VOTING_PERIOD = 7 days;    // Duration of voting
    uint256 public constant GRACE_PERIOD = 14 days;    // Max time to execute after passing
    uint256 public constant MIN_EXECUTION_DELAY = 2 days; // Min delay for execution

    // Tiered quorum requirements (basis points)
    mapping(ActionType => uint256) public minQuorumBP; 

    // Voting power threshold for proposal creation
