    // Signers with voting rights
    mapping(address => Signer) public signers;
    address[] public signerList;

    // Proposals
    Proposal[] public proposals;

    // Time lock for execution
    mapping(bytes32 => uint256) public timeLocks;

    // Sunset mechanism
    uint256 public sunsetTimestamp;
    address public timelockAdmin;

    // --- Events ---

    event ProposalCreated(
        uint256 indexed proposalId,
        address indexed creator,
        string description,
        Action[] actions
    );
    event VoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        bool support,
        uint256 votes
    );
    event ProposalExecuted(uint256 indexed proposalId);
    event ProposalQueued(
        uint256 indexed proposalId,
        bytes32 indexed queueId,
        uint256 eta
    );
    event SignerAdded(address indexed signer, uint256 votingPower);
    event SignerRemoved(address indexed signer);
    event CreationThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);
    event QuorumUpdated(ActionType indexed actionType, uint256 oldQuorum, uint256 newQuorum);
    event SunsetActivated(uint256 timestamp);
    event AdminTransferred(address oldAdmin, address newAdmin);

    // --- Modifiers ---

    modifier onlySigner() {
        require(signers[msg.sender].exists, "Governance: not a signer");
        _;
    }

    modifier onlyTimelockAdmin() {
        require(msg.sender == timelockAdmin || msg.sender == owner(), "Governance: not admin");
        _;
    }

    modifier notSunset() {
        if (sunsetTimestamp != 0) {
            require(block.timestamp < sunsetTimestamp, "Governance: sunset activated");
        }
        _;
    }

    // --- Constructor ---

    constructor(address _votingToken, address[] memory initialSigners, uint256[] memory votingPowers) {
        require(initialSigners.length == votingPowers.length, "Governance: arrays length mismatch");
        require(initialSigners.length >= 3, "Governance: at least 3 signers required");

        votingToken = IERC20(_votingToken);
        timelockAdmin = msg.sender;

        // Initialize quorum requirements (e.g., 5%, 10%, 20% of total supply)
        minQuorumBP[ActionType.LOW] = 500;   // 5%
        minQuorumBP[ActionType.MEDIUM] = 1000; // 10%
        minQuorumBP[ActionType.HIGH] = 2000;  // 20%

        creationThreshold = 10000 * 10**18; // Example: 10k tokens

        for (uint256 i = 0; i < initialSigners.length; i++) {
            require(initialSigners[i] != address(0), "Governance: zero address");
            require(votingPowers[i] > 0, "Governance: zero voting power");
            signers[initialSigners[i]] = Signer(true, votingPowers[i]);
            signerList.push(initialSigners[i]);
            emit SignerAdded(initialSigners[i], votingPowers[i]);
        }
    }

    // --- External Functions ---

    /**
     * @dev Create a new proposal
     */
    function createProposal(
        string calldata description,
        address[] calldata targets,
        uint256[] calldata values,
        bytes[] calldata datas,
        ActionType[] calldata actionTypes
    ) external onlySigner notSunset nonReentrant returns (uint256) {
        require(targets.length > 0, "Governance: empty actions");
        require(targets.length == values.length && targets.length == datas.length && targets.length == actionTypes.length, "Governance: arrays length mismatch");

        // Check voting power for creation
        require(signers[msg.sender].votingPower >= creationThreshold, "Governance: insufficient voting power to create proposal");

        Action[] memory actions = new Action[](targets.length);
        for (uint256 i = 0; i < targets.length; i++) {
            actions[i] = Action({
                target: targets[i],
                value: values[i],
                data: datas[i],
                actionType: actionTypes[i]
            });
        }

        uint256 votingDeadline = block.timestamp.add(VOTING_DELAY).add(VOTING_PERIOD);
        uint256 executionDeadline = votingDeadline.add(GRACE_PERIOD);

        proposals.push(Proposal({
            description: description,
            actions: actions,
            creationTime: block.timestamp,
            votingDeadline: votingDeadline,
            executionDeadline: executionDeadline,
            yesVotes: 0,
            noVotes: 0,
            executed: false
        }));

        uint256 proposalId = proposals.length - 1;
        emit ProposalCreated(proposalId, msg.sender, description, actions);
        return proposalId;
    }

    /**
     * @dev Cast a vote on a proposal
     */
    function castVote(uint256 proposalId, bool support) external onlySigner notSunset nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(block.timestamp >= proposal.creationTime.add(VOTING_DELAY), "Governance: voting not started");
        require(block.timestamp <= proposal.votingDeadline, "Governance: voting closed");
        require(!proposal.hasVoted[msg.sender], "Governance: already voted");
        require(!proposal.executed, "Governance: proposal already executed");

        uint256 votingPower = signers[msg.sender].votingPower;
        if (support) {
            proposal.yesVotes = proposal.yesVotes.add(votingPower);
        } else {
            proposal.noVotes = proposal.noVotes.add(votingPower);
        }

        proposal.hasVoted[msg.sender] = true;

        emit VoteCast(proposalId, msg.sender, support, votingPower);
    }

    /**
     * @dev Queue a successful proposal for execution after the minimum delay
     */
    function queue(uint256 proposalId) external notSunset nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(block.timestamp > proposal.votingDeadline, "Governance: still in voting period");
        require(!proposal.executed, "Governance: proposal already executed");
        require(isProposalPassed(proposalId), "Governance: proposal not passed");

        bytes32 queueId = getQueueId(proposalId);
        require(timeLocks[queueId] == 0, "Governance: already queued");

        uint256 eta = block.timestamp.add(MIN_EXECUTION_DELAY);
        timeLocks[queueId] = eta;

        emit ProposalQueued(proposalId, queueId, eta);
    }

    /**
     * @dev Execute a queued proposal
     */
    function execute(uint256 proposalId) external payable notSunset nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(!proposal.executed, "Governance: already executed");
        require(isProposalPassed(proposalId), "Governance: proposal not passed");

        bytes32 queueId = getQueueId(proposalId);
        require(timeLocks[queueId] != 0, "Governance: not queued");
        require(block.timestamp >= timeLocks[queueId], "Governance: not yet eligible");
        require(block.timestamp <= proposal.executionDeadline, "Governance: execution deadline passed");

        proposal.executed = true;

        for (uint256 i = 0; i < proposal.actions.length; i++) {
            _executeAction(
                proposal.actions[i].target,
                proposal.actions[i].value,
                proposal.actions[i].data
            );
        }

        delete timeLocks[queueId];
        emit ProposalExecuted(proposalId);
    }

    // --- Public & View Functions ---

    function getQueueId(uint256 proposalId) public pure returns (bytes32) {
        return keccak256(abi.encode("PROPOSAL_QUEUED", proposalId));
    }

    function getProposalCount() external view returns (uint256) {
        return proposals.length;
    }

    function getState(uint256 proposalId) external view returns (string memory) {
        Proposal storage proposal = proposals[proposalId];
        if (block.timestamp <= proposal.creationTime.add(VOTING_DELAY)) return "Pending";
        if (block.timestamp <= proposal.votingDeadline) return "Active";
        if (!isProposalPassed(proposalId)) return "Defeated";
        if (!proposal.executed) {
            bytes32 queueId = getQueueId(proposalId);
            if (timeLocks[queueId] == 0) return "Succeeded";
            if (block.timestamp < timeLocks[queueId]) return "Queued";
            return "Eligible";
        }
        return "Executed";
    }

    function isProposalPassed(uint256 proposalId) public view returns (bool) {
        Proposal storage proposal = proposals[proposalId];
        if (block.timestamp <= proposal.votingDeadline) return false;
        if (proposal.executed) return true;

        // Determine highest severity action type
        ActionType highestSeverity = ActionType.LOW;
        for (uint256 i = 0; i < proposal.actions.length; i++) {
            if (uint256(proposal.actions[i].actionType) > uint256(highestSeverity)) {
                highestSeverity = proposal.actions[i].actionType;
            }
        }

        uint256 totalVotingPower = getTotalVotingPower();
        uint256 quorumRequired = totalVotingPower.mul(minQuorumBP[highestSeverity]).div(10000);

        return proposal.yesVotes > proposal.noVotes && proposal.yesVotes >= quorumRequired;
    }

    function getTotalVotingPower() public view returns (uint256) {
        uint256 total = 0;
        for (uint256 i = 0; i < signerList.length; i++) {
            total = total.add(signers[signerList[i]].votingPower);
        }
        return total;
    }

    // --- Owner / Admin Functions ---

    /**
     * @dev Add a new signer
     */
    function addSigner(address signer, uint256 votingPower) external onlyOwner notSunset {
        require(signer != address(0), "Governance: zero address");
        require(votingPower > 0, "Governance: zero voting power");
        require(!signers[signer].exists, "Governance: already exists");

        signers[signer] = Signer(true, votingPower);
        signerList.push(signer);
        emit SignerAdded(signer, votingPower);
    }

    /**
     * @dev Remove an existing signer
     */
    function removeSigner(address signer) external onlyOwner notSunset {
        require(signers[signer].exists, "Governance: not a signer");
        signers[signer].exists = false;
        emit SignerRemoved(signer);
    }

    /**
     * @dev Update the creation threshold
     */
    function updateCreationThreshold(uint256 newThreshold) external onlyOwner notSunset {
        uint256 oldThreshold = creationThreshold;
        creationThreshold = newThreshold;
        emit CreationThresholdUpdated(oldThreshold, newThreshold);
    }

    /**
     * @dev Update quorum requirement for an action type
     */
    function updateQuorum(ActionType actionType, uint256 newQuorumBP) external onlyOwner notSunset {
        require(newQuorumBP <= 10000, "Governance: invalid basis points");
        uint256 oldQuorum = minQuorumBP[actionType];
        minQuorumBP[actionType] = newQuorumBP;
        emit QuorumUpdated(actionType, oldQuorum, newQuorumBP);
    }

    /**
     * @dev Activate the sunset mechanism
     */
    function activateSunset(uint256 durationDays) external onlyOwner {
        require(sunsetTimestamp == 0, "Governance: sunset already set");
        sunsetTimestamp = block.timestamp.add(durationDays * 1 days);
        emit SunsetActivated(sunsetTimestamp);
    }

    /**
     * @dev Transfer timelock admin role
     */
    function transferAdmin(address newAdmin) external onlyTimelockAdmin notSunset {
        require(newAdmin != address(0), "Governance: zero address");
        address oldAdmin = timelockAdmin;
        timelockAdmin = newAdmin;
        emit AdminTransferred(oldAdmin, newAdmin);
    }

    // --- Internal Functions ---

    function _executeAction(address target, uint256 value, bytes memory data) internal {
        (bool success, bytes memory returndata) = target.call{value: value}(data);
        require(success, string(returndata));
    }
    // --- Fallback ---
    receive() external payable {}
}

