}

contract VeYFIVestingEscrow {
 address public owner;
 address public recipient;
 address public token;
 address public operator;
 uint256 public vestingStart;
 uint256 public vestingDuration;
 uint256 public cliffDuration;
 uint256 public totalAmount;
 uint256 public claimedAmount;
 bool public revoked;
 bool public revocable;
 bytes4 private constant EIP1271_MAGIC_VALUE = 0x1626ba7e;
 event TokensClaimed(address indexed recipient, uint256 amount);
 event VestingRevoked(address indexed owner, uint256 unvestedAmount);
 event OperatorUpdated(address indexed newOperator);
 modifier onlyOwner() {
 require(msg.sender == owner, "Not owner");
 _;
 }
 modifier onlyOperator() {
 require(msg.sender == operator, "Not operator");
 _;
 }
 constructor(
 address _recipient,
 address _token,
 uint256 _vestingDuration,
 uint256 _cliffDuration,
 uint256 _totalAmount,
 bool _revocable
 ) {
 owner = msg.sender;
 recipient = _recipient;
 token = _token;
 operator = msg.sender;
 vestingStart = block.timestamp;
 vestingDuration = _vestingDuration;
 cliffDuration = _cliffDuration;
 totalAmount = _totalAmount;
 revocable = _revocable;
 }
 function claim() external {
 require(msg.sender == recipient || msg.sender == operator, "Not authorized");
 uint256 claimable = getClaimableAmount();
 require(claimable > 0, "No tokens to claim");
 claimedAmount += claimable;
 IERC20(token).transfer(recipient, claimable);
 emit TokensClaimed(recipient, claimable);
 }
 function claimWithSignature(bytes memory signature) external {
 bytes32 hash = keccak256(abi.encodePacked("claim", block.chainid, address(this)));
 require(_isValidSignature(recipient, hash, signature), "Invalid signature");
 uint256 claimable = getClaimableAmount();
 require(claimable > 0, "No tokens to claim");
 claimedAmount += claimable;
 IERC20(token).transfer(recipient, claimable);
 emit TokensClaimed(recipient, claimable);
 }
 function revoke() external onlyOwner {
 require(revocable, "Not revocable");
 require(!revoked, "Already revoked");
 revoked = true;
 uint256 unvested = totalAmount - getVestedAmount();
 if (unvested > 0) {
 IERC20(token).transfer(owner, unvested);
 }
 emit VestingRevoked(owner, unvested);
 }
 function setOperator(address newOperator) external onlyOwner {
 operator = newOperator;
 emit OperatorUpdated(newOperator);
 }
 function getClaimableAmount() public view returns (uint256) {
 return getVestedAmount() - claimedAmount;
 }
 function getVestedAmount() public view returns (uint256) {
 if (block.timestamp < vestingStart + cliffDuration) {
 return 0;
 }
 if (block.timestamp >= vestingStart + vestingDuration || revoked) {
 return totalAmount;
 }
 return (totalAmount * (block.timestamp - vestingStart)) / vestingDuration;
 }
 function _isValidSignature(address signer, bytes32 hash, bytes memory signature) internal view returns (bool) {
 (uint8 v, bytes32 r, bytes32 s) = abi.decode(signature, (uint8, bytes32, bytes32));
 address recovered = ecrecover(hash, v, r, s);
 if (recovered == signer) {
 return true;
 }
 if (signer.code.length > 0) {
 try IERC1271(signer).isValidSignature(hash, signature) returns (bytes4 magicValue) {
 return magicValue == EIP1271_MAGIC_VALUE;
 } catch {
 return false;
 }
 }
 return false;
 }
}

