contract MemeToken is ERC20, Ownable {
    using SafeERC20 for IERC20;
    IUniswapV2Router02 public uniswapRouter;
    address public uniswapPair;
    address public marketingWallet;
    address public liquidityWallet;
    uint256 public buyTax = 500;
    uint256 public sellTax = 700;
    uint256 public liquidityTax = 200;
    uint256 public marketingTax = 300;
    uint256 public maxTxAmount;
    uint256 public swapThreshold;
    uint256 private constant TAX_DENOMINATOR = 10000;
    bool public tradingEnabled = false;
    bool private inSwap;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isExcludedFromMaxTx;
    mapping(address => bool) public blockedSellers;
    event TradingEnabled(bool enabled);
    event TaxesUpdated(uint256 buyTax, uint256 sellTax, uint256 liquidityTax, uint256 marketingTax);
    event MarketingWalletUpdated(address newWallet);
    event LiquidityAdded(uint256 tokenAmount, uint256 ethAmount, uint256 liquidity);
    event TokensSwappedForETH(uint256 tokenAmount, uint256 ethAmount);
    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor(string memory name, string memory symbol, uint256 totalSupply, address router, address marketing, address liquidity) ERC20(name, symbol) {
        marketingWallet = marketing;
        liquidityWallet = liquidity;
        uniswapRouter = IUniswapV2Router02(router);
        uniswapPair = IUniswapV2Factory(uniswapRouter.factory()).createPair(address(this), uniswapRouter.WETH());
        maxTxAmount = totalSupply * 10**decimals() / 100;
        swapThreshold = totalSupply * 10**decimals() / 1000;
        _mint(msg.sender, totalSupply * 10**decimals());
        isExcludedFromFee[msg.sender] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromFee[marketingWallet] = true;
        isExcludedFromFee[liquidityWallet] = true;
        isExcludedFromMaxTx[msg.sender] = true;
        isExcludedFromMaxTx[address(this)] = true;
        isExcludedFromMaxTx[marketingWallet] = true;
        isExcludedFromMaxTx[liquidityWallet] = true;
    }
    function _transfer(address from, address to, uint256 amount) internal override {
        require(from != address(0), "Transfer from zero address");
        require(to != address(0), "Transfer to zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        if (!isExcludedFromMaxTx[from] && !isExcludedFromMaxTx[to]) {
            require(amount <= maxTxAmount, "Exceeds max transaction amount");
        }
        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading not enabled");
        }
        if (to == uniswapPair && blockedSellers[from]) {
            revert("Address blocked from selling");
        }
        uint256 taxAmount = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to] && !inSwap) {
            if (from == uniswapPair) {
                taxAmount = amount * buyTax / TAX_DENOMINATOR;
            } else if (to == uniswapPair) {
                taxAmount = amount * sellTax / TAX_DENOMINATOR;
                _swapAndLiquify();
            }
            if (taxAmount > 0) {
                super._transfer(from, address(this), taxAmount);
                amount -= taxAmount;
            }
        }
        super._transfer(from, to, amount);
    }
    function _swapAndLiquify() private lockTheSwap {
        uint256 contractTokenBalance = balanceOf(address(this));
        if (contractTokenBalance >= swapThreshold) {
            uint256 totalTax = liquidityTax + marketingTax;
            uint256 liquidityTokens = contractTokenBalance * liquidityTax / totalTax / 2;
            uint256 marketingTokens = contractTokenBalance - liquidityTokens;
            uint256 initialBalance = address(this).balance;
            _swapTokensForEth(marketingTokens);
            uint256 newBalance = address(this).balance - initialBalance;
            uint256 marketingETH = newBalance * marketingTax / totalTax;
            uint256 liquidityETH = newBalance - marketingETH;
            if (marketingETH > 0) {
                payable(marketingWallet).transfer(marketingETH);
            }
            if (liquidityTokens > 0 && liquidityETH > 0) {
                _addLiquidity(liquidityTokens, liquidityETH);
            }
        }
    }
    function _swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapRouter.WETH();
        _approve(address(this), address(uniswapRouter), tokenAmount);
        uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount,0,path,address(this),block.timestamp);
        emit TokensSwappedForETH(tokenAmount, address(this).balance);
    }
    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        _approve(address(this), address(uniswapRouter), tokenAmount);
        uniswapRouter.addLiquidityETH{value: ethAmount}(address(this),tokenAmount,0,0,liquidityWallet,block.timestamp);
        emit LiquidityAdded(tokenAmount, ethAmount, 0);
    }
    function enableTrading() external onlyOwner {
        tradingEnabled = true;
        emit TradingEnabled(true);
    }
    function setTaxes(uint256 _buyTax, uint256 _sellTax, uint256 _liquidityTax, uint256 _marketingTax) external onlyOwner {
        require(_buyTax <= 1000, "Buy tax too high");
        require(_sellTax <= 1000, "Sell tax too high");
        require(_liquidityTax + _marketingTax <= _buyTax && _liquidityTax + _marketingTax <= _sellTax, "Tax distribution invalid");
        buyTax = _buyTax;
        sellTax = _sellTax;
        liquidityTax = _liquidityTax;
        marketingTax = _marketingTax;
        emit TaxesUpdated(_buyTax, _sellTax, _liquidityTax, _marketingTax);
    }
    function setWallets(address _marketingWallet, address _liquidityWallet) external onlyOwner {
        require(_marketingWallet != address(0), "Invalid marketing wallet");
        require(_liquidityWallet != address(0), "Invalid liquidity wallet");
        marketingWallet = _marketingWallet;
        liquidityWallet = _liquidityWallet;
        emit MarketingWalletUpdated(_marketingWallet);
    }
    function setMaxTxAmount(uint256 _maxTxAmount) external onlyOwner {
        maxTxAmount = _maxTxAmount;
    }
    function setSwapThreshold(uint256 _swapThreshold) external onlyOwner {
        swapThreshold = _swapThreshold;
    }
    function excludeFromFee(address account, bool excluded) external onlyOwner {
        isExcludedFromFee[account] = excluded;
    }
    function excludeFromMaxTx(address account, bool excluded) external onlyOwner {
        isExcludedFromMaxTx[account] = excluded;
    }
    function blockSeller(address account, bool blocked) external onlyOwner {
        blockedSellers[account] = blocked;
    }
    function manualSwap(uint256 tokenAmount) external onlyOwner {
        _swapTokensForEth(tokenAmount);
    }
    function manualLiquidity(uint256 tokenAmount, uint256 ethAmount) external onlyOwner {
        _addLiquidity(tokenAmount, ethAmount);
    }
    function rescueTokens(address token, uint256 amount) external onlyOwner {
        IERC20(token).safeTransfer(owner(), amount);
    }
    receive() external payable {}
}

