        string memory _name,
        string memory _symbol,
        string memory _uri,
        string memory _extension,
        uint256 _maxSupply,
        address _router
    )
        ERC721(_name, _symbol)
        Ownable(msg.sender)
    {
        maxSupply = _maxSupply;
        baseURI = _uri;
        uriExtension = _extension;
        router = _router;
    }
