        IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(routerAddress);
        // Create a uniswap pair for this token
        address _uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory())
            .createPair(address(this), _uniswapV2Router.WETH());

        uniswapV2Router = _uniswapV2Router;
        uniswapV2Pair = _uniswapV2Pair;
        automatedMarketMakerPairs[_uniswapV2Pair] = true;

        // Exclude owner and this contract from fee
        isExcludedFromFees[owner()] = true;
        isExcludedFromFees[address(this)] = true;

        // Set initial limits
        uint256 totalSupply = 100_000_000 * 10**18; // 100 million tokens
        maxTxAmount = totalSupply / 200; // 0.5%
        maxWalletBalance = totalSupply / 100; // 1%
        swapTokensAtAmount = totalSupply / 2000; // 0.05%
        maxSwapSize = totalSupply / 500; // 0.2%

        // Mint total supply to owner
        _mint(owner(), totalSupply);
    }

    // --- External Functions ---

    /**
     * @dev Standard transfer with fees, limits, and swap logic.
     */
    function _transfer(
        address from,
        address to,
        uint256 amount
    ) internal override {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        require(!isBlacklisted[from] && !isBlacklisted[to], "ALT: Blacklisted address");

        // Check transaction limit
        if (amount > maxTxAmount) {
            revert("ALT: Exceeds max transaction amount");
        }

        // Check wallet limit (except for swaps and removes)
        if (to != uniswapV2Pair && automatedMarketMakerPairs[to]) {
            uint256 currentBalance = balanceOf(to);
            if (currentBalance.add(amount) > maxWalletBalance) {
                revert("ALT: Exceeds max wallet balance");
            }
        }

        uint256 contractTokenBalance = balanceOf(address(this));
        bool canSwap = contractTokenBalance >= swapTokensAtAmount;

        if (!swapping && canSwap && !automatedMarketMakerPairs[from] && from != owner() && to != owner()) {
            swapping = true;

            uint256 swapAmount = contractTokenBalance;
            if (swapAmount > maxSwapSize) {
                swapAmount = maxSwapSize;
            }

            _swapAndLiquify(swapAmount);

            swapping = false;
        }

        bool takeFee = !swapping && !isExcludedFromFees[from] && !isExcludedFromFees[to];

        if (takeFee) {
            uint256 fees = 0;
            uint256 liquidityShare = 0;

            if (automatedMarketMakerPairs[to]) {
                // SELL
                fees = amount.mul(totalSellFee).div(10000);
                liquidityShare = amount.mul(sellLiquidityFee).div(10000);
            } else if (automatedMarketMakerPairs[from]) {
                // BUY
                fees = amount.mul(totalBuyFee).div(10000);
                liquidityShare = amount.mul(buyLiquidityFee).div(10000);
            }

            if (fees > 0) {
                super._transfer(from, address(this), fees);
                amount = amount.sub(fees);

                // Forward non-liquidity fees
                uint256 marketingAndDevShare = fees.sub(liquidityShare);
                if (marketingAndDevShare > 0) {
                    super._transfer(address(this), feeWallet, marketingAndDevShare);
                }
            }
        }

        super._transfer(from, to, amount);
    }

    // --- Internal Functions ---

    function _swapAndLiquify(uint256 contractTokenBalance) private lockTheSwap {
        // Split contract balance into halves
        uint256 half = contractTokenBalance.div(2);
        uint256 otherHalf = contractTokenBalance.sub(half);

        // Capture the contract's current ETH balance
        uint256 initialBalance = address(this).balance;

        // Swap half of tokens for ETH
        _swapTokensForEth(half); 

        // How much ETH did we just swap into?
        uint256 newBalance = address(this).balance.sub(initialBalance);

        // Add liquidity to Uniswap
        _addLiquidity(otherHalf, newBalance);

        emit SwapAndLiquify(half, newBalance, otherHalf);
    }

    function _swapTokensForEth(uint256 tokenAmount) private {
        // Generate the uniswap pair path of token -> WETH
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);

        // Make the swap
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0, // Accept any amount of ETH
            path,
            address(this),
            block.timestamp
        );
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        // Approve token transfer to uniswap router
        _approve(address(this), address(uniswapV2Router), tokenAmount);

        // Add the liquidity
        (, uint256 ethFromLiquidity, uint256 tokensFromLiquidity) = uniswapV2Router.addLiquidityETH{value: ethAmount}(
            address(this),
            tokenAmount,
            0, // Slippage is unavoidable
            0, // Slippage is unavoidable
            address(this),
            block.timestamp
        );

        // Burn a portion of the LP tokens if enabled
        if (liquidityBurnEnabled && block.timestamp >= nextLiquidityBurnDeadline) {
            uint256 lpTokensToBurn = IERC20(uniswapV2Pair).balanceOf(address(this)).mul(liquidityBurnRate).div(10000);
            if (lpTokensToBurn > 0) {
                IERC20(uniswapV2Pair).transfer(address(0), lpTokensToBurn); // Burn by sending to 0x
                nextLiquidityBurnDeadline = block.timestamp + liquidityBurnCooldown;
                emit BurnedLiquidity(lpTokensToBurn);
            }
        }
    }

    // --- Owner Functions ---

    /**
     * @dev Sets the wallet to receive non-liquidity fees.
     */
    function setFeeWallet(address newWallet) external onlyOwner {
        require(newWallet != address(0), "ALT: zero address");
        emit FeeWalletUpdated(feeWallet, newWallet);
        feeWallet = newWallet;
    }

    /**
     * @dev Updates buy fee structure.
     */
    function setBuyFees(uint256 newLiquidityFee, uint256 newTotalFee) external onlyOwner {
        require(newLiquidityFee <= 1000 && newTotalFee <= 2000, "ALT: fee too high"); // Max 10% total
        emit BuyFeesUpdated(buyLiquidityFee, totalBuyFee, newLiquidityFee, newTotalFee);
        buyLiquidityFee = newLiquidityFee;
        totalBuyFee = newTotalFee;
    }

    /**
     * @dev Updates sell fee structure.
     */
    function setSellFees(uint256 newLiquidityFee, uint256 newTotalFee) external onlyOwner {
        require(newLiquidityFee <= 1000 && newTotalFee <= 2000, "ALT: fee too high"); // Max 10% total
        emit SellFeesUpdated(sellLiquidityFee, totalSellFee, newLiquidityFee, newTotalFee);
        sellLiquidityFee = newLiquidityFee;
        totalSellFee = newTotalFee;
    }

    /**
     * @dev Sets the threshold for triggering swap and add liquidity.
     */
    function setSwapTokensAtAmount(uint256 amount) external onlyOwner {
        require(amount > 0, "ALT: zero amount");
        emit SwapTokensAtAmountUpdated(swapTokensAtAmount, amount);
        swapTokensAtAmount = amount;
    }

    /**
     * @dev Updates max transaction amount.
     */
    function setMaxTxAmount(uint256 amount) external onlyOwner {
        require(amount > 0, "ALT: zero amount");
        emit MaxTxAmountUpdated(maxTxAmount, amount);
        maxTxAmount = amount;
    }

    /**
     * @dev Updates max wallet balance.
     */
    function setMaxWalletBalance(uint256 amount) external onlyOwner {
        require(amount > 0, "ALT: zero amount");
        emit MaxWalletBalanceUpdated(maxWalletBalance, amount);
        maxWalletBalance = amount;
    }

    /**
     * @dev Toggles fee exclusion for an account.
     */
    function setExcludedFromFees(address account, bool excluded) external onlyOwner {
        require(account != address(0), "ALT: zero address");
        isExcludedFromFees[account] = excluded;
        emit ExcludedFromFees(account, excluded);
    }

    /**
     * @dev Adds or removes an address from the blacklist.
     */
    function setBlacklisted(address account, bool blacklisted) external onlyOwner {
        require(account != address(0), "ALT: zero address");
        isBlacklisted[account] = blacklisted;
        emit Blacklisted(account, blacklisted);
    }

    /**
     * @dev Toggles the liquidity burn mechanism.
     */
    function toggleLiquidityBurn(bool enabled) external onlyOwner {
        liquidityBurnEnabled = enabled;
        emit LiquidityBurnToggled(enabled);
    }

    /**
     * @dev Updates the rate of LP tokens burned.
     */
    function setLiquidityBurnRate(uint256 rate) external onlyOwner {
        require(rate <= 10000, "ALT: invalid rate"); // Max 100%
        emit LiquidityBurnRateUpdated(liquidityBurnRate, rate);
        liquidityBurnRate = rate;
    }

    /**
     * @dev Updates the cooldown between liquidity burns.
     */
    function setLiquidityBurnCooldown(uint256 cooldown) external onlyOwner {
        require(cooldown >= 1 hours, "ALT: too short");
        emit LiquidityBurnCooldownUpdated(liquidityBurnCooldown, cooldown);
        liquidityBurnCooldown = cooldown;
    }

    // --- External Functions ---

    /**
     * @dev Allows owner to rescue ETH stuck in contract.
     */
    function withdrawETH() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    /**
     * @dev Allows owner to rescue ERC20 tokens stuck in contract.
     */
    function rescueERC20(address tokenAddress, uint256 amount) external onlyOwner {
        IERC20(tokenAddress).transfer(owner(), amount);
    }

    // --- Receive ETH ---
    receive() external payable {
        require(msg.sender == address(uniswapV2Router), "ALT: not router");
    }
}

