        uint256 tokenBalance = balanceOf(address(this));
        if (tokenBalance > 0) {
            swapTokensForEth(tokenBalance);
        }
        uint256 ethBalance = address(this).balance;
        if (ethBalance > 0) {
            sendETHToFee(ethBalance);
        }
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/utils/Context.sol";

/**
 * @title VestedToken
 * @dev ERC20 token with built-in vesting schedules.
 * Allows the owner to allocate tokens to beneficiaries with cliff, duration, and periodic releases.
 * Vested tokens are non-transferable until released.
 */
contract VestedToken is ERC20, Ownable {
    using SafeMath for uint256;

    // --- Structs ---
    struct VestingSchedule {
        bool initialized;
        address beneficiary;
        uint256 start; // Start time of the vesting period
        uint256 cliff; // Cliff period in seconds
        uint256 duration; // Duration of the vesting period in seconds
        uint256 period; // Time between releases (e.g., 1 days)
        uint256 amountTotal; // Total amount to be released
        uint256 released; // Amount already released
        bool revocable; // Whether the schedule can be revoked
    }

    // --- State Variables ---
    bytes32[] private vestingSchedulesIds;
    mapping(bytes32 => VestingSchedule) private vestingSchedules;
    mapping(address => uint256) public vestedBalance; // Total amount currently vested for an address
    mapping(address => uint256) public nonVestedBalance; // Balance excluding vested tokens

    uint256 private vestingSchedulesCount;
    uint256 private vestingSchedulesReleased;

    // --- Events ---
    event VestingScheduleCreated(bytes32 indexed scheduleId, address indexed beneficiary, uint256 amount);
    event VestingReleased(bytes32 indexed scheduleId, uint256 amount);
    event VestingRevoked(bytes32 indexed scheduleId, uint256 refundedAmount);
    event TokenVested(address indexed beneficiary, uint256 amount);
    event TokenUnvested(address indexed beneficiary, uint256 amount);

    // --- Constructor ---
    /**
     * @dev Initializes the contract with a name, symbol, and mints total supply to owner.
     * @param name The name of the token.
     * @param symbol The symbol of the token.
     * @param totalSupply The total supply to mint to the owner.
     */
    constructor(string memory name, string memory symbol, uint256 totalSupply) ERC20(name, symbol) {
        _mint(owner(), totalSupply);
    }

    // --- Internal Functions ---

    /**
     * @dev Gets the total number of created vesting schedules.
     */
    function getVestingSchedulesCount() public view returns (uint256) {
        return vestingSchedulesCount;
    }

    /**
     * @dev Gets the total number of released vesting tokens.
     */
    function getVestingSchedulesTotalReleased() public view returns (uint256) {
        return vestingSchedulesReleased;
    }

    /**
     * @dev Returns the vesting schedule identifier for a given beneficiary and index.
     */
    function getVestingScheduleId(address beneficiary, uint256 index) public pure returns (bytes32) {
        return keccak256(abi.encodePacked(beneficiary, index));
    }

    /**
     * @dev Returns the vesting schedule for a given identifier.
     */
    function getVestingSchedule(bytes32 scheduleId) public view returns (VestingSchedule memory) {
        return vestingSchedules[scheduleId];
    }

    /**
     * @dev Returns the amount of tokens that can be released from a vesting schedule.
     */
    function computeReleasableAmount(VestingSchedule memory schedule) public view returns (uint256) {
        uint256 currentTime = block.timestamp;
        if (currentTime < schedule.cliff) {
            return 0;
        }
        if (currentTime >= schedule.start.add(schedule.duration)) {
            return schedule.amountTotal.sub(schedule.released);
        }
        // Compute the number of fully elapsed periods
        uint256 elapsedPeriods = currentTime.sub(schedule.start).div(schedule.period);
        uint256 releasable = schedule.amountTotal.mul(elapsedPeriods).div(schedule.duration.div(schedule.period));
        return releasable.sub(schedule.released);
    }

    // --- Public Functions ---

    /**
     * @dev Creates a new vesting schedule for a beneficiary.
     * Only the owner can call this function.
     * @param _beneficiary The address of the beneficiary.
     * @param _start The start time of the vesting period.
     * @param _cliff The cliff period (seconds after start when vesting begins).
     * @param _duration The total duration of the vesting period.
     * @param _period The time interval between releases (e.g., daily, weekly).
     * @param _amount The total amount of tokens to vest.
     * @param _revocable Whether the schedule is revocable by the owner.
     */
    function createVestingSchedule(
        address _beneficiary,
        uint256 _start,
        uint256 _cliff,
        uint256 _duration,
        uint256 _period,
        uint256 _amount,
        bool _revocable
    ) external onlyOwner {
        require(_beneficiary != address(0), "VestedToken: beneficiary is zero address");
        require(_amount > 0, "VestedToken: amount is 0");
        require(_duration > 0, "VestedToken: duration is 0");
        require(_period > 0, "VestedToken: period is 0");
        require(_duration >= _period, "VestedToken: duration < period");
        require(_start.add(_cliff) >= block.timestamp, "VestedToken: start + cliff in the past");
        require(_start.add(_duration) > _start.add(_cliff), "VestedToken: end <= cliff");

        // Transfer tokens to this contract to fund the vesting
        require(transfer(address(this), _amount), "VestedToken: transfer failed");

        // Create unique ID
        bytes32 scheduleId = getVestingScheduleId(_beneficiary, vestingSchedulesCount);

        VestingSchedule memory newSchedule = VestingSchedule(
            true,
            _beneficiary,
            _start,
            _start + _cliff,
            _start + _duration,
            _period,
            _amount,
            0,
            _revocable
        );

        vestingSchedules[scheduleId] = newSchedule;
        vestingSchedulesIds.push(scheduleId);

        // Update balances
        vestedBalance[_beneficiary] = vestedBalance[_beneficiary].add(_amount);
        nonVestedBalance[address(this)] = nonVestedBalance[address(this)].sub(_amount); // Contract holds tokens

        vestingSchedulesCount++;

        emit VestingScheduleCreated(scheduleId, _beneficiary, _amount);
        emit TokenVested(_beneficiary, _amount);
    }

    /**
     * @dev Releases vested tokens for a specific schedule.
     * Anyone can call this to release tokens for a schedule if releasable.
     * @param scheduleId The ID of the vesting schedule.
     */
    function release(bytes32 scheduleId) external {
        VestingSchedule storage schedule = vestingSchedules[scheduleId];
        require(schedule.initialized, "VestedToken: invalid schedule");
        require(schedule.beneficiary == msg.sender, "VestedToken: not beneficiary");

        uint256 amount = computeReleasableAmount(schedule);
        require(amount > 0, "VestedToken: no tokens to release");

        schedule.released = schedule.released.add(amount);
        vestingSchedulesReleased = vestingSchedulesReleased.add(amount);

        // Update balances
        vestedBalance[schedule.beneficiary] = vestedBalance[schedule.beneficiary].sub(amount);
        nonVestedBalance[schedule.beneficiary] = nonVestedBalance[schedule.beneficiary].add(amount);

        // Transfer tokens to beneficiary
        require(ERC20.transfer(schedule.beneficiary, amount), "VestedToken: transfer failed");

        emit VestingReleased(scheduleId, amount);
    }

    /**
     * @dev Revokes a vesting schedule. Only callable by owner if revocable.
     * @param scheduleId The ID of the vesting schedule.
     */
    function revoke(bytes32 scheduleId) external onlyOwner {
        VestingSchedule storage schedule = vestingSchedules[scheduleId];
        require(schedule.initialized, "VestedToken: invalid schedule");
        require(schedule.revocable, "VestedToken: not revocable");

        uint256 unreleased = schedule.amountTotal.sub(schedule.released);
        uint256 refunded;

        if (unreleased > 0) {
            refunded = unreleased;
            // Transfer unreleased tokens back to owner
            require(ERC20.transfer(owner(), refunded), "VestedToken: transfer to owner failed");

            // Update balances
            vestedBalance[schedule.beneficiary] = vestedBalance[schedule.beneficiary].sub(unreleased);
            nonVestedBalance[owner()] = nonVestedBalance[owner()].add(refunded);
        }

        // Mark as uninitialized
        schedule.initialized = false;

        emit VestingRevoked(scheduleId, refunded);
    }

    // --- Override Transfer Functions ---

    /**
     * @dev Overrides transfer to prevent transfers of vested tokens.
     * Beneficiaries can only transfer non-vested (released) portion.
     */
    function transfer(address recipient, uint256 amount) public override returns (bool) {
        require(amount <= nonVestedBalance[_msgSender()], "VestedToken: amount exceeds non-vested balance");
        return super.transfer(recipient, amount);
    }

    /**
     * @dev Overrides transferFrom to prevent transfers of vested tokens.
     */
    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        require(amount <= nonVestedBalance[sender], "VestedToken: amount exceeds non-vested balance");
        return super.transferFrom(sender, recipient, amount);
    }

    // --- View Functions ---

    /**
     * @dev Returns the total balance of an account, including both vested and non-vested.
     */
    function balanceOf(address account) public view override returns (uint256) {
        return vestedBalance[account].add(nonVestedBalance[account]);
    }

    /**
     * @dev Returns the non-vested (spendable) balance of an account.
     */
    function nonVestedBalanceOf(address account) public view returns (uint256) {
        return nonVestedBalance[account];
    }

    /**
     * @dev Returns the vested (locked) balance of an account.
     */
    function vestedBalanceOf(address account) public view returns (uint256) {
        return vestedBalance[account];
    }

    // --- Owner Functions ---

    /**
     * @dev Withdraws any accidentally sent ERC20 tokens.
     */
    function rescueERC20(address tokenAddress, uint256 amount) external onlyOwner {
        require(tokenAddress != address(this), "VestedToken: cannot rescue own tokens");
        IERC20(tokenAddress).transfer(owner(), amount);
    }
}

pragma solidity ^0.8.20;
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
contract MintableERC20 is ERC20 {
    uint8 immutable private _decimals;
    address public minter;
    address public vault;
    uint256 public mintQuota;
    constructor(address minter_, address vault_, string memory name, string memory symbol, uint8 decimals_) ERC20(name, symbol) {
        minter = minter_;
        vault = vault_;
        _decimals = decimals_;
    }
    function decimals() public view override returns (uint8) {
        return _decimals;
    }
    modifier onlyMinter() {
        require(msg.sender == minter, "Require minter");
        _;
    }
    modifier onlyVault() {
        require(msg.sender == vault, "Require vault");
        _;
    }
    event MinterTransferred(address indexed prevMinter, address indexed newMinter);
    function transferMinter(address newMinter) external onlyMinter {
        address prevMinter = minter;
        minter = newMinter;
        emit MinterTransferred(prevMinter, newMinter);
    }
    event VaultTransferred(address indexed prevVault, address indexed newVault);
    function transferVault(address newVault) external onlyVault {
        address prevVault = vault;
        vault = newVault;
        emit VaultTransferred(prevVault, newVault);
    }
    function updateMintQuota(uint256 delta) onlyVault external {
        mintQuota += delta;
    }
    function mint(address account, uint256 amount) onlyMinter external {
        if (account != vault) {
            mintQuota -= amount;
        }
        _mint(account, amount);
    }
    function burn(address account, uint256 amount) onlyMinter external {
        _burn(account, amount);
    }
}

