pragma solidity 0.8.18;
import { Math } from '@openzeppelin/contracts/utils/math/Math.sol';
import { DepositsState } from '../../interfaces/pool/commons/IPoolState.sol';
import { _priceAt, MAX_FENWICK_INDEX } from '../helpers/PoolHelper.sol';
import { Maths } from './Maths.sol';
library Deposits {
    uint256 internal constant SIZE = 8192;
    error InvalidAmount();
    function unscaledAdd(
        DepositsState storage deposits_,
        uint256 index_,
        uint256 unscaledAddAmount_
    ) internal {
        if (unscaledAddAmount_ == 0) revert InvalidAmount();
        ++index_;




        uint256 value;
        uint256 scaling;
        uint256 newValue;
        while (index_ <= SIZE) {
            value    = deposits_.values[index_];
            scaling  = deposits_.scaling[index_];
            newValue = value + unscaledAddAmount_;


            if (scaling != 0) unscaledAddAmount_ = Maths.wmul(newValue, scaling) - Maths.wmul(value, scaling);
            deposits_.values[index_] = newValue;
            index_ += lsb(index_);
        }
    }
    function findIndexAndSumOfSum(
        DepositsState storage deposits_,
        uint256 targetSum_
    ) internal view returns (uint256 sumIndex_, uint256 sumIndexSum_, uint256 sumIndexScale_) {
        uint256 i  = 4096; 
        uint256 runningScale = Maths.WAD;
        uint256 lowerIndexSum;
        uint256 curIndex;
        uint256 value;
        uint256 scaling;
        uint256 scaledValue;
        while (i > 0) {
            curIndex = sumIndex_ + i;
            value    = deposits_.values[curIndex];
            scaling  = deposits_.scaling[curIndex];
            scaledValue =
                lowerIndexSum +
                (
                    scaling != 0 ? Math.mulDiv(
                        runningScale * scaling,
                        value,
                        1e36
                    ) : Maths.wmul(runningScale, value)
                );
            if (scaledValue  < targetSum_) {
                if (curIndex <= MAX_FENWICK_INDEX) {
                    sumIndex_ = curIndex;
                    lowerIndexSum = scaledValue;
                }
            } else {
                if (scaling != 0) runningScale = Maths.floorWmul(runningScale, scaling);
                sumIndexSum_   = scaledValue;
                sumIndexScale_ = runningScale;
            }
            i = i >> 1;
        }
    }
    function findIndexOfSum(
        DepositsState storage deposits_,
        uint256 sum_
    ) internal view returns (uint256 sumIndex_) {
        (sumIndex_,,) = findIndexAndSumOfSum(deposits_, sum_);
    }
    function lsb(
        uint256 i_
    ) internal pure returns (uint256 lsb_) {
        if (i_ != 0) {
            lsb_ = i_ & ((i_ ^ 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff) + 1);
        }
    }
    function mult(
        DepositsState storage deposits_,
        uint256 index_,
        uint256 factor_
    ) internal {
        ++index_;
        uint256 sum;
        uint256 value;
        uint256 scaling;
        uint256 bit = lsb(index_);




        while (bit <= SIZE) {
            if ((bit & index_) != 0) {
                value   = deposits_.values[index_];
                scaling = deposits_.scaling[index_];
                if (scaling != 0) {

                    uint256 scaledFactor = Maths.wmul(factor_, scaling);
                    sum += Maths.wmul(scaledFactor, value) - Maths.wmul(scaling, value);
                    deposits_.scaling[index_] = scaledFactor;
                } else {
                    sum += Maths.wmul(factor_, value) - value;
                    deposits_.scaling[index_] = factor_;
                }
                index_ -= bit;
            } else {
                uint256 superRangeIndex = index_ + bit;
                value   = (deposits_.values[superRangeIndex] += sum);
                scaling = deposits_.scaling[superRangeIndex];
                if (scaling != 0) sum = Maths.wmul(value, scaling) - Maths.wmul(value - sum, scaling);
            }
            bit = bit << 1;
        }
    }
    function prefixSum(
        DepositsState storage deposits_,
        uint256 sumIndex_
    ) internal view returns (uint256 sum_) {
        ++sumIndex_;
        uint256 runningScale = Maths.WAD; 
        uint256 j            = SIZE;      
        uint256 index        = 0;         
        uint256 indexLSB = lsb(sumIndex_);
        uint256 curIndex;
        while (j >= indexLSB) {
            curIndex = index + j;
            if (curIndex > SIZE) continue;
            uint256 scaled = deposits_.scaling[curIndex];
            if (sumIndex_ & j != 0) {
                uint256 value = deposits_.values[curIndex];
                sum_  += scaled != 0 ? Math.mulDiv(
                    runningScale * scaled,
                    value,
                    1e36
                ) : Maths.wmul(runningScale, value);
                index = curIndex;
                if (index == sumIndex_) break;
            } else {
                if (scaled != 0) runningScale = Maths.floorWmul(runningScale, scaled);
            }
            j = j >> 1;
        }
    }
    function unscaledRemove(
        DepositsState storage deposits_,
        uint256 index_,
        uint256 unscaledRemoveAmount_
    ) internal {
        if (unscaledRemoveAmount_ == 0) revert InvalidAmount();
        ++index_;


        while (index_ <= SIZE) {
            uint256 value   = (deposits_.values[index_] -= unscaledRemoveAmount_);
            uint256 scaling = deposits_.scaling[index_];


            if (scaling != 0) unscaledRemoveAmount_ = Maths.wmul(value + unscaledRemoveAmount_, scaling) - Maths.wmul(value,  scaling);
            index_ += lsb(index_);
        }
    }
    function scale(
        DepositsState storage deposits_,
        uint256 index_
    ) internal view returns (uint256 scaled_) {
        ++index_;
        scaled_ = Maths.WAD;
        while (index_ <= SIZE) {
            uint256 scaling = deposits_.scaling[index_];
            if (scaling != 0) scaled_ = Maths.wmul(scaled_, scaling);
            index_ += lsb(index_);
        }
    }
    function treeSum(
        DepositsState storage deposits_
    ) internal view returns (uint256) {
        return deposits_.values[SIZE];
    }
    function valueAt(
        DepositsState storage deposits_,
        uint256 index_
    ) internal view returns (uint256 depositValue_) {
        depositValue_ = Maths.wmul(unscaledValueAt(deposits_, index_), scale(deposits_,index_));
    }
    function unscaledValueAt(
        DepositsState storage deposits_,
        uint256 index_
    ) internal view returns (uint256 unscaledDepositValue_) {
        ++index_;
        uint256 j = 1;

        unscaledDepositValue_ = deposits_.values[index_];
        uint256 curIndex;
        uint256 value;
        uint256 scaling;
        while (j & index_ == 0) {
            curIndex = index_ - j;
            value   = deposits_.values[curIndex];
            scaling = deposits_.scaling[curIndex];
            unscaledDepositValue_ -= scaling != 0 ? Maths.wmul(scaling, value) : value;
            j = j << 1;
        }
    }
    function getLup(
        DepositsState storage deposits_,
        uint256 debt_
    ) internal view returns (uint256) {
        return _priceAt(findIndexOfSum(deposits_, debt_));
    }
}

pragma solidity ^0.5.16;
pragma experimental ABIEncoderV2;
import "./MixinResolver.sol";
import "./TemporarilyOwned.sol";
import "./interfaces/IOwnerRelayOnOptimism.sol";
import "@eth-optimism/contracts/iOVM/bridge/messaging/iAbs_BaseCrossDomainMessenger.sol";
contract OwnerRelayOnOptimism is MixinResolver, TemporarilyOwned, IOwnerRelayOnOptimism {
    bytes32 private constant CONTRACT_EXT_MESSENGER = "ext:Messenger";
    bytes32 private constant CONTRACT_BASE_OWNER_RELAY_ON_ETHEREUM = "base:OwnerRelayOnEthereum";
    constructor(
        address _resolver,
        address _temporaryOwner,
        uint _ownershipDuration
    ) public MixinResolver(_resolver) TemporarilyOwned(_temporaryOwner, _ownershipDuration) {}
    function _messenger() private view returns (iAbs_BaseCrossDomainMessenger) {
        return iAbs_BaseCrossDomainMessenger(requireAndGetAddress(CONTRACT_EXT_MESSENGER));
    }
    function _ownerRelayOnEthereum() private view returns (address) {
        return requireAndGetAddress(CONTRACT_BASE_OWNER_RELAY_ON_ETHEREUM);
    }
    function _relayCall(address target, bytes memory payload) private {
        (bool success, bytes memory result) = target.call(payload);
        require(success, string(abi.encode("xChain call failed:", result)));
    }
    function _onlyAllowMessengerAndL1Relayer() internal view {
        iAbs_BaseCrossDomainMessenger messenger = _messenger();
        require(msg.sender == address(messenger), "Sender is not the messenger");
        require(messenger.xDomainMessageSender() == _ownerRelayOnEthereum(), "L1 sender is not the owner relay");
    }
    modifier onlyMessengerAndL1Relayer() {
        _onlyAllowMessengerAndL1Relayer();
        _;
    }
    function resolverAddressesRequired() public view returns (bytes32[] memory addresses) {
        addresses = new bytes32[](2);
        addresses[0] = CONTRACT_EXT_MESSENGER;
        addresses[1] = CONTRACT_BASE_OWNER_RELAY_ON_ETHEREUM;
    }
    function directRelay(address target, bytes calldata payload) external onlyTemporaryOwner {
        _relayCall(target, payload);
        emit DirectRelay(target, payload);
    }
    function finalizeRelay(address target, bytes calldata payload) external onlyMessengerAndL1Relayer {
        _relayCall(target, payload);
        emit RelayFinalized(target, payload);
    }
    function finalizeRelayBatch(address[] calldata targets, bytes[] calldata payloads) external onlyMessengerAndL1Relayer {
        for (uint256 i = 0; i < targets.length; i++) {
            _relayCall(targets[i], payloads[i]);
        }
        emit RelayBatchFinalized(targets, payloads);
    }
    event DirectRelay(address target, bytes payload);
    event RelayFinalized(address target, bytes payload);
    event RelayBatchFinalized(address[] targets, bytes[] payloads);
}

