pragma solidity ^0.8.24;
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
contract TokenLock is Ownable {
    struct LockInfo {
        uint256 amount;
        uint256 releaseTime;
    }
    mapping(address => LockInfo) private clairTeamLocks;
    mapping(address => LockInfo) private investorLocks;
    IERC20 public token;
    address public investorAddress;
    address public clairTeamAddress;
    event TokensLocked(address indexed recipient, uint256 amount, uint256 releaseTime);
    event ClairTeamTokensReleased(address indexed recipient, uint256 amount);
    event InvestorTokensReleased(address indexed recipient, uint256 amount);
    modifier onlyClairTeam() {
        require(msg.sender == clairTeamAddress, "Only Clair team address allowed");
        _;
    }
    modifier onlyInvestor() {
        require(msg.sender == investorAddress, "Only investor address allowed");
        _;
    }
    constructor(address _tokenAddress, address _clairTeamAddress, address _investorAddress) Ownable(msg.sender) {
        token = IERC20(_tokenAddress);
        clairTeamAddress = _clairTeamAddress;
        investorAddress = _investorAddress;
    }
    function lockForClairTeam(address _recipient, uint256 _amount) external onlyClairTeam() {
        require(clairTeamLocks[_recipient].amount == 0, "Tokens already locked for this address");
        require(_amount > 0, "Amount must be greater than zero");
        uint256 _releaseTime = block.timestamp + 24 * 30 days;
        clairTeamLocks[_recipient] = LockInfo(_amount, _releaseTime);
        token.transferFrom(msg.sender, address(this), _amount);
        emit TokensLocked(_recipient, _amount, _releaseTime);
    }
    function lockForInvestors(address _recipient, uint256 _amount) external onlyInvestor() {
        require(investorLocks[_recipient].amount == 0, "Tokens already locked for this address");
        require(_amount > 0, "Amount must be greater than zero");
        uint256 _releaseTime = block.timestamp + 24 * 30 days;
        investorLocks[_recipient] = LockInfo(_amount, _releaseTime);
        token.transferFrom(msg.sender, address(this), _amount);
        emit TokensLocked(_recipient, _amount, _releaseTime);
    }
    function releaseClairTeamTokens() external onlyClairTeam {
        address recipient = msg.sender;
        require(clairTeamLocks[recipient].amount > 0, "No tokens locked for this address");
        require(block.timestamp >= clairTeamLocks[recipient].releaseTime, "Release time not reached yet");
        uint256 amount = clairTeamLocks[recipient].amount;
        delete clairTeamLocks[recipient];
        token.transfer(recipient, amount);
        emit ClairTeamTokensReleased(recipient, amount);
    }
    function releaseInvestorTokens() external onlyInvestor {
        address recipient = msg.sender;
        require(investorLocks[recipient].amount > 0, "No tokens locked for this address");
        require(block.timestamp >= investorLocks[recipient].releaseTime, "Release time not reached yet");
        uint256 amount = investorLocks[recipient].amount;
        delete investorLocks[recipient];
        token.transfer(recipient, amount);
        emit InvestorTokensReleased(recipient, amount);
    }
    function getClairTeamLock(address _recipient) external view returns (uint256 amount, uint256 releaseTime) {
        return (clairTeamLocks[_recipient].amount, clairTeamLocks[_recipient].releaseTime);
    }
    function getInvestorLock(address _recipient) external view returns (uint256 amount, uint256 releaseTime) {
        return (investorLocks[_recipient].amount, investorLocks[_recipient].releaseTime);
    }
}

pragma solidity ^0.8.20;
import {AccessControl} from "../access/AccessControl.sol";
import {ERC721Holder} from "../token/ERC721/utils/ERC721Holder.sol";
import {ERC1155Holder} from "../token/ERC1155/utils/ERC1155Holder.sol";
import {Address} from "../utils/Address.sol";
import {IERC165} from "../utils/introspection/ERC165.sol";
contract TimelockController is AccessControl, ERC721Holder, ERC1155Holder {
    bytes32 public constant PROPOSER_ROLE = keccak256("PROPOSER_ROLE");
    bytes32 public constant EXECUTOR_ROLE = keccak256("EXECUTOR_ROLE");
    bytes32 public constant CANCELLER_ROLE = keccak256("CANCELLER_ROLE");
    uint256 internal constant _DONE_TIMESTAMP = uint256(1);
    mapping(bytes32 id => uint256) private _timestamps;
    uint256 private _minDelay;
    enum OperationState {
        Unset,
        Waiting,
        Ready,
        Done
