contract RUNE404 {
    string public _name = unicode"Rune404";
    string public _symbol = unicode"RUNE404";
    uint8 public constant decimals = 9;
    uint256 public constant totalSupply = 4444* 10**decimals;
    uint256 constant swapAmount = totalSupply / 100;
