contract LiquidityToken is ERC20, Ownable {
    using SafeERC20 for IERC20;
    IUniswapV2Router02 public uniswapRouter;
    address public uniswapPair;
    address public marketingWallet;
    address public developmentWallet;
    uint256 public buyMarketingFee = 200;
    uint256 public buyDevelopmentFee = 100;
    uint256 public buyLiquidityFee = 100;
    uint256 public sellMarketingFee = 300;
    uint256 public sellDevelopmentFee = 200;
    uint256 public sellLiquidityFee = 200;
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;
    uint256 public swapThreshold;
    uint256 public lpBurnPercent = 25;
    uint256 public lastLpBurnTime;
    uint256 public lpBurnFrequency = 3600;
    uint256 private constant FEE_DENOMINATOR = 10000;
    bool public tradingEnabled = false;
    bool private inSwap;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isExcludedFromLimit;
    mapping(address => bool) public blacklist;
    event TradingEnabled(bool enabled);
    event FeesUpdated(uint256 buyMarketing, uint256 buyDevelopment, uint256 buyLiquidity, uint256 sellMarketing, uint256 sellDevelopment, uint256 sellLiquidity);
    event WalletsUpdated(address marketing, address development);
    event LiquidityAdded(uint256 tokenAmount, uint256 ethAmount);
    event TokensSwapped(uint256 tokenAmount, uint256 ethAmount);
    event LpBurned(uint256 amount);
    event BlacklistUpdated(address account, bool status);
    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor(string memory name, string memory symbol, uint256 totalSupply, address router, address marketing, address development) ERC20(name, symbol) {
        marketingWallet = marketing;
        developmentWallet = development;
        uniswapRouter = IUniswapV2Router02(router);
        uniswapPair = IUniswapV2Factory(uniswapRouter.factory()).createPair(address(this), uniswapRouter.WETH());
        maxTxAmount = totalSupply * 10**decimals() / 100;
        maxWalletAmount = totalSupply * 10**decimals() / 50;
        swapThreshold = totalSupply * 10**decimals() / 1000;
        _mint(msg.sender, totalSupply * 10**decimals());
        isExcludedFromFee[msg.sender] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromFee[marketingWallet] = true;
        isExcludedFromFee[developmentWallet] = true;
        isExcludedFromLimit[msg.sender] = true;
        isExcludedFromLimit[address(this)] = true;
        isExcludedFromLimit[marketingWallet] = true;
        isExcludedFromLimit[developmentWallet] = true;
    }
    function _transfer(address from, address to, uint256 amount) internal override {
        require(from != address(0), "Transfer from zero address");
        require(to != address(0), "Transfer to zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        require(!blacklist[from] && !blacklist[to], "Blacklisted address");
        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading not enabled");
        }
        if (!isExcludedFromLimit[from] && !isExcludedFromLimit[to]) {
            require(amount <= maxTxAmount, "Exceeds max transaction amount");
            if (to != uniswapPair) {
                require(balanceOf(to) + amount <= maxWalletAmount, "Exceeds max wallet amount");
            }
        }
        uint256 totalFee = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to] && !inSwap) {
            if (from == uniswapPair) {
                totalFee = amount * (buyMarketingFee + buyDevelopmentFee + buyLiquidityFee) / FEE_DENOMINATOR;
            } else if (to == uniswapPair) {
                totalFee = amount * (sellMarketingFee + sellDevelopmentFee + sellLiquidityFee) / FEE_DENOMINATOR;
                _processFees();
                _autoBurnLp();
            }
            if (totalFee > 0) {
                super._transfer(from, address(this), totalFee);
                amount -= totalFee;
            }
        }
        super._transfer(from, to, amount);
    }
    function _processFees() private lockTheSwap {
        uint256 contractBalance = balanceOf(address(this));
        if (contractBalance >= swapThreshold) {
            uint256 totalSellFee = sellMarketingFee + sellDevelopmentFee + sellLiquidityFee;
            uint256 marketingTokens = contractBalance * sellMarketingFee / totalSellFee;
            uint256 developmentTokens = contractBalance * sellDevelopmentFee / totalSellFee;
            uint256 liquidityTokens = contractBalance - marketingTokens - developmentTokens;
            uint256 initialBalance = address(this).balance;
            if (marketingTokens + developmentTokens > 0) {
                _swapTokensForEth(marketingTokens + developmentTokens);
            }
            uint256 newBalance = address(this).balance - initialBalance;
            uint256 marketingETH = newBalance * sellMarketingFee / (sellMarketingFee + sellDevelopmentFee);
            uint256 developmentETH = newBalance - marketingETH;
            if (marketingETH > 0) {
                payable(marketingWallet).transfer(marketingETH);
            }
            if (developmentETH > 0) {
                payable(developmentWallet).transfer(developmentETH);
            }
            if (liquidityTokens > 0) {
                _addLiquidity(liquidityTokens);
            }
        }
    }
    function _autoBurnLp() private {
        if (lastLpBurnTime + lpBurnFrequency <= block.timestamp) {
            uint256 lpBalance = balanceOf(uniswapPair);
            if (lpBalance > 0) {
                uint256 burnAmount = lpBalance * lpBurnPercent / FEE_DENOMINATOR;
                if (burnAmount > 0) {
                    _transfer(uniswapPair, address(0xdead), burnAmount);
                    IUniswapV2Pair(uniswapPair).sync();
                    lastLpBurnTime = block.timestamp;
                    emit LpBurned(burnAmount);
                }
            }
        }
    }
    function _swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapRouter.WETH();
        _approve(address(this), address(uniswapRouter), tokenAmount);
        uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount,0,path,address(this),block.timestamp);
        emit TokensSwapped(tokenAmount, address(this).balance);
    }
    function _addLiquidity(uint256 tokenAmount) private {
        uint256 half = tokenAmount / 2;
        uint256 otherHalf = tokenAmount - half;
        uint256 initialBalance = address(this).balance;
        _swapTokensForEth(half);
        uint256 newBalance = address(this).balance - initialBalance;
        _approve(address(this), address(uniswapRouter), otherHalf);
        uniswapRouter.addLiquidityETH{value: newBalance}(address(this),otherHalf,0,0,owner(),block.timestamp);
        emit LiquidityAdded(otherHalf, newBalance);
    }
    function enableTrading() external onlyOwner {
        tradingEnabled = true;
        emit TradingEnabled(true);
    }
    function setFees(uint256 _buyMarketing, uint256 _buyDevelopment, uint256 _buyLiquidity, uint256 _sellMarketing, uint256 _sellDevelopment, uint256 _sellLiquidity) external onlyOwner {
        require(_buyMarketing + _buyDevelopment + _buyLiquidity <= 1000, "Buy fees too high");
        require(_sellMarketing + _sellDevelopment + _sellLiquidity <= 1500, "Sell fees too high");
        buyMarketingFee = _buyMarketing;
        buyDevelopmentFee = _buyDevelopment;
        buyLiquidityFee = _buyLiquidity;
        sellMarketingFee = _sellMarketing;
        sellDevelopmentFee = _sellDevelopment;
        sellLiquidityFee = _sellLiquidity;
        emit FeesUpdated(_buyMarketing, _buyDevelopment, _buyLiquidity, _sellMarketing, _sellDevelopment, _sellLiquidity);
    }
    function setWallets(address _marketing, address _development) external onlyOwner {
        require(_marketing != address(0) && _development != address(0), "Invalid wallets");
        marketingWallet = _marketing;
        developmentWallet = _development;
        emit WalletsUpdated(_marketing, _development);
    }
    function setLimits(uint256 _maxTxAmount, uint256 _maxWalletAmount) external onlyOwner {
        maxTxAmount = _maxTxAmount;
        maxWalletAmount = _maxWalletAmount;
    }
    function setSwapThreshold(uint256 _swapThreshold) external onlyOwner {
        swapThreshold = _swapThreshold;
    }
    function setLpBurnSettings(uint256 _percent, uint256 _frequency) external onlyOwner {
        require(_percent <= 1000, "Burn percent too high");
        lpBurnPercent = _percent;
        lpBurnFrequency = _frequency;
    }
    function excludeFromFee(address account, bool excluded) external onlyOwner {
        isExcludedFromFee[account] = excluded;
    }
    function excludeFromLimit(address account, bool excluded) external onlyOwner {
        isExcludedFromLimit[account] = excluded;
    }
    function updateBlacklist(address account, bool status) external onlyOwner {
        blacklist[account] = status;
        emit BlacklistUpdated(account, status);
    }
    function batchUpdateBlacklist(address[] calldata accounts, bool status) external onlyOwner {
        for (uint256 i = 0; i < accounts.length; i++) {
            blacklist[accounts[i]] = status;
            emit BlacklistUpdated(accounts[i], status);
        }
    }
    function manualProcessFees() external onlyOwner {
        _processFees();
    }
    function manualBurnLp() external onlyOwner {
        _autoBurnLp();
    }
    function rescueTokens(address token, uint256 amount) external onlyOwner {
        IERC20(token).safeTransfer(owner(), amount);
    }
    receive() external payable {}
}

