contract CurvePool {
    string public name;
    string public symbol;
    uint8 public decimals;
    address[2] public coins;
    uint256[2] public balances;
    uint256 public totalSupply;
    address public owner;
    uint256 public fee;
    uint256 public adminFee;
    uint256 public initialA;
    uint256 public futureA;
    uint256 public initialATime;
    uint256 public futureATime;
    uint256 public constant A_PRECISION = 100;
    uint256 public constant FEE_DENOMINATOR = 10**10;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event AddLiquidity(address indexed provider, uint256[2] amounts, uint256 fee, uint256 tokenSupply);
    event RemoveLiquidity(address indexed provider, uint256[2] amounts, uint256 tokenSupply);
    event Exchange(address indexed buyer, uint256 soldId, uint256 tokensSold, uint256 boughtId, uint256 tokensBought);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(address[2] memory _coins, string memory _name, string memory _symbol, uint256 _fee, uint256 _adminFee, uint256 _A) {
        owner = msg.sender;
        coins = _coins;
        name = _name;
        symbol = _symbol;
        decimals = 18;
        fee = _fee;
        adminFee = _adminFee;
        initialA = _A * A_PRECISION;
        futureA = _A * A_PRECISION;
        initialATime = block.timestamp;
        futureATime = block.timestamp;
    }
    function exchange(uint256 i, uint256 j, uint256 dx, uint256 minDy) external returns (uint256) {
        require(i != j && i < 2 && j < 2, "Invalid indices");
        uint256 dy = getDy(i, j, dx);
        require(dy >= minDy, "Slippage");
        IERC20(coins[i]).transferFrom(msg.sender, address(this), dx);
        IERC20(coins[j]).transfer(msg.sender, dy);
        balances[i] += dx;
        balances[j] -= dy;
        emit Exchange(msg.sender, i, dx, j, dy);
        return dy;
    }
    function addLiquidity(uint256[2] memory amounts, uint256 minMintAmount) external returns (uint256) {
        uint256 tokenAmount = getAddLiquidityMintAmount(amounts);
        require(tokenAmount >= minMintAmount, "Slippage");
        for (uint256 i = 0; i < 2; i++) {
            if (amounts[i] > 0) {
                IERC20(coins[i]).transferFrom(msg.sender, address(this), amounts[i]);
                balances[i] += amounts[i];
            }
        }
        _mint(msg.sender, tokenAmount);
        emit AddLiquidity(msg.sender, amounts, fee, totalSupply);
        return tokenAmount;
    }
    function removeLiquidity(uint256 amount, uint256[2] memory minAmounts) external returns (uint256[2] memory) {
        uint256[2] memory amounts = getRemoveLiquidityAmounts(amount);
        for (uint256 i = 0; i < 2; i++) {
            require(amounts[i] >= minAmounts[i], "Slippage");
            if (amounts[i] > 0) {
                IERC20(coins[i]).transfer(msg.sender, amounts[i]);
                balances[i] -= amounts[i];
            }
        }
        _burn(msg.sender, amount);
        emit RemoveLiquidity(msg.sender, amounts, totalSupply);
        return amounts;
    }
    function getDy(uint256 i, uint256 j, uint256 dx) public view returns (uint256) {
        uint256[2] memory xp = getXP();
        uint256 x = xp[i] + dx;
        uint256 y = getY(i, j, x, xp);
        uint256 dy = xp[j] - y - 1;
        uint256 fee_ = (dy * fee) / FEE_DENOMINATOR;
        return dy - fee_;
    }
    function getAddLiquidityMintAmount(uint256[2] memory amounts) public view returns (uint256) {
        uint256[2] memory xp = getXP();
        uint256 D0 = getD(xp);
        for (uint256 i = 0; i < 2; i++) {
            xp[i] += amounts[i];
        }
        uint256 D1 = getD(xp);
        uint256 tokenAmount = totalSupply;
        if (tokenAmount > 0) {
            return ((D1 - D0) * tokenAmount) / D0;
        } else {
            return D1;
        }
    }
    function getRemoveLiquidityAmounts(uint256 amount) public view returns (uint256[2] memory) {
        uint256[2] memory amounts;
        for (uint256 i = 0; i < 2; i++) {
            amounts[i] = (balances[i] * amount) / totalSupply;
        }
        return amounts;
    }
    function getXP() public view returns (uint256[2] memory) {
        return [balances[0], balances[1]];
    }
    function getD(uint256[2] memory xp) public view returns (uint256) {
        uint256 A = getA();
        uint256 S = xp[0] + xp[1];
        if (S == 0) return 0;
        uint256 DPrev = 0;
        uint256 D = S;
        uint256 Ann = A * 2;
        for (uint256 i = 0; i < 256; i++) {
            uint256 D_P = D;
            for (uint256 j = 0; j < 2; j++) {
                D_P = (D_P * D) / (xp[j] * 2);
            }
            DPrev = D;
            D = ((Ann * S + D_P * 2) * D) / ((Ann - 1) * D + (2 + 2) * D_P);
            if (D > DPrev && D - DPrev <= 1) break;
            if (DPrev > D && DPrev - D <= 1) break;
        }
        return D;
    }
    function getY(uint256 i, uint256 j, uint256 x, uint256[2] memory xp) public view returns (uint256) {
        uint256 A = getA();
        uint256 D = getD(xp);
        uint256 c = D;
        uint256 S_ = 0;
        uint256 Ann = A * 2;
        for (uint256 k = 0; k < 2; k++) {
            if (k == i) {
                S_ += x;
                c = (c * D) / (x * 2);
            } else if (k != j) {
                S_ += xp[k];
                c = (c * D) / (xp[k] * 2);
            }
        }
        c = (c * D) / (Ann * 2);
        uint256 b = S_ + D / Ann;
        uint256 yPrev = 0;
        uint256 y = D;
        for (uint256 m = 0; m < 256; m++) {
            yPrev = y;
            y = (y * y + c) / (2 * y + b - D);
            if (y > yPrev && y - yPrev <= 1) break;
            if (yPrev > y && yPrev - y <= 1) break;
        }
        return y;
    }
    function getA() public view returns (uint256) {
        uint256 t1 = futureATime;
        uint256 A1 = futureA;
        if (block.timestamp < t1) {
            uint256 A0 = initialA;
            uint256 t0 = initialATime;
            return A0 + ((A1 - A0) * (block.timestamp - t0)) / (t1 - t0);
        } else {
            return A1;
        }
    }
    function rampA(uint256 _futureA, uint256 _futureTime) external onlyOwner {
        require(block.timestamp >= initialATime + 86400, "Wait 1 day");
        require(_futureA >= initialA / 2 && _futureA <= initialA * 2, "A out of range");
        initialA = getA();
        futureA = _futureA;
        initialATime = block.timestamp;
        futureATime = _futureTime;
    }
    function stopRampA() external onlyOwner {
        futureA = getA();
        futureATime = block.timestamp;
    }
    function setFees(uint256 _fee, uint256 _adminFee) external onlyOwner {
        fee = _fee;
        adminFee = _adminFee;
    }
    function transfer(address to, uint256 value) external returns (bool) {
        require(balanceOf[msg.sender] >= value, "Insufficient balance");
        balanceOf[msg.sender] -= value;
        balanceOf[to] += value;
        emit Transfer(msg.sender, to, value);
        return true;
    }
    function approve(address spender, uint256 value) external returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) external returns (bool) {
        require(balanceOf[from] >= value, "Insufficient balance");
        require(allowance[from][msg.sender] >= value, "Allowance exceeded");
        balanceOf[from] -= value;
        balanceOf[to] += value;
        allowance[from][msg.sender] -= value;
        emit Transfer(from, to, value);
        return true;
    }
    function _mint(address to, uint256 value) internal {
        totalSupply += value;
        balanceOf[to] += value;
        emit Transfer(address(0), to, value);
    }
    function _burn(address from, uint256 value) internal {
        balanceOf[from] -= value;
        totalSupply -= value;
        emit Transfer(from, address(0), value);
    }
}

