import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract VeYFIVestingEscrow is Ownable, ReentrancyGuard {
 address public immutable recipient;
 IERC20 public immutable token;
 uint256 public immutable startTime;
 uint256 public immutable cliffDuration;
 uint256 public immutable vestingDuration;
 uint256 public released;
 bool public revoked;
 address public operator;

 event Released(uint256 amount);
 event Revoked();
 event OperatorSet(address indexed operator);

 constructor(
 address recipient_,
 IERC20 token_,
 uint256 startTime_,
 uint256 cliffDuration_,
 uint256 vestingDuration_,
 address operator_
 ) {
 require(recipient_ != address(0), "Recipient zero");
 require(address(token_) != address(0), "Token zero");
 require(startTime_ > 0, "Start time zero");
 require(cliffDuration_ <= vestingDuration_, "Cliff > vesting");
 recipient = recipient_;
 token = token_;
 startTime = startTime_;
 cliffDuration = cliffDuration_;
 vestingDuration = vestingDuration_;
 operator = operator_;
 }

 modifier onlyRecipientOrOperator() {
 require(msg.sender == recipient || msg.sender == operator, "Not authorized");
 ;
 }

 function setOperator(address operator) external onlyOwner {
 operator = operator_;
 emit OperatorSet(operator_);
 }

 function claim() external nonReentrant onlyRecipientOrOperator {
 uint256 amount = _releasableAmount();
 require(amount > 0, "No amount releasable");
 released += amount;
 emit Released(amount);
 bool success = token.transfer(recipient, amount);
 require(success, "Transfer failed");
 }

 function revoke() external onlyOwner {
 require(!revoked, "Already revoked");
 revoked = true;
 emit Revoked();
 }

 function _releasableAmount() internal view returns (uint256) {
 return _vestedAmount() - released;
 }

 function _vestedAmount() internal view returns (uint256) {
 uint256 totalAllocation = token.balanceOf(address(this)) + released;
 if (revoked) {
 return totalAllocation;
 }
 uint256 currentTime = block.timestamp;
 if (currentTime < startTime + cliffDuration) {
 return 0;
 }
 if (currentTime >= startTime + vestingDuration) {
 return totalAllocation;
 }
 return (totalAllocation * (currentTime - startTime)) / vestingDuration;
 }

 function isValidSignature(bytes32 hash, bytes memory signature) external view returns (bytes4) {
 address signer = _recoverSigner(hash, signature);
 if (signer == owner() || signer == operator) {
 return 0x1626ba7e;
 }
 return 0xffffffff;
 }

 function _recoverSigner(bytes32 hash, bytes memory signature) internal pure returns (address) {
 require(signature.length == 65, "Invalid signature length");
 bytes32 r;
 bytes32 s;
 uint8 v;
 assembly {
 r := mload(add(signature, 32))
 s := mload(add(signature, 64))
 v := byte(0, mload(add(signature, 96)))
 }
 return ecrecover(hash, v, r, s);
 }
}

